{
  "name": "Yiwu Sourcing AI",
  "description": "A dual-interface app for sourcing agents (mobile) and documentation specialists (desktop). Features AI-powered data enrichment for HS Codes and materials.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ProcessingStatus {
  DRAFT = 'DRAFT',
  AI_PROCESSING = 'AI_PROCESSING',
  COMPLETED = 'COMPLETED',
  REVIEW_NEEDED = 'REVIEW_NEEDED'
}

export interface Product {
  id: string;
  sku: string;
  photoUrl: string;

  // Mobile Input Fields
  nameCn: string;
  priceRmb: number;
  moq: number;
  shopNo: string;

  // OCR / Manual Fields (Box Info)
  boxLength: number;
  boxWidth: number;
  boxHeight: number;
  pcsPerBox: number;

  // AI Enriched Fields
  nameEn?: string;
  materialEn?: string;
  hsCode?: string;
  usage?: string;
  taxRate?: number; // Estimated percentage

  // Calculated Fields
  cbm?: number;
  landedCost?: number;

  timestamp: number;
  status: ProcessingStatus;
}

export interface AIEnrichmentResult {
  nameEn: string;
  materialEn: string;
  hsCode: string;
  usage: string;
  taxRate: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found via process.env.API_KEY");
  }
  return new GoogleGenAI({ apiKey });
};

export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  const ai = getClient();

  const prompt = `
    You are an expert international trade sourcing agent in Yiwu, China.
    I have a product with the Chinese name: "${nameCn}".

    Please provide the following details for export documentation:
    1. English Product Name (Professional trade term).
    2. Material Composition (Guess the likely material in English, e.g., Stainless Steel 304, PP Plastic).
    3. HS Code (The most likely 6-digit Harmonized System code).
    4. Usage (Short description of use).
    5. EU Import Tax Rate (Estimated percentage as a number, e.g., 6.5).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "Professional English product name" },
            materialEn: { type: Type.STRING, description: "Material composition in English" },
            hsCode: { type: Type.STRING, description: "6-digit HS Code" },
            usage: { type: Type.STRING, description: "Short usage description" },
            taxRate: { type: Type.NUMBER, description: "Estimated EU tax rate percentage" }
          },
          required: ["nameEn", "materialEn", "hsCode", "usage", "taxRate"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Camera, Save, Box, Home, Plus } from 'lucide-react';
import { Product, ProcessingStatus } from '../types';

interface MobileEntryProps {
  onSave: (product: Product) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); // simplified for demo input "60x40x50"
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPhotoPreview(ev.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSimulateOCR = () => {
    // Simulate OCR filling in box data
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Parse dimensions
    const [l, w, h] = boxDims.split('x').map(Number);

    const newProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l || 0,
      boxWidth: w || 0,
      boxHeight: h || 0,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    onSave(newProduct);

    // Reset Form
    setNameCn('');
    setPriceRmb('');
    setMoq('');
    setShopNo('');
    setBoxDims('');
    setPcsPerBox('');
    setPhotoPreview(null);
    alert("Product Saved Successfully!");
  };

  if (activeTab === 'list') {
    return (
      <div className="flex flex-col h-full bg-slate-100">
        <div className="p-4 bg-white shadow-sm">
          <h2 className="text-lg font-bold">Today's List</h2>
          <p className="text-sm text-gray-500">Go to Desktop View to process</p>
        </div>
        <div className="flex-1 p-4 flex flex-col items-center justify-center text-gray-400">
            <Box size={48} />
            <p className="mt-2">Items stored locally.</p>
        </div>
        <nav className="bg-white border-t p-2 flex justify-around">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center text-gray-400">
            <Plus />
            <span className="text-xs">New</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center text-blue-600">
            <Home />
            <span className="text-xs">List</span>
          </button>
        </nav>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-slate-50 relative">
      {/* Header */}
      <div className="bg-blue-600 text-white p-4 sticky top-0 z-10 shadow-md">
        <h1 className="text-lg font-bold">New Product</h1>
        <p className="text-xs opacity-80">Yiwu Market District 4</p>
      </div>

      {/* Form Content */}
      <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-4 space-y-4 pb-24">

        {/* Photo Section */}
        <div className="bg-white p-4 rounded-xl shadow-sm space-y-2">
          <label className="block text-sm font-medium text-gray-700">Product Photo</label>
          <div className="flex items-center gap-4">
            <div className="relative w-24 h-24 bg-gray-100 rounded-lg flex items-center justify-center border-2 border-dashed border-gray-300 overflow-hidden">
               {photoPreview ? (
                 <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
               ) : (
                 <Camera className="text-gray-400" />
               )}
               <input 
                 type="file" 
                 accept="image/*" 
                 onChange={handlePhotoSelect}
                 className="absolute inset-0 opacity-0 cursor-pointer"
               />
            </div>
            <div className="flex-1">
               <button 
                 type="button" 
                 className="text-sm text-blue-600 font-medium border border-blue-600 px-3 py-1.5 rounded-full w-full mb-2"
               >
                 Take Photo
               </button>
               <p className="text-xs text-gray-400">Supports multi-shot</p>
            </div>
          </div>
        </div>

        {/* Basic Info */}
        <div className="bg-white p-4 rounded-xl shadow-sm space-y-4">
           <div>
            <label className="block text-xs font-bold text-gray-500 uppercase">Product Name (CN)</label>
            <input 
              type="text" 
              value={nameCn}
              onChange={(e) => setNameCn(e.target.value)}
              placeholder="e.g., 18cm不锈钢盖"
              className="w-full text-lg font-medium border-b border-gray-200 py-2 focus:outline-none focus:border-blue-500"
              required
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase">RMB Cost</label>
              <div className="relative">
                <span className="absolute left-0 top-2 text-gray-400">¥</span>
                <input 
                  type="number" 
                  value={priceRmb}
                  onChange={(e) => setPriceRmb(e.target.value)}
                  placeholder="0.00"
                  className="w-full pl-4 py-2 border-b border-gray-200 focus:outline-none focus:border-blue-500"
                  inputMode="decimal"
                  required
                />
              </div>
            </div>
             <div>
              <label className="block text-xs font-bold text-gray-500 uppercase">MOQ</label>
              <input 
                type="number" 
                value={moq}
                onChange={(e) => setMoq(e.target.value)}
                placeholder="PCS"
                className="w-full py-2 border-b border-gray-200 focus:outline-none focus:border-blue-500"
                inputMode="numeric"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase">Shop No.</label>
            <input 
              type="text" 
              value={shopNo}
              onChange={(e) => setShopNo(e.target.value)}
              placeholder="e.g., F1-1234"
              className="w-full py-2 border-b border-gray-200 focus:outline-none focus:border-blue-500"
            />
          </div>
        </div>

        {/* Logistics Info */}
        <div className="bg-white p-4 rounded-xl shadow-sm space-y-4">
          <div className="flex justify-between items-center">
             <h3 className="text-sm font-bold text-gray-700">Packing Details</h3>
             <button 
               type="button" 
               onClick={handleSimulateOCR}
               className="text-xs bg-indigo-50 text-indigo-600 px-2 py-1 rounded font-medium flex items-center gap-1"
             >
               <Camera size={12} /> OCR Scan Box
             </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
               <label className="block text-xs text-gray-500">Box Size (LxWxH)</label>
               <input 
                type="text"
                value={boxDims}
                onChange={(e) => setBoxDims(e.target.value)}
                placeholder="60x40x50"
                className="w-full py-2 border-b border-gray-200 focus:outline-none"
               />
            </div>
             <div>
               <label className="block text-xs text-gray-500">Pcs/Box</label>
               <input 
                type="number"
                value={pcsPerBox}
                onChange={(e) => setPcsPerBox(e.target.value)}
                placeholder="120"
                className="w-full py-2 border-b border-gray-200 focus:outline-none"
               />
            </div>
          </div>
        </div>

      </form>

      {/* Floating Action Button */}
      <div className="absolute bottom-6 left-6 right-6">
        <button 
          onClick={handleSubmit}
          className="w-full bg-blue-600 text-white rounded-xl py-4 shadow-lg flex items-center justify-center gap-2 font-bold active:scale-95 transition-transform"
        >
          <Save size={20} />
          Save Product
        </button>
      </div>

      {/* Bottom Nav */}
      <nav className="bg-white border-t p-2 flex justify-around absolute bottom-0 w-full">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center text-blue-600">
            <Plus />
            <span className="text-xs">New</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center text-gray-400">
            <Home />
            <span className="text-xs">List</span>
          </button>
        </nav>
    </div>
  );
};

export default MobileEntry;

import React, { useState } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Download, Sparkles, RefreshCw, AlertCircle, CheckCircle2 } from 'lucide-react';

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);

  const calculateMetrics = (p: Product) => {
    // Logic from PRD
    // CBM = (L*W*H)/1000000
    const cbm = (p.boxLength * p.boxWidth * p.boxHeight) / 1000000;
    // Estimated Freight (Simulated constant) + Tax + Base
    // Landed = RMB/7.2 (Ex rate) + (Freight/Pcs) + Duty
    const exRate = 7.2;
    const estimatedFreightPerCbm = 300; // USD
    const freightCost = cbm > 0 && p.pcsPerBox > 0 ? (estimatedFreightPerCbm * cbm) / p.pcsPerBox : 0;
    const baseUsd = p.priceRmb / exRate;
    const dutyCost = p.taxRate ? baseUsd * (p.taxRate / 100) : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      landedCost: Number((baseUsd + freightCost + dutyCost).toFixed(3))
    };
  };

  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) {
      alert("Please provide an API Key in the metadata/environment to use AI features.");
      return;
    }

    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });

    try {
      const result = await enrichProductData(product.nameCn);

      const metrics = calculateMetrics(product); // Recalculate with potential new data if needed

      const updatedProduct: Product = {
        ...product,
        ...result,
        cbm: metrics.cbm,
        landedCost: metrics.landedCost, // Recalculate with tax rate
        status: ProcessingStatus.REVIEW_NEEDED
      };

      // Re-run calc with tax rate now available
      const finalMetrics = calculateMetrics(updatedProduct);
      updatedProduct.landedCost = finalMetrics.landedCost;

      onUpdateProduct(updatedProduct);
    } catch (error) {
      alert("AI Enrichment failed. See console.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const handleExport = () => {
    alert("Downloading PackingList.xlsx... (Simulation)");
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      {/* Top Bar */}
      <header className="bg-white border-b px-8 py-4 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-slate-800">Yiwu Sourcing Manager</h1>
          <p className="text-sm text-slate-500">Documentation Center</p>
        </div>
        <div className="flex gap-4">
           <button onClick={handleExport} className="flex items-center gap-2 px-4 py-2 border border-slate-300 rounded-md text-slate-700 hover:bg-slate-50">
             <Download size={16} /> Export Excel
           </button>
           <div className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-md border border-indigo-100">
             <span className="font-bold">{products.length}</span> SKU(s) Loaded
           </div>
        </div>
      </header>

      {/* Main Grid */}
      <main className="flex-1 overflow-auto p-8">
        <div className="bg-white rounded-lg shadow border border-slate-200 overflow-hidden">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-100 text-slate-600 uppercase font-bold text-xs">
              <tr>
                <th className="p-4 w-16">Foto</th>
                <th className="p-4 w-24">Status</th>
                <th className="p-4">Product Info (CN/EN)</th>
                <th className="p-4 w-32">HS Code / Tax</th>
                <th className="p-4">Material / Usage</th>
                <th className="p-4 w-24 text-right">RMB</th>
                <th className="p-4 w-24 text-right">Landed($)</th>
                <th className="p-4 w-32 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {products.length === 0 && (
                <tr>
                  <td colSpan={8} className="p-12 text-center text-slate-400">
                    No products yet. Use the Mobile view to add items.
                  </td>
                </tr>
              )}
              {products.map((p) => {
                const isProcessing = processingId === p.id;
                const isEnriched = p.status === ProcessingStatus.REVIEW_NEEDED || p.status === ProcessingStatus.COMPLETED;

                return (
                  <tr key={p.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4">
                      <img src={p.photoUrl} alt="Product" className="w-12 h-12 rounded object-cover border border-slate-200" />
                    </td>
                    <td className="p-4">
                      {isProcessing ? (
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800 animate-pulse">
                          AI Working...
                        </span>
                      ) : isEnriched ? (
                         <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
                          <AlertCircle size={10} /> Review
                        </span>
                      ) : (
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-600">
                          Draft
                        </span>
                      )}
                    </td>
                    <td className="p-4">
                      <div className="font-medium text-slate-900">{p.nameCn}</div>
                      <div className={`text-xs mt-1 ${isEnriched ? 'text-indigo-600 font-medium' : 'text-slate-400 italic'}`}>
                        {p.nameEn || "Pending Translation..."}
                      </div>
                      <div className="text-xs text-slate-400 mt-1">Shop: {p.shopNo} | SKU: {p.sku}</div>
                    </td>
                    <td className="p-4">
                      <div className={`${isEnriched ? 'bg-yellow-50 p-1 rounded' : ''}`}>
                        <div className="font-mono text-slate-700">{p.hsCode || "---"}</div>
                        <div className="text-xs text-slate-500">Tax: {p.taxRate ? `${p.taxRate}%` : "-"}</div>
                      </div>
                    </td>
                    <td className="p-4 max-w-xs">
                      <div className={`${isEnriched ? 'bg-yellow-50 p-1 rounded' : ''}`}>
                         <div className="truncate text-slate-700" title={p.materialEn}>{p.materialEn || "---"}</div>
                         <div className="text-xs text-slate-500 truncate" title={p.usage}>{p.usage || "---"}</div>
                      </div>
                    </td>
                    <td className="p-4 text-right font-medium">¥{p.priceRmb}</td>
                    <td className="p-4 text-right font-bold text-green-600">
                      {p.landedCost ? `$${p.landedCost}` : "-"}
                    </td>
                    <td className="p-4 text-center">
                      {!isEnriched && !isProcessing && (
                        <button 
                          onClick={() => handleEnrichment(p)}
                          className="w-full flex items-center justify-center gap-1 bg-gradient-to-r from-violet-600 to-indigo-600 text-white px-3 py-1.5 rounded text-xs hover:shadow-md transition-all"
                        >
                          <Sparkles size={12} /> AI Auto-Fill
                        </button>
                      )}
                      {isEnriched && (
                        <button 
                          onClick={() => onUpdateProduct({...p, status: ProcessingStatus.COMPLETED})}
                          className="w-full flex items-center justify-center gap-1 bg-white border border-green-600 text-green-600 px-3 py-1.5 rounded text-xs hover:bg-green-50"
                        >
                          <CheckCircle2 size={12} /> Confirm
                        </button>
                      )}
                      {isProcessing && (
                         <div className="flex justify-center">
                           <RefreshCw size={16} className="animate-spin text-indigo-600" />
                         </div>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import MobileEntry from './components/MobileEntry';
import Dashboard from './components/Dashboard';
import { Product } from './types';
import { Smartphone, Monitor } from 'lucide-react';

export default function App() {
  const [viewMode, setViewMode] = useState<'mobile' | 'desktop'>('mobile');
  const [products, setProducts] = useState<Product[]>([]);

  // Load from local storage on mount (Simulation of DB)
  useEffect(() => {
    const saved = localStorage.getItem('yiwu_products');
    if (saved) {
      setProducts(JSON.parse(saved));
    }
  }, []);

  // Save to local storage whenever products change
  useEffect(() => {
    localStorage.setItem('yiwu_products', JSON.stringify(products));
  }, [products]);

  const handleAddProduct = (newProduct: Product) => {
    setProducts(prev => [newProduct, ...prev]);
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden font-sans text-slate-900">

      {/* Dev Switcher - For Demo Purposes */}
      <div className="bg-slate-900 text-white p-2 flex justify-center items-center gap-4 text-xs z-50">
        <span className="opacity-50 uppercase tracking-widest font-bold">Role Switcher:</span>
        <button 
          onClick={() => setViewMode('mobile')}
          className={`flex items-center gap-2 px-3 py-1 rounded-full transition-colors ${viewMode === 'mobile' ? 'bg-blue-600' : 'hover:bg-slate-700'}`}
        >
          <Smartphone size={14} /> Sourcing Agent (Mobile)
        </button>
        <button 
          onClick={() => setViewMode('desktop')}
          className={`flex items-center gap-2 px-3 py-1 rounded-full transition-colors ${viewMode === 'desktop' ? 'bg-indigo-600' : 'hover:bg-slate-700'}`}
        >
          <Monitor size={14} /> Office Admin (PC)
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden bg-slate-200 relative">

        {viewMode === 'mobile' ? (
          <div className="h-full w-full max-w-md mx-auto bg-white shadow-2xl overflow-hidden relative border-x border-gray-300">
             <MobileEntry onSave={handleAddProduct} />
          </div>
        ) : (
          <div className="h-full w-full bg-white">
            <Dashboard products={products} onUpdateProduct={handleUpdateProduct} />
          </div>
        )}

      </div>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found via process.env.API_KEY");
  }
  return new GoogleGenAI({ apiKey });
};

// Text-based enrichment (existing)
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  const ai = getClient();

  const prompt = `
    You are an expert international trade sourcing agent in Yiwu, China.
    I have a product with the Chinese name: "${nameCn}".

    Please provide the following details for export documentation:
    1. English Product Name (Professional trade term).
    2. Material Composition (Guess the likely material in English, e.g., Stainless Steel 304, PP Plastic).
    3. HS Code (The most likely 6-digit Harmonized System code).
    4. Usage (Short description of use).
    5. EU Import Tax Rate (Estimated percentage as a number, e.g., 6.5).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "Professional English product name" },
            materialEn: { type: Type.STRING, description: "Material composition in English" },
            hsCode: { type: Type.STRING, description: "6-digit HS Code" },
            usage: { type: Type.STRING, description: "Short usage description" },
            taxRate: { type: Type.NUMBER, description: "Estimated EU tax rate percentage" }
          },
          required: ["nameEn", "materialEn", "hsCode", "usage", "taxRate"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

// Image-based analysis (New for Batch OCR)
export const analyzeImage = async (base64Image: string): Promise<{nameCn: string, priceRmb: number, moq: number, nameEn: string, materialEn: string}> => {
  const ai = getClient();
  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: "Analyze this product image from a wholesale market. Extract the product name (in Chinese if visible, otherwise describe it in Chinese), estimate a price if visible on a tag (otherwise return 0), estimate MOQ if visible (otherwise 0), suggest an English Name, and guess the Material." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameCn: { type: Type.STRING, description: "Product Name in Chinese" },
            priceRmb: { type: Type.NUMBER, description: "Price on tag or 0" },
            moq: { type: Type.NUMBER, description: "MOQ on tag or 0" },
            nameEn: { type: Type.STRING, description: "English Name" },
            materialEn: { type: Type.STRING, description: "Material" },
          },
          required: ["nameCn", "priceRmb", "moq", "nameEn", "materialEn"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Image Analysis failed:", error);
    // Fallback to avoid breaking the batch loop
    return {
      nameCn: "待识别商品 (Unidentified)",
      priceRmb: 0,
      moq: 0,
      nameEn: "Pending Analysis",
      materialEn: ""
    };
  }
};

