  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); // simplified for demo input "60x40x50"
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPhotoPreview(ev.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setIsBatchProcessing(true);
      const files = Array.from(e.target.files);

      try {
        // Process sequentially to be gentle on API, or Promise.all for speed.
        // Using Promise.all for better UX demo.
        const promises = files.map(async (file) => {
          return new Promise<void>((resolve) => {
            const reader = new FileReader();
            reader.onload = async (ev) => {
              const base64 = ev.target?.result as string;

              // Call AI to identify product
              let aiData;
              try {
                aiData = await analyzeImage(base64);
              } catch (err) {
                 aiData = { nameCn: "Unknown Item", priceRmb: 0, moq: 0, nameEn: "Unknown", materialEn: "" };
              }

              const newProduct: Product = {
                id: Date.now().toString() + Math.random(),
                sku: `YW-${Math.floor(Math.random() * 10000)}`,
                photoUrl: base64,
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn, // Pre-fill from visual analysis
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || "TBD", // Inherit shop number if set, else TBD
                boxLength: 0,
                boxWidth: 0,
                boxHeight: 0,
                pcsPerBox: 0,
                status: ProcessingStatus.DRAFT, // Needs manual review for box dims
                timestamp: Date.now()
              };

              onSave(newProduct);
              resolve();
            };
            reader.readAsDataURL(file);
          });
        });

        await Promise.all(promises);
        alert(`Successfully batch processed ${files.length} images!`);
        setActiveTab('list');
      } catch (error) {
        console.error(error);
        alert("Batch processing had some errors.");
      } finally {
