  }

  return (
    <div className="flex flex-col h-full bg-slate-50 relative">
      {isBatchProcessing && (
        <div className="absolute inset-0 z-50 bg-black/80 flex flex-col items-center justify-center text-white">
           <Loader2 className="animate-spin mb-4" size={48} />
