import React, { useState } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { FileDown, Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText } from 'lucide-react';

// Declare XLSX globally since we loaded it via CDN
declare const XLSX: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);

  const calculateMetrics = (p: Product) => {
    // Logic from PRD
    // CBM = (L*W*H)/1000000
    const cbm = (p.boxLength * p.boxWidth * p.boxHeight) / 1000000;
    // Estimated Freight (Simulated constant) + Tax + Base
    // Landed = RMB/7.2 (Ex rate) + (Freight/Pcs) + Duty
    const exRate = 7.2;
    const estimatedFreightPerCbm = 300; // USD
    const freightCost = cbm > 0 && p.pcsPerBox > 0 ? (estimatedFreightPerCbm * cbm) / p.pcsPerBox : 0;
    const baseUsd = p.priceRmb / exRate;
    const dutyCost = p.taxRate ? baseUsd * (p.taxRate / 100) : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      landedCost: Number((baseUsd + freightCost + dutyCost).toFixed(3))
    };
  };

  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) {
      alert("Please provide an API Key in the metadata/environment to use AI features.");
      return;
    }

    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });

    try {
      const result = await enrichProductData(product.nameCn);

      const metrics = calculateMetrics(product); // Recalculate with potential new data if needed

      const updatedProduct: Product = {
        ...product,
        ...result,
        cbm: metrics.cbm,
        landedCost: metrics.landedCost, // Recalculate with tax rate
        status: ProcessingStatus.REVIEW_NEEDED
      };

      // Re-run calc with tax rate now available
      const finalMetrics = calculateMetrics(updatedProduct);
      updatedProduct.landedCost = finalMetrics.landedCost;

      onUpdateProduct(updatedProduct);
    } catch (error) {
      alert("AI Enrichment failed. See console.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const generateExcel = (type: 'packinglist' | 'invoice') => {
    if (products.length === 0) {
      alert("No products to export.");
      return;
    }

    // Format data for Excel
    const data = products.map((p, index) => {
      const cartonQty = p.moq && p.pcsPerBox ? Math.ceil(p.moq / p.pcsPerBox) : 1;
      const totalQty = cartonQty * p.pcsPerBox;
      const totalCbm = p.cbm ? p.cbm * cartonQty : 0;
      const totalPrice = p.landedCost ? p.landedCost * totalQty : 0;

      if (type === 'packinglist') {
        return {
          "No.": index + 1,
          "SKU": p.sku,
          "Description (EN)": p.nameEn || p.nameCn,
          "Material": p.materialEn || "N/A",
          "HS Code": p.hsCode || "---",
          "Qty (PCS)": totalQty,
          "Pcs/Ctn": p.pcsPerBox,
          "Cartons": cartonQty,
          "CBM/Ctn": p.cbm,
          "Total CBM": totalCbm.toFixed(3),
          "G.W (KGS)": (totalCbm * 150).toFixed(2), // Estimated weight
          "Dimensions (cm)": `${p.boxLength}x${p.boxWidth}x${p.boxHeight}`
        };
      } else {
        // Commercial Invoice
        return {
           "No.": index + 1,
           "SKU": p.sku,
           "Description": p.nameEn || p.nameCn,
           "HS Code": p.hsCode,
           "Quantity": totalQty,
           "Unit Price (USD)": p.landedCost || 0,
           "Total Amount (USD)": totalPrice.toFixed(2)
        };
      }
    });

    const worksheet = XLSX.utils.json_to_sheet(data);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, type === 'packinglist' ? "Packing List" : "Invoice");

    // Auto-width columns roughly
    const maxWidth = 20;
    const wscols = Object.keys(data[0]).map(() => ({ wch: maxWidth }));
    worksheet['!cols'] = wscols;

    XLSX.writeFile(workbook, `Yiwu_${type === 'packinglist' ? 'PackingList' : 'Invoice'}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      {/* Top Bar */}
      <header className="bg-white border-b px-8 py-4 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-slate-800">Yiwu Sourcing Manager</h1>
          <p className="text-sm text-slate-500">Documentation Center</p>
        </div>
        <div className="flex gap-2">
           <button 
             onClick={() => generateExcel('packinglist')} 
             className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 shadow-sm transition-colors"
           >
             <FileSpreadsheet size={16} /> Packing List
           </button>
           <button 
             onClick={() => generateExcel('invoice')} 
             className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 shadow-sm transition-colors"
           >
             <FileText size={16} /> Commercial Invoice
           </button>
           <div className="ml-4 flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-md border border-indigo-100">
             <span className="font-bold">{products.length}</span> SKU(s)
           </div>
        </div>
      </header>

      {/* Main Grid */}
      <main className="flex-1 overflow-auto p-8">
        <div className="bg-white rounded-lg shadow border border-slate-200 overflow-hidden">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-100 text-slate-600 uppercase font-bold text-xs">
              <tr>
                <th className="p-4 w-16">Foto</th>
                <th className="p-4 w-24">Status</th>
                <th className="p-4">Product Info (CN/EN)</th>
                <th className="p-4 w-32">HS Code / Tax</th>
                <th className="p-4">Material / Usage</th>
                <th className="p-4 w-24 text-right">RMB</th>
                <th className="p-4 w-24 text-right">Landed($)</th>
                <th className="p-4 w-32 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {products.length === 0 && (
                <tr>
                  <td colSpan={8} className="p-12 text-center text-slate-400">
                    No products yet. Use the Mobile view to add items (Supports Batch Upload).
                  </td>
                </tr>
