import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found via process.env.API_KEY");
  }
  return new GoogleGenAI({ apiKey });
};

// Text-based enrichment (existing)
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  const ai = getClient();

  const prompt = `
    You are an expert international trade sourcing agent in Yiwu, China.
    I have a product with the Chinese name: "${nameCn}".

    Please provide the following details for export documentation:
    1. English Product Name (Professional trade term).
    2. Material Composition (Guess the likely material in English, e.g., Stainless Steel 304, PP Plastic).
    3. HS Code (The most likely 6-digit Harmonized System code).
    4. Usage (Short description of use).
    5. EU Import Tax Rate (Estimated percentage as a number, e.g., 6.5).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "Professional English product name" },
            materialEn: { type: Type.STRING, description: "Material composition in English" },
            hsCode: { type: Type.STRING, description: "6-digit HS Code" },
            usage: { type: Type.STRING, description: "Short usage description" },
            taxRate: { type: Type.NUMBER, description: "Estimated EU tax rate percentage" }
          },
          required: ["nameEn", "materialEn", "hsCode", "usage", "taxRate"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

export interface ImageAnalysisResult {
  nameCn: string;
  priceRmb: number;
  moq: number;
  nameEn: string;
  materialEn: string;
  boxLength: number;
  boxWidth: number;
  boxHeight: number;
  pcsPerBox: number;
}

// Image-based analysis (Enhanced for OCR)
export const analyzeImage = async (base64Image: string): Promise<ImageAnalysisResult> => {
  const ai = getClient();
  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: `
            Analyze this wholesale product image. 
            1. OCR: Read any Chinese text for the Product Name. Read any numbers that look like dimensions (e.g., 60x50x40) or packing quantities (e.g., 120 PCS/CTN).
            2. Identification: If no text, describe the item in Chinese and English.
            3. Estimation: Estimate material, price, and MOQ if tags are visible.

            Return JSON. If dimensions are not found, return 0.
            ` 
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameCn: { type: Type.STRING, description: "Product Name (CN)" },
            priceRmb: { type: Type.NUMBER, description: "Price" },
            moq: { type: Type.NUMBER, description: "MOQ" },
            nameEn: { type: Type.STRING, description: "English Name" },
            materialEn: { type: Type.STRING, description: "Material" },
            boxLength: { type: Type.NUMBER, description: "Box Length (cm)" },
            boxWidth: { type: Type.NUMBER, description: "Box Width (cm)" },
            boxHeight: { type: Type.NUMBER, description: "Box Height (cm)" },
            pcsPerBox: { type: Type.NUMBER, description: "Items per carton" },
          },
          required: ["nameCn", "priceRmb", "moq", "nameEn", "materialEn", "boxLength", "boxWidth", "boxHeight", "pcsPerBox"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Image Analysis failed:", error);
    return {
      nameCn: "待识别商品 (Unidentified)",
      priceRmb: 0,
      moq: 0,
      nameEn: "Pending Analysis",
      materialEn: "",
      boxLength: 0,
      boxWidth: 0,
      boxHeight: 0,
      pcsPerBox: 0
    };
  }
};

