import React, { useState } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText } from 'lucide-react';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);

  const calculateMetrics = (p: Product) => {
    // Logic from PRD
    // CBM = (L*W*H)/1000000
    const cbm = (p.boxLength * p.boxWidth * p.boxHeight) / 1000000;
    // Estimated Freight (Simulated constant) + Tax + Base
    // Landed = RMB/7.2 (Ex rate) + (Freight/Pcs) + Duty
    const exRate = 7.2;
    const estimatedFreightPerCbm = 300; // USD
    const freightCost = cbm > 0 && p.pcsPerBox > 0 ? (estimatedFreightPerCbm * cbm) / p.pcsPerBox : 0;
    const baseUsd = p.priceRmb / exRate;
    const dutyCost = p.taxRate ? baseUsd * (p.taxRate / 100) : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      landedCost: Number((baseUsd + freightCost + dutyCost).toFixed(3))
    };
  };

  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) {
      alert("Please provide an API Key in the metadata/environment to use AI features.");
      return;
    }

    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });

    try {
      const result = await enrichProductData(product.nameCn);

      const metrics = calculateMetrics(product); 

      const updatedProduct: Product = {
        ...product,
        ...result,
        cbm: metrics.cbm,
        landedCost: metrics.landedCost, 
        status: ProcessingStatus.REVIEW_NEEDED
      };

      const finalMetrics = calculateMetrics(updatedProduct);
      updatedProduct.landedCost = finalMetrics.landedCost;

      onUpdateProduct(updatedProduct);
    } catch (error) {
      alert("AI Enrichment failed. See console.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const generateExcel = async (type: 'packinglist' | 'invoice') => {
    if (products.length === 0) {
      alert("No products to export.");
      return;
    }

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet(type === 'packinglist' ? 'Packing List' : 'Invoice');

    // Define Columns based on Screenshot Requirements
    // Image in First Column (A)
    const commonStyle = { alignment: { vertical: 'middle', horizontal: 'center', wrapText: true } };

    if (type === 'packinglist') {
      sheet.columns = [
        { header: 'Image', key: 'image', width: 16, style: commonStyle },
        { header: 'No.', key: 'no', width: 6, style: commonStyle },
        { header: 'SKU', key: 'sku', width: 15, style: commonStyle },
        { header: 'Description (EN)', key: 'desc', width: 35, style: { ...commonStyle, alignment: { ...commonStyle.alignment, horizontal: 'left' } } },
        { header: 'Material', key: 'material', width: 20, style: commonStyle },
        { header: 'HS Code', key: 'hscode', width: 15, style: commonStyle },
        { header: 'Qty (PCS)', key: 'qty', width: 10, style: commonStyle },
        { header: 'Pcs/Ctn', key: 'pcsBox', width: 10, style: commonStyle },
        { header: 'Cartons', key: 'cartons', width: 10, style: commonStyle },
        { header: 'CBM/Ctn', key: 'cbmCtn', width: 12, style: commonStyle },
        { header: 'Total CBM', key: 'totalCbm', width: 12, style: commonStyle },
        { header: 'G.W (KGS)', key: 'gw', width: 12, style: commonStyle },
        { header: 'Dimensions (cm)', key: 'dims', width: 20, style: commonStyle },
      ];
    } else {
      // Invoice
      sheet.columns = [
        { header: 'Image', key: 'image', width: 16, style: commonStyle },
        { header: 'No.', key: 'no', width: 6, style: commonStyle },
        { header: 'SKU', key: 'sku', width: 15, style: commonStyle },
        { header: 'Description', key: 'desc', width: 35, style: { ...commonStyle, alignment: { ...commonStyle.alignment, horizontal: 'left' } } },
        { header: 'HS Code', key: 'hscode', width: 15, style: commonStyle },
        { header: 'Quantity', key: 'qty', width: 12, style: commonStyle },
        { header: 'Unit Price (USD)', key: 'price', width: 15, style: commonStyle },
        { header: 'Total Amount (USD)', key: 'total', width: 18, style: commonStyle },
      ];
    }

    // Header styling
    sheet.getRow(1).font = { bold: true, size: 12 };
    sheet.getRow(1).height = 30;
    sheet.getRow(1).alignment = { vertical: 'middle', horizontal: 'center' };

    // Fill Data
    for (let i = 0; i < products.length; i++) {
      const p = products[i];
      const cartonQty = p.moq && p.pcsPerBox ? Math.ceil(p.moq / p.pcsPerBox) : 0;
      const totalQty = cartonQty * p.pcsPerBox || p.moq;
      const totalCbm = p.cbm ? p.cbm * cartonQty : 0;
      const totalPrice = p.landedCost ? p.landedCost * totalQty : 0;
      const rowIndex = i + 2; // Header is row 1

      // Values map
      const rowValues = type === 'packinglist' ? {
        no: i + 1,
        sku: p.sku,
        desc: p.nameEn || p.nameCn,
        material: p.materialEn || "N/A",
        hscode: p.hsCode || "---",
        qty: totalQty,
        pcsBox: p.pcsPerBox,
        cartons: cartonQty,
        cbmCtn: p.cbm?.toFixed(3),
        totalCbm: totalCbm.toFixed(3),
        gw: (totalCbm * 150).toFixed(2), // Estimation
        dims: `${p.boxLength}x${p.boxWidth}x${p.boxHeight}`
      } : {
        no: i + 1,
        sku: p.sku,
        desc: p.nameEn || p.nameCn,
        hscode: p.hsCode || "---",
        qty: totalQty,
        price: p.landedCost || 0,
        total: totalPrice.toFixed(2)
      };

      const row = sheet.addRow(rowValues);
      row.height = 80; // Set row height for image

      // Add Image
      if (p.photoUrl) {
        try {
          // Remove prefix if present (data:image/jpeg;base64,)
          const base64 = p.photoUrl.split(',')[1];
