import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found via process.env.API_KEY");
  }
  return new GoogleGenAI({ apiKey });
};

// Text-based enrichment: Now acts as a Customs Expert
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  const ai = getClient();

  const prompt = `
    You are a Senior Customs Broker and Sourcing Agent.
    Product Chinese Name: "${nameCn}".

    Task:
    1. Translate to a professional English Trade Name (Description).
    2. Identify the likely Material Composition (e.g., "PP Plastic", "Stainless Steel 304", "Polyester").
    3. Assign the most accurate 6-digit HS Code for export from China to EU.
    4. Describe Usage briefly.
    5. Estimate EU Import Duty Rate (%) based on common tariffs for this HS Code.

    Output JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "Trade Name (EN)" },
            materialEn: { type: Type.STRING, description: "Material Composition" },
            hsCode: { type: Type.STRING, description: "HS Code (6-digit)" },
            usage: { type: Type.STRING, description: "Usage" },
            taxRate: { type: Type.NUMBER, description: "Duty Rate (%)" }
          },
          required: ["nameEn", "materialEn", "hsCode", "usage", "taxRate"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

export interface ImageAnalysisResult {
  nameCn: string;
  priceRmb: number;
  moq: number;
  nameEn: string;
  materialEn: string;
  boxLength: number;
  boxWidth: number;
  boxHeight: number;
