    // Add nice border to header
    headerRow.eachCell((cell) => {
      cell.border = { bottom: { style: 'thin' } };
      cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF2F2F2' } };
    });

    // -- Row Generation --
    for (let i = 0; i < products.length; i++) {
      const p = products[i];
      const rowIndex = i + 2;

      // Calcs
      const cartonQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
      const totalQty = (cartonQty * p.pcsPerBox) || p.moq || 0;
      const totalCbm = (p.cbm || 0) * cartonQty;
      const unitPrice = p.landedCost || 0;
      const totalAmount = unitPrice * totalQty;

      // Estimate G.W: Simple formula CBM * 167 (Air) or just estimate. 
      // User screenshot shows 47.79 KGS for 0.319 CBM -> ~150kg/cbm ratio.
      const gw = totalCbm * 150; 

      const rowValues = type === 'packinglist' ? {
        no: i + 1,
        sku: p.sku,
        desc: p.nameEn || p.nameCn,
        material: p.materialEn || "",
        hscode: p.hsCode || "",
        qty: totalQty,
        pcsBox: p.pcsPerBox || 0,
        cartons: cartonQty,
        cbmCtn: p.cbm ? p.cbm.toFixed(3) : "0.000",
        totalCbm: totalCbm.toFixed(3),
        gw: gw.toFixed(2),
        dims: (p.boxLength && p.boxWidth) ? `${p.boxLength}x${p.boxWidth}x${p.boxHeight}` : "0x0x0"
      } : {
        no: i + 1,
        sku: p.sku,
        desc: p.nameEn || p.nameCn,
        hscode: p.hsCode || "",
        qty: totalQty,
        price: unitPrice.toFixed(3), // 3 decimals for Unit Price
        total: totalAmount.toFixed(2) // 2 decimals for Total
      };

      const row = sheet.addRow(rowValues);
      row.height = 80; // Enough height for image
      row.font = { name: 'Arial', size: 10 };

      // -- Add Image --
      if (p.photoUrl) {
        try {
          // Detect mime type simple check
          const signature = p.photoUrl.substring(0, 30);
          let ext: 'jpeg' | 'png' = 'jpeg';
          if (signature.includes('png')) ext = 'png';

          const base64 = p.photoUrl.split(',')[1];
          if (base64) {
            const imageId = workbook.addImage({
              base64: base64,
              extension: ext,
            });

            // Inset image slightly
            sheet.addImage(imageId, {
              tl: { col: 0.1, row: rowIndex - 1 + 0.1 },
              br: { col: 0.9, row: rowIndex - 0.1 }
            });
          }
        } catch (e) {
          console.warn("Image add error", e);
        }
      }
    }

    // Write Buffer
    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_${type === 'packinglist' ? 'PackingList' : 'Invoice'}.xlsx`);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      {/* Top Bar */}
      <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-10">
        <div>
          <h1 className="text-xl font-bold text-slate-800">Yiwu Sourcing Manager</h1>
          <p className="text-sm text-slate-500">Documentation Center</p>
        </div>
        <div className="flex gap-2">
           <button 
             onClick={() => generateExcel('packinglist')} 
             className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 shadow-sm transition-colors"
           >
             <FileSpreadsheet size={16} /> Packing List
