             onClick={() => generateExcel('invoice')} 
             className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 shadow-sm transition-colors"
           >
             <FileText size={16} /> Invoice
