                      </div>
                    </td>
                    <td className="p-4 text-right font-medium">¥{p.priceRmb}</td>
                    <td className="p-4 text-right font-bold text-green-600">
                      {p.landedCost ? `$${p.landedCost}` : "-"}
                    </td>
                    <td className="p-4 text-center">
                      {!isEnriched && !isProcessing && (
                        <button 
                          onClick={() => handleEnrichment(p)}
                          className="w-full flex items-center justify-center gap-1 bg-gradient-to-r from-violet-600 to-indigo-600 text-white px-3 py-1.5 rounded text-xs hover:shadow-md transition-all"
                        >
                          <Sparkles size={12} /> AI Auto-Fill
                        </button>
                      )}
                      {isEnriched && (
                        <button 
                          onClick={() => onUpdateProduct({...p, status: ProcessingStatus.COMPLETED})}
                          className="w-full flex items-center justify-center gap-1 bg-white border border-green-600 text-green-600 px-3 py-1.5 rounded text-xs hover:bg-green-50"
                        >
                          <CheckCircle2 size={12} /> Confirm
                        </button>
                      )}
                      {isProcessing && (
                         <div className="flex justify-center">
                           <RefreshCw size={16} className="animate-spin text-indigo-600" />
                         </div>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
};

