import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found via process.env.API_KEY");
  }
  return new GoogleGenAI({ apiKey });
};

// Text-based enrichment: Now acts as a Customs Expert & Translator
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  const ai = getClient();

  const prompt = `
    You are a Senior Customs Broker and Sourcing Agent.
    Product Chinese Name: "${nameCn}".

    Task:
    1. Translate to professional English Trade Name.
    2. Translate to Spanish Product Name (Nombre de Producto).
    3. Categorize (Main Category usually material or use, Sub Category specific item).
    4. Identify Material Composition.
    5. Assign HS Code (China export).
    6. Estimate EU Import Duty Rate (%).

    Output JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "English Name" },
            nameEs: { type: Type.STRING, description: "Spanish Name" },
            categoryMain: { type: Type.STRING, description: "Main Category (e.g. Kitchenware)" },
            categorySub: { type: Type.STRING, description: "Sub Category (e.g. Pots)" },
            materialEn: { type: Type.STRING, description: "Material Composition" },
            hsCode: { type: Type.STRING, description: "HS Code" },
            usage: { type: Type.STRING, description: "Usage" },
            taxRate: { type: Type.NUMBER, description: "EU Duty Rate (%)" }
          },
          required: ["nameEn", "nameEs", "categoryMain", "categorySub", "materialEn", "hsCode", "taxRate"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

