// Image-based analysis: Enhanced for Tag/Label Reading (OCR)
export const analyzeImage = async (base64Image: string): Promise<ImageAnalysisResult> => {
  const ai = getClient();
  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: `
            You are a Data Entry Clerk at Yiwu Market. Your job is to extract data from the PHOTO of the product and its TAG/LABEL.

            1. **FIND THE TAG**: Look for a white handwritten or printed card.
            2. **EXTRACT DATA**:
               - **Name**: Read Chinese name.
               - **Price**: Look for '¥', 'RMB', 'Price', '单价'.
               - **Packing (Pcs/Ctn)**: Look for 'Qty', '装箱数', 'Pcs/Ctn', 'PCS'.
               - **Dimensions (Meas)**: Look for 'Meas', 'Size', '规格', 'CBM'. Format is usually Length*Width*Height (e.g., 60*50*40). Extract these numbers accurately.

            3. **ESTIMATE (Only if tag is missing)**: 
               - Guess Material and English Name.
               - If Price/MOQ/Dimensions are strictly NOT visible, return 0. Do not hallucinate numbers.

            Output JSON format.
            ` 
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameCn: { type: Type.STRING, description: "Product Name (CN)" },
            priceRmb: { type: Type.NUMBER, description: "Price (RMB)" },
            moq: { type: Type.NUMBER, description: "MOQ" },
            nameEn: { type: Type.STRING, description: "English Name" },
            materialEn: { type: Type.STRING, description: "Material" },
            boxLength: { type: Type.NUMBER, description: "Box Length (cm)" },
            boxWidth: { type: Type.NUMBER, description: "Box Width (cm)" },
            boxHeight: { type: Type.NUMBER, description: "Box Height (cm)" },
            pcsPerBox: { type: Type.NUMBER, description: "Items per carton (Qty)" },
          },
          required: ["nameCn", "priceRmb", "moq", "nameEn", "materialEn", "boxLength", "boxWidth", "boxHeight", "pcsPerBox"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Image Analysis failed:", error);
    return {
      nameCn: "待识别商品",
      priceRmb: 0,
      moq: 0,
      nameEn: "Pending Analysis",
      materialEn: "",
      boxLength: 0,
      boxWidth: 0,
      boxHeight: 0,
      pcsPerBox: 0
    };
  }
};

import React, { useState, useEffect } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText, Settings, Database } from 'lucide-react';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);

  // Global Settings for Calculation
  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150); // Euro or USD per CBM
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2); // For USD calculations
  const [vatRate, setVatRate] = useState<number>(21); // Default Spain VAT 21%

  // Recalculate all products when global settings change
  useEffect(() => {
    products.forEach(p => {
      // Only update if parameters differ or if calculated fields are missing
      if (p.exRateEuroRmb !== euroRmbRate || p.freightRate !== freightRateCbm) {
         const metrics = calculateMetrics({ ...p, exRateEuroRmb: euroRmbRate, freightRate: freightRateCbm, vatRate: vatRate });
         const updated = { ...p, ...metrics };
         onUpdateProduct(updated);
      }
    });
  }, [euroRmbRate, freightRateCbm, vatRate]); // Warning: This might cause loop if not careful with dependency. 
  // In a real app, use a "Recalculate" button or separate context. 
  // For this demo, we will calculate dynamically on render/export to avoid state thrashing,
  // OR just update the single product being processed.

  const calculateMetrics = (p: Product, overrides?: { euroRate?: number, freight?: number, vat?: number }) => {
    const rate = overrides?.euroRate || euroRmbRate;
    const freight = overrides?.freight || freightRateCbm;
    const vat = overrides?.vat || vatRate;
    const usdRate = usdRmbRate;

    // 1. Specs
    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const gwLb = (p.gwKg || 0) * 2.2046;

    // 2. Costs
    // Freight per PC = (RatePerCbm * CBM) / PcsPerBox
    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) 
      ? (freight * cbm) / p.pcsPerBox 
      : 0;

    // Base Cost Euro = RMB / Rate
    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;

    // Duty Cost = BaseEuro * TaxRate
    const taxPercent = p.taxRate || 0;
    const dutyCost = baseCostEuro * (taxPercent / 100);

    // Landed Cost (Euro) = Base + Freight + Duty
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;

    // Spain Price (Euro) = Landed * Margin (e.g. 30%)? Or just Cost?
    // Let's assume a simple markup for "Spain Price" if needed, or just keep it as cost basis.
    // PRD says: "Spain Price" (Suggesting Retail or Wholesale price). Let's add 20% margin.
    const priceSpainEuro = landedCostEuro * 1.2;

    // Stock Price USD = RMB / USD Rate
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      gwLb: Number(gwLb.toFixed(2)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
      // Save current config snapshot
      exRateEuroRmb: rate,
      freightRate: freight,
      vatRate: vat
    };
  };

  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) {
      alert("Please provide an API Key.");
      return;
    }

    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });

    try {
      const result = await enrichProductData(product.nameCn);

      const mergedProduct = { ...product, ...result };
      const metrics = calculateMetrics(mergedProduct);

      const updatedProduct: Product = {
        ...mergedProduct,
        ...metrics,
        status: ProcessingStatus.REVIEW_NEEDED
      };

      onUpdateProduct(updatedProduct);
    } catch (error) {
      alert("AI Enrichment failed.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice') => {
    if (products.length === 0) {
      alert("No products to export.");
      return;
    }

    const workbook = new ExcelJS.Workbook();
    let sheetName = 'Sheet1';
    if (exportType === 'master') sheetName = 'Product Info';
    if (exportType === 'packinglist') sheetName = 'Packing List';
    if (exportType === 'invoice') sheetName = 'Invoice';

    const sheet = workbook.addWorksheet(sheetName);

    // -- Header Styles --
    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };

    // -- Define Columns based on Export Type --
    if (exportType === 'master') {
      // The Full "Product Info" Schema
      sheet.columns = [
        { header: 'Image', key: 'image', width: 12 },
        { header: 'SKU', key: 'sku', width: 12, style: centerStyle },
        { header: 'Name (CN)', key: 'nameCn', width: 20, style: leftStyle },
        { header: 'Product Name (EN)', key: 'nameEn', width: 25, style: leftStyle },
        { header: 'Nombre Producto (ES)', key: 'nameEs', width: 25, style: leftStyle },
        { header: 'Category', key: 'catMain', width: 15, style: centerStyle },
        { header: 'Sub-Cat', key: 'catSub', width: 15, style: centerStyle },
        { header: 'Material', key: 'mat', width: 20, style: leftStyle },
        { header: 'HS Code', key: 'hs', width: 12, style: centerStyle },

        // Specs
        { header: 'L (cm)', key: 'l', width: 8, style: centerStyle },
        { header: 'W (cm)', key: 'w', width: 8, style: centerStyle },
        { header: 'H (cm)', key: 'h', width: 8, style: centerStyle },
        { header: 'Pcs/Box', key: 'pcs', width: 8, style: centerStyle },
        { header: 'CBM', key: 'cbm', width: 10, style: centerStyle },
        { header: 'G.W(kg)', key: 'gw', width: 8, style: centerStyle },

        // Finance
        { header: 'Cost (RMB)', key: 'rmb', width: 10, style: centerStyle },
        { header: 'Duty(%)', key: 'tax', width: 8, style: centerStyle },
        { header: 'Frt/Pc(€)', key: 'frt', width: 10, style: centerStyle },
        { header: 'Landed(€)', key: 'landed', width: 10, style: centerStyle },
        { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
      ];
    } else if (exportType === 'packinglist') {
      sheet.columns = [
        { header: 'Image', key: 'image', width: 16 },
        { header: 'No.', key: 'no', width: 6, style: centerStyle },
        { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
        { header: 'Description', key: 'desc', width: 35, style: leftStyle },
        { header: 'Qty (PCS)', key: 'qty', width: 10, style: centerStyle },
        { header: 'Cartons', key: 'cartons', width: 10, style: centerStyle },
        { header: 'CBM', key: 'totalCbm', width: 12, style: centerStyle },
        { header: 'G.W (KGS)', key: 'totalGw', width: 12, style: centerStyle },
      ];
    } else {
      // Invoice
      sheet.columns = [
        { header: 'Image', key: 'image', width: 16 },
        { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
        { header: 'Description', key: 'desc', width: 35, style: leftStyle },
        { header: 'HS Code', key: 'hs', width: 15, style: centerStyle },
        { header: 'Qty', key: 'qty', width: 10, style: centerStyle },
        { header: 'Unit Price ($)', key: 'price', width: 15, style: centerStyle },
        { header: 'Total ($)', key: 'total', width: 18, style: centerStyle },
      ];
    }

    // Header Styles
    sheet.getRow(1).font = { bold: true, size: 11 };
    sheet.getRow(1).height = 25;
    sheet.getRow(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFEEEEEE' } };

    // -- Populate Data --
    for (let i = 0; i < products.length; i++) {
      const p = products[i];
      // Ensure metrics are fresh (using current global state)
      const metrics = calculateMetrics(p); 

      const rowIndex = i + 2;
      const cartonQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
      const totalQty = (cartonQty * p.pcsPerBox) || p.moq || 0;
      const totalCbm = (metrics.cbm || 0) * cartonQty;
      const totalGw = (p.gwKg || 15) * cartonQty; // Default 15kg if missing

      let rowValues = {};

      if (exportType === 'master') {
        rowValues = {
          sku: p.sku,
          nameCn: p.nameCn,
          nameEn: p.nameEn,
          nameEs: p.nameEs,
          catMain: p.categoryMain,
          catSub: p.categorySub,
          mat: p.materialEn,
          hs: p.hsCode,
          l: p.boxLength,
          w: p.boxWidth,
          h: p.boxHeight,
          pcs: p.pcsPerBox,
          cbm: metrics.cbm,
          gw: p.gwKg || 0,
          rmb: p.priceRmb,
          tax: p.taxRate,
          frt: metrics.freightPerPc,
          landed: metrics.landedCostEuro,
          moq: p.moq
        };
      } else if (exportType === 'packinglist') {
        rowValues = {
          no: i + 1,
          sku: p.sku,
          desc: p.nameEn || p.nameCn,
          qty: totalQty,
          cartons: cartonQty,
          totalCbm: totalCbm.toFixed(3),
          totalGw: totalGw.toFixed(2)
        };
      } else {
        // Invoice
        rowValues = {
          sku: p.sku,
          desc: p.nameEn || p.nameCn,
          hs: p.hsCode,
          qty: totalQty,
          price: metrics.priceStockUsd?.toFixed(3), // Using Stock Price USD for Invoice
          total: (metrics.priceStockUsd ? metrics.priceStockUsd * totalQty : 0).toFixed(2)
        };
      }

      const row = sheet.addRow(rowValues);
      row.height = 60; // Space for image

      // Image Embedding
      if (p.photoUrl) {
        try {
          const base64 = p.photoUrl.split(',')[1];
          if (base64) {
            const imageId = workbook.addImage({
              base64: base64,
              extension: 'jpeg',
            });
            sheet.addImage(imageId, {
              tl: { col: 0.1, row: rowIndex - 1 + 0.1 },
              br: { col: 0.9, row: rowIndex - 0.1 }
            });
          }
        } catch (e) {
          console.warn("Image error", e);
        }
      }
    }

    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_${exportType}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">

      {/* Settings & Header */}
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-10 shadow-sm">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <Database className="text-blue-600" /> 
              Yiwu Product Master
            </h1>
            <p className="text-sm text-slate-500">Manage Master Data -> Generate Docs</p>
          </div>

          <div className="flex gap-2">
             <button onClick={() => generateExcel('master')} className="btn-export bg-indigo-600">
               <Database size={16} /> Export Master Info
             </button>
             <div className="h-8 w-px bg-gray-300 mx-2"></div>
             <button onClick={() => generateExcel('packinglist')} className="btn-export bg-green-600">
               <FileSpreadsheet size={16} /> Packing List
             </button>
             <button onClick={() => generateExcel('invoice')} className="btn-export bg-blue-600">
               <FileText size={16} /> Invoice
             </button>
          </div>
        </div>

        {/* Global Configuration Bar */}
        <div className="bg-slate-100 p-3 rounded-lg flex flex-wrap gap-6 items-center text-sm border border-slate-200">
          <div className="flex items-center gap-2">
            <Settings size={14} className="text-slate-500" />
            <span className="font-bold text-slate-700">Global Config:</span>
          </div>

          <div className="flex items-center gap-2">
            <label>Rate (EUR/RMB):</label>
            <input 
              type="number" 
              value={euroRmbRate} 
              onChange={e => setEuroRmbRate(Number(e.target.value))}
              className="w-16 p-1 border rounded text-center font-mono"
            />
          </div>

          <div className="flex items-center gap-2">
            <label>Frt Rate (€/CBM):</label>
            <input 
              type="number" 
              value={freightRateCbm} 
              onChange={e => setFreightRateCbm(Number(e.target.value))}
              className="w-16 p-1 border rounded text-center font-mono"
            />
          </div>

          <div className="flex items-center gap-2">
            <label>Duty (%):</label>
            <input 
              type="number" 
              value={vatRate} // Using as generic Duty/Tax placeholder for input
              onChange={e => setVatRate(Number(e.target.value))} // Actually maps to TaxRate logic in enriching
              className="w-16 p-1 border rounded text-center font-mono"
            />
            <span className="text-xs text-gray-400">(Default)</span>
          </div>
        </div>
      </header>

      {/* Main Data Grid */}
      <main className="flex-1 overflow-auto p-6">
        <div className="bg-white rounded-lg shadow border border-slate-200 overflow-hidden">
          <table className="w-full text-left text-xs">
            <thead className="bg-slate-100 text-slate-600 uppercase font-bold sticky top-0 z-0">
              <tr>
                <th className="p-3 w-16">Img</th>
                <th className="p-3">Core Info</th>
                <th className="p-3">Specs (Box)</th>
                <th className="p-3 text-right">Cost (¥)</th>
                <th className="p-3 text-right">Landed (€)</th>
                <th className="p-3 text-center">AI Data</th>
                <th className="p-3 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {products.map((p) => {
                const metrics = calculateMetrics(p); // Dynamic calc for display
                const isProcessing = processingId === p.id;

                return (
                  <tr key={p.id} className="hover:bg-slate-50">
                    <td className="p-3">
                      <img src={p.photoUrl} className="w-10 h-10 rounded border object-cover" />
                    </td>
                    <td className="p-3">
                      <div className="font-bold text-slate-800">{p.sku}</div>
                      <div className="text-slate-600">{p.nameCn}</div>
                      <div className="text-indigo-600">{p.nameEn || "-"}</div>
                    </td>
                    <td className="p-3">
                      <div>{p.boxLength}x{p.boxWidth}x{p.boxHeight} cm</div>
                      <div className="text-slate-500">{p.pcsPerBox} pcs/ctn</div>
                      <div className="font-mono text-xs">{metrics.cbm.toFixed(3)} m³</div>
                    </td>
                    <td className="p-3 text-right font-medium text-slate-700">
                      ¥{p.priceRmb}
                    </td>
                    <td className="p-3 text-right">
                      <div className="font-bold text-green-600">€{metrics.landedCostEuro.toFixed(2)}</div>
                      <div className="text-slate-400 text-[10px]">Frt: {metrics.freightPerPc.toFixed(2)}</div>
                    </td>
                    <td className="p-3">
                      {p.hsCode ? (
                        <div className="space-y-1">
                          <span className="bg-gray-100 px-1 rounded text-[10px]">HS: {p.hsCode}</span>
                          <span className="bg-gray-100 px-1 rounded text-[10px] block">Mat: {p.materialEn?.slice(0,10)}..</span>
                          <span className="bg-orange-50 text-orange-700 px-1 rounded text-[10px] block">Duty: {p.taxRate}%</span>
                        </div>
                      ) : (
                        <span className="text-slate-300">-</span>
                      )}
                    </td>
                    <td className="p-3 text-center">
                       <button 
                          onClick={() => handleEnrichment(p)}
                          disabled={isProcessing}
                          className="p-2 bg-indigo-50 text-indigo-600 rounded hover:bg-indigo-100 transition-colors"
                          title="Auto-Fill with AI"
                        >
                          {isProcessing ? <RefreshCw size={14} className="animate-spin" /> : <Sparkles size={14} />}
                        </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </main>

      <style>{`
        .btn-export {
          @apply flex items-center gap-2 px-3 py-2 text-white rounded-md text-xs font-medium hover:opacity-90 transition-opacity shadow-sm;
        }
      `}</style>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText, Settings, Database, Edit, Save as SaveIcon, X } from 'lucide-react';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Product>>({});

  // Global Settings for Calculation
  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150); // Euro or USD per CBM
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2); // For USD calculations
  const [vatRate, setVatRate] = useState<number>(21); // Default Spain VAT 21%

  // Recalculate all products when global settings change
  useEffect(() => {
    products.forEach(p => {
      // Only update if parameters differ or if calculated fields are missing
      if (p.exRateEuroRmb !== euroRmbRate || p.freightRate !== freightRateCbm) {
         const metrics = calculateMetrics({ ...p, exRateEuroRmb: euroRmbRate, freightRate: freightRateCbm, vatRate: vatRate });
         const updated = { ...p, ...metrics };
         onUpdateProduct(updated);
      }
    });
  }, [euroRmbRate, freightRateCbm, vatRate]);

  const calculateMetrics = (p: Product, overrides?: { euroRate?: number, freight?: number, vat?: number }) => {
    const rate = overrides?.euroRate || euroRmbRate;
    const freight = overrides?.freight || freightRateCbm;
    const vat = overrides?.vat || vatRate;
    const usdRate = usdRmbRate;

    // 1. Specs
    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const gwLb = (p.gwKg || 0) * 2.2046;

    // 2. Costs
    // Freight per PC = (RatePerCbm * CBM) / PcsPerBox
    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) 
      ? (freight * cbm) / p.pcsPerBox 
      : 0;

    // Base Cost Euro = RMB / Rate
    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;

    // Duty Cost = BaseEuro * TaxRate
    const taxPercent = p.taxRate || 0;
    const dutyCost = baseCostEuro * (taxPercent / 100);

    // Landed Cost (Euro) = Base + Freight + Duty
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;

    // Spain Price (Euro) = Landed * Margin (e.g. 20%)
    const priceSpainEuro = landedCostEuro * 1.2;

    // Stock Price USD = RMB / USD Rate
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      gwLb: Number(gwLb.toFixed(2)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
      exRateEuroRmb: rate,
      freightRate: freight,
      vatRate: vat
    };
  };

  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) {
      alert("Please provide an API Key.");
      return;
    }

    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });

    try {
      const result = await enrichProductData(product.nameCn);

      const mergedProduct = { ...product, ...result };
      const metrics = calculateMetrics(mergedProduct);

      const updatedProduct: Product = {
        ...mergedProduct,
        ...metrics,
        status: ProcessingStatus.REVIEW_NEEDED
      };

      onUpdateProduct(updatedProduct);
    } catch (error) {
      alert("AI Enrichment failed.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const startEditing = (product: Product) => {
    setEditingId(product.id);
    setEditForm({ ...product });
  };

  const saveEdit = () => {
    if (!editingId) return;
    const product = products.find(p => p.id === editingId);
    if (product) {
        const merged = { ...product, ...editForm };
        const metrics = calculateMetrics(merged);
        onUpdateProduct({ ...merged, ...metrics });
    }
    setEditingId(null);
    setEditForm({});
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice') => {
    if (products.length === 0) {
      alert("No products to export.");
      return;
    }

    const workbook = new ExcelJS.Workbook();
    let sheetName = 'Sheet1';
    if (exportType === 'master') sheetName = 'Product Info';
    if (exportType === 'packinglist') sheetName = 'Packing List';
    if (exportType === 'invoice') sheetName = 'Invoice';

    const sheet = workbook.addWorksheet(sheetName);

    // -- Header Styles --
    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };

    // -- Define Columns based on Export Type --
    if (exportType === 'master') {
      // STRICT ORDER from Screenshot
      // Image, SKU, Name (CN), Product Name (EN), Nombre Producto (ES), Category, Sub-Cat, Material, HS Code, 
      // L (cm), W (cm), H (cm), Pcs/Box, CBM, G.W(kg), Cost (RMB), Duty(%), Frt/Pc(€), Landed(€), MOQ
      sheet.columns = [
        { header: 'Image', key: 'image', width: 14 },
        { header: 'SKU', key: 'sku', width: 12, style: centerStyle },
        { header: 'Name (CN)', key: 'nameCn', width: 20, style: leftStyle },
        { header: 'Product Name (EN)', key: 'nameEn', width: 25, style: leftStyle },
        { header: 'Nombre Producto (ES)', key: 'nameEs', width: 25, style: leftStyle },
        { header: 'Category', key: 'catMain', width: 15, style: centerStyle },
        { header: 'Sub-Cat', key: 'catSub', width: 15, style: centerStyle },
        { header: 'Material', key: 'mat', width: 30, style: leftStyle }, // Wider for description
        { header: 'HS Code', key: 'hs', width: 12, style: centerStyle },

        // Specs
        { header: 'L (cm)', key: 'l', width: 8, style: centerStyle },
        { header: 'W (cm)', key: 'w', width: 8, style: centerStyle },
        { header: 'H (cm)', key: 'h', width: 8, style: centerStyle },
        { header: 'Pcs/Box', key: 'pcs', width: 8, style: centerStyle },
        { header: 'CBM', key: 'cbm', width: 10, style: centerStyle },
        { header: 'G.W(kg)', key: 'gw', width: 8, style: centerStyle },

        // Finance
        { header: 'Cost (RMB)', key: 'rmb', width: 10, style: centerStyle },
        { header: 'Duty(%)', key: 'tax', width: 8, style: centerStyle },
        { header: 'Frt/Pc(€)', key: 'frt', width: 10, style: centerStyle },
        { header: 'Landed(€)', key: 'landed', width: 10, style: centerStyle },
        { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
      ];
    } else if (exportType === 'packinglist') {
      sheet.columns = [
        { header: 'Image', key: 'image', width: 16 },
        { header: 'No.', key: 'no', width: 6, style: centerStyle },
        { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
        { header: 'Description', key: 'desc', width: 35, style: leftStyle },
        { header: 'Qty (PCS)', key: 'qty', width: 10, style: centerStyle },
        { header: 'Cartons', key: 'cartons', width: 10, style: centerStyle },
        { header: 'CBM', key: 'totalCbm', width: 12, style: centerStyle },
        { header: 'G.W (KGS)', key: 'totalGw', width: 12, style: centerStyle },
      ];
    } else {
      // Invoice
      sheet.columns = [
        { header: 'Image', key: 'image', width: 16 },
        { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
        { header: 'Description', key: 'desc', width: 35, style: leftStyle },
        { header: 'HS Code', key: 'hs', width: 15, style: centerStyle },
        { header: 'Qty', key: 'qty', width: 10, style: centerStyle },
        { header: 'Unit Price ($)', key: 'price', width: 15, style: centerStyle },
        { header: 'Total ($)', key: 'total', width: 18, style: centerStyle },
      ];
    }

    // Header Styles
    sheet.getRow(1).font = { bold: true, size: 10, name: 'Arial' };
    sheet.getRow(1).height = 30;
    sheet.getRow(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFEEEEEE' } };
    sheet.getRow(1).alignment = { vertical: 'middle', horizontal: 'center' };

    // -- Populate Data --
    for (let i = 0; i < products.length; i++) {
      const p = products[i];
      // Ensure metrics are fresh (using current global state)
      const metrics = calculateMetrics(p); 

      const rowIndex = i + 2;
      const cartonQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
      const totalQty = (cartonQty * p.pcsPerBox) || p.moq || 0;
      const totalCbm = (metrics.cbm || 0) * cartonQty;
      const totalGw = (p.gwKg || 15) * cartonQty; 

      let rowValues = {};

      if (exportType === 'master') {
        rowValues = {
          sku: p.sku,
          nameCn: p.nameCn,
          nameEn: p.nameEn,
          nameEs: p.nameEs,
          catMain: p.categoryMain,
          catSub: p.categorySub,
          mat: p.materialEn,
          hs: p.hsCode,
          l: p.boxLength,
          w: p.boxWidth,
          h: p.boxHeight,
          pcs: p.pcsPerBox,
          cbm: metrics.cbm,
          gw: p.gwKg || 0,
          rmb: p.priceRmb,
          tax: p.taxRate,
          frt: metrics.freightPerPc,
          landed: metrics.landedCostEuro,
          moq: p.moq
        };
      } else if (exportType === 'packinglist') {
        rowValues = {
          no: i + 1,
          sku: p.sku,
          desc: p.nameEn || p.nameCn,
          qty: totalQty,
          cartons: cartonQty,
          totalCbm: totalCbm.toFixed(3),
          totalGw: totalGw.toFixed(2)
        };
      } else {
        rowValues = {
          sku: p.sku,
          desc: p.nameEn || p.nameCn,
          hs: p.hsCode,
          qty: totalQty,
          price: metrics.priceStockUsd?.toFixed(3),
          total: (metrics.priceStockUsd ? metrics.priceStockUsd * totalQty : 0).toFixed(2)
        };
      }

      const row = sheet.addRow(rowValues);
      row.height = 70; // Fixed height to fit image well

      // Image Embedding - Refined for "Fit"
      if (p.photoUrl) {
        try {
          const base64 = p.photoUrl.split(',')[1];
          if (base64) {
            const imageId = workbook.addImage({
              base64: base64,
              extension: 'jpeg',
            });
            // Padding 0.05 ensures it doesn't touch the grid lines, 'oneCell' property ensures it behaves like a cell content
            sheet.addImage(imageId, {
              tl: { col: 0.05, row: rowIndex - 1 + 0.05 },
              br: { col: 0.95, row: rowIndex - 0.05 },
              editAs: 'oneCell' 
            });
          }
        } catch (e) {
          console.warn("Image error", e);
        }
      }
    }

    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_${exportType}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">

      {/* Settings & Header */}
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-10 shadow-sm">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <Database className="text-blue-600" /> 
              Yiwu Product Master
            </h1>
            <p className="text-sm text-slate-500">Manage Master Data &rarr; Export to Excel</p>
          </div>

          <div className="flex gap-2">
             <button onClick={() => generateExcel('master')} className="btn-export bg-indigo-600">
               <Database size={16} /> Export Master Info
             </button>
             <div className="h-8 w-px bg-gray-300 mx-2"></div>
             <button onClick={() => generateExcel('packinglist')} className="btn-export bg-green-600">
               <FileSpreadsheet size={16} /> Packing List
             </button>
             <button onClick={() => generateExcel('invoice')} className="btn-export bg-blue-600">
               <FileText size={16} /> Invoice
             </button>
          </div>
        </div>

        {/* Global Configuration Bar */}
        <div className="bg-slate-100 p-3 rounded-lg flex flex-wrap gap-6 items-center text-sm border border-slate-200">
          <div className="flex items-center gap-2">
            <Settings size={14} className="text-slate-500" />
            <span className="font-bold text-slate-700">Config:</span>
          </div>

          <div className="flex items-center gap-2">
            <label>Rate (EUR/RMB):</label>
            <input 
              type="number" 
              value={euroRmbRate} 
              onChange={e => setEuroRmbRate(Number(e.target.value))}
              className="w-16 p-1 border rounded text-center font-mono"
            />
          </div>

          <div className="flex items-center gap-2">
            <label>Frt Rate (€/CBM):</label>
            <input 
              type="number" 
              value={freightRateCbm} 
              onChange={e => setFreightRateCbm(Number(e.target.value))}
              className="w-16 p-1 border rounded text-center font-mono"
            />
          </div>

          <div className="flex items-center gap-2">
            <label>Duty (%):</label>
            <input 
              type="number" 
              value={vatRate} 
              onChange={e => setVatRate(Number(e.target.value))}
              className="w-16 p-1 border rounded text-center font-mono"
            />
          </div>
        </div>
      </header>

      {/* Main Data Grid */}
      <main className="flex-1 overflow-auto p-6">
        <div className="bg-white rounded-lg shadow border border-slate-200 overflow-x-auto">
          <table className="w-full text-left text-xs min-w-[1200px]">
            <thead className="bg-slate-100 text-slate-600 uppercase font-bold sticky top-0 z-0">
              <tr>
                <th className="p-3 w-16">Img</th>
                <th className="p-3">Core Info</th>
                <th className="p-3">English / Spanish</th>
                <th className="p-3">Category</th>
                <th className="p-3">Specs (Box)</th>
                <th className="p-3 text-right">Cost (¥)</th>
                <th className="p-3 text-right">Landed (€)</th>
                <th className="p-3 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {products.map((p) => {
                const metrics = calculateMetrics(p); 
                const isProcessing = processingId === p.id;
                const isEditing = editingId === p.id;

                return (
                  <tr key={p.id} className={`hover:bg-slate-50 ${isEditing ? 'bg-indigo-50' : ''}`}>
                    <td className="p-3">
                      <img src={p.photoUrl} className="w-10 h-10 rounded border object-cover bg-white" />
                    </td>

                    {/* Core Info */}
                    <td className="p-3">
                      <div className="font-bold text-slate-800">{p.sku}</div>
                      {isEditing ? (
                        <input 
                          className="w-full p-1 border rounded text-xs mt-1" 
                          value={editForm.nameCn || ''} 
                          onChange={e => setEditForm({...editForm, nameCn: e.target.value})}
                          placeholder="CN Name"
                        />
                      ) : (
                        <div className="text-slate-600">{p.nameCn}</div>
                      )}
                      <div className="text-xs text-gray-400">HS: {p.hsCode}</div>
                    </td>

                    {/* Translations */}
                    <td className="p-3 max-w-[200px]">
                      {isEditing ? (
                         <div className="space-y-1">
                           <input 
                              className="w-full p-1 border rounded text-xs" 
                              value={editForm.nameEn || ''} 
                              onChange={e => setEditForm({...editForm, nameEn: e.target.value})}
                              placeholder="English Name"
                           />
                           <input 
                              className="w-full p-1 border rounded text-xs" 
                              value={editForm.nameEs || ''} 
                              onChange={e => setEditForm({...editForm, nameEs: e.target.value})}
                              placeholder="Spanish Name"
                           />
                         </div>
                      ) : (
                        <>
                           <div className="text-indigo-600 font-medium">{p.nameEn || "-"}</div>
                           <div className="text-emerald-600 italic">{p.nameEs || "-"}</div>
                        </>
                      )}
                    </td>

                    {/* Category */}
                    <td className="p-3">
                       {isEditing ? (
                         <div className="space-y-1">
                           <input 
                              className="w-full p-1 border rounded text-xs" 
                              value={editForm.categoryMain || ''} 
                              onChange={e => setEditForm({...editForm, categoryMain: e.target.value})}
                              placeholder="Main Cat"
                           />
                           <input 
                              className="w-full p-1 border rounded text-xs" 
                              value={editForm.categorySub || ''} 
                              onChange={e => setEditForm({...editForm, categorySub: e.target.value})}
                              placeholder="Sub Cat"
                           />
                         </div>
                       ) : (
                         <div className="space-y-1">
                            <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] block w-fit">{p.categoryMain || "N/A"}</span>
                            <span className="text-gray-400 text-[10px] block pl-1">&rarr; {p.categorySub || "N/A"}</span>
                         </div>
                       )}
                    </td>

                    {/* Specs */}
                    <td className="p-3">
                      {isEditing ? (
                         <div className="flex gap-1">
                            <input className="w-8 p-1 border rounded" placeholder="L" type="number" value={editForm.boxLength} onChange={e => setEditForm({...editForm, boxLength: Number(e.target.value)})} />
                            <input className="w-8 p-1 border rounded" placeholder="W" type="number" value={editForm.boxWidth} onChange={e => setEditForm({...editForm, boxWidth: Number(e.target.value)})} />
                            <input className="w-8 p-1 border rounded" placeholder="H" type="number" value={editForm.boxHeight} onChange={e => setEditForm({...editForm, boxHeight: Number(e.target.value)})} />
                         </div>
                      ) : (
                        <div>{p.boxLength}x{p.boxWidth}x{p.boxHeight} cm</div>
                      )}

                      <div className="text-slate-500 mt-1 flex items-center gap-2">
                        {isEditing ? (
                           <input className="w-12 p-1 border rounded" placeholder="Pcs" type="number" value={editForm.pcsPerBox} onChange={e => setEditForm({...editForm, pcsPerBox: Number(e.target.value)})} />
                        ) : (
                           <span>{p.pcsPerBox} pcs/ctn</span>
                        )}
                        <span className="font-mono text-xs text-gray-400">| {metrics.cbm.toFixed(3)} m³</span>
                      </div>
                    </td>

                    {/* Cost RMB */}
                    <td className="p-3 text-right font-medium text-slate-700">
                      {isEditing ? (
                        <input 
                          className="w-16 p-1 border rounded text-right" 
                          type="number" 
                          value={editForm.priceRmb} 
                          onChange={e => setEditForm({...editForm, priceRmb: Number(e.target.value)})}
                        />
                      ) : (
                        `¥${p.priceRmb}`
                      )}
                    </td>

                    {/* Landed Euro */}
                    <td className="p-3 text-right">
                      <div className="font-bold text-green-600">€{metrics.landedCostEuro.toFixed(2)}</div>
                      <div className="text-slate-400 text-[10px]">Duty: {p.taxRate}%</div>
                    </td>

                    {/* Actions */}
                    <td className="p-3 text-center">
                      <div className="flex flex-col gap-2 items-center">
                        {isEditing ? (
                          <>
                            <button onClick={saveEdit} className="p-1.5 bg-green-100 text-green-700 rounded hover:bg-green-200" title="Save">
                              <SaveIcon size={14} />
                            </button>
                            <button onClick={cancelEdit} className="p-1.5 bg-red-100 text-red-700 rounded hover:bg-red-200" title="Cancel">
                              <X size={14} />
                            </button>
                          </>
                        ) : (
                          <>
                             <button 
                                onClick={() => handleEnrichment(p)}
                                disabled={isProcessing}
                                className="p-1.5 bg-indigo-50 text-indigo-600 rounded hover:bg-indigo-100 transition-colors"
                                title="Auto-Fill with AI"
                              >
                                {isProcessing ? <RefreshCw size={14} className="animate-spin" /> : <Sparkles size={14} />}
                              </button>
                              <button 
                                onClick={() => startEditing(p)}
                                className="p-1.5 bg-gray-50 text-gray-600 rounded hover:bg-gray-100 transition-colors"
                                title="Edit Manually"
                              >
                                <Edit size={14} />
                              </button>
                          </>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </main>

      <style>{`
        .btn-export {
          @apply flex items-center gap-2 px-3 py-2 text-white rounded-md text-xs font-medium hover:opacity-90 transition-opacity shadow-sm;
        }
      `}</style>
    </div>
  );
};

