import React, { useState, useEffect } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText, Settings, Database, Edit, Save as SaveIcon, X, Trash2, CheckSquare, Square, Printer } from 'lucide-react';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void; // New prop for batch delete
}

// Default Invoice Configuration
const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832",
  bankBeneficiary: "YiWu Edas Import and Export Co., Ltd",
  bankName: "TED BANK, Yiwu Branch",
  bankAddress: "TED Address, Yiwu, China",
  bankSwift: "TEDXXXX",
  bankAccount: "TED-ACCOUNT-NUMBER",
};

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct, onDeleteProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Product>>({});

  // Batch Actions State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);

  // Invoice Config Modal State
  const [showInvoiceModal, setShowInvoiceModal] = useState(false);
  const [invoiceConfig, setInvoiceConfig] = useState(DEFAULT_INVOICE_CONFIG);

  // Global Settings for Calculation
  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150);
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2); 
  const [vatRate, setVatRate] = useState<number>(21);

  // --- Metrics Calculation ---
  const calculateMetrics = (p: Product, overrides?: { euroRate?: number, freight?: number, vat?: number }) => {
    const rate = overrides?.euroRate || euroRmbRate;
    const freight = overrides?.freight || freightRateCbm;
    const vat = overrides?.vat || vatRate;
    const usdRate = usdRmbRate;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const gwLb = (p.gwKg || 0) * 2.2046;

    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) 
      ? (freight * cbm) / p.pcsPerBox 
      : 0;

    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;
    const dutyCost = baseCostEuro * ((p.taxRate || 0) / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      gwLb: Number(gwLb.toFixed(2)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
      exRateEuroRmb: rate,
      freightRate: freight,
      vatRate: vat
    };
  };

  // --- Selection Handlers ---
  const toggleSelectAll = () => {
    if (selectedIds.size === products.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(products.map(p => p.id)));
    }
  };

  const toggleSelectRow = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedIds(newSet);
  };

  // --- Bulk Actions ---
  const handleBulkDelete = () => {
    if (confirm(`Are you sure you want to delete ${selectedIds.size} items?`)) {
      // In a real app we would call onDeleteProduct passed from props
      // Since we didn't add it to props in previous steps, let's just simulate or assume props updated
      // For now, we will manually filter local products if prop exists, else alert
      if (onDeleteProduct) {
        onDeleteProduct(Array.from(selectedIds));
        setSelectedIds(new Set());
      } else {
        alert("Delete function needs to be passed from parent.");
      }
    }
  };

  const handleBulkEnrich = async () => {
    setIsBulkProcessing(true);
    const itemsToProcess = products.filter(p => selectedIds.has(p.id));

    // Process sequentially to avoid rate limits, or Promise.all if API allows
    for (const product of itemsToProcess) {
       try {
         const result = await enrichProductData(product.nameCn);
         const metrics = calculateMetrics({ ...product, ...result });
         onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
       } catch (e) {
         console.error(`Failed to enrich ${product.id}`, e);
       }
    }
    setIsBulkProcessing(false);
    setSelectedIds(new Set());
    alert("Batch Processing Completed!");
  };

  // --- Single Item Actions ---
  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) return alert("API Key missing");
    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });
    try {
      const result = await enrichProductData(product.nameCn);
      const metrics = calculateMetrics({ ...product, ...result });
      onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
    } catch (error) {
      alert("AI Enrichment failed.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const startEditing = (product: Product) => {
    setEditingId(product.id);
    setEditForm({ ...product });
  };
  const saveEdit = () => {
    if (!editingId) return;
    const product = products.find(p => p.id === editingId);
    if (product) {
        const merged = { ...product, ...editForm };
        const metrics = calculateMetrics(merged);
        onUpdateProduct({ ...merged, ...metrics });
    }
    setEditingId(null);
    setEditForm({});
  };

  // --- EXCEL GENERATION ---
  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice') => {
    if (products.length === 0) return alert("No products to export.");

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet(exportType === 'invoice' ? 'INVOICE' : 'Sheet1');

    // Helper Styles
    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };
    const borderStyle = {
      top: { style: 'thin' },
      left: { style: 'thin' },
      bottom: { style: 'thin' },
      right: { style: 'thin' }
    };

    if (exportType === 'invoice') {
      // --- CUSTOM INVOICE FORMAT ---

      // 1. Setup Columns (A-N based on screenshot)
      sheet.columns = [
        { key: 'no', width: 5 },          // A: No.
        { key: 'sku', width: 12 },        // B: Item NO
        { key: 'desc', width: 40 },       // C: Description
        { key: 'hs', width: 15 },         // D: HS CODE
        { key: 'ctns', width: 8 },        // E: CTNS
        { key: 'pkg', width: 15 },        // F: Package (pcs/ctn)
        { key: 'qty', width: 10 },        // G: QTY (pcs)
        { key: 'unit', width: 6 },        // H: Unit
        { key: 'price', width: 12 },      // I: Unit Price (RMB)
        { key: 'amount', width: 15 },     // J: Amount (RMB)
        { key: 'gwCtn', width: 10 },      // K: G.W./ctn
        { key: 'totalGw', width: 12 },    // L: Total G.W.
        { key: 'cbmCtn', width: 10 },     // M: CBM/ctn
        { key: 'totalCbm', width: 12 },   // N: Total CBM
      ];

      // 2. Header Section (Seller Info)
      sheet.mergeCells('A1:N1');
      sheet.getCell('A1').value = invoiceConfig.sellerName; // Chinese/English name
      sheet.getCell('A1').font = { bold: true, size: 16 };
      sheet.getCell('A1').alignment = centerStyle;

      sheet.mergeCells('A2:N2');
      sheet.getCell('A2').value = invoiceConfig.sellerName; // English Name
      sheet.getCell('A2').font = { size: 12 };
      sheet.getCell('A2').alignment = centerStyle;

      sheet.mergeCells('A3:N3');
      sheet.getCell('A3').value = invoiceConfig.sellerAddress;
      sheet.getCell('A3').alignment = centerStyle;

      sheet.mergeCells('A4:N4');
      sheet.getCell('A4').value = `Telephone: ${invoiceConfig.sellerPhone}    E_mail address: ${invoiceConfig.sellerEmail}`;
      sheet.getCell('A4').alignment = centerStyle;

      // Title
      sheet.mergeCells('A6:N6');
      sheet.getCell('A6').value = "INVOICE";
      sheet.getCell('A6').font = { bold: true, size: 20 };
      sheet.getCell('A6').alignment = centerStyle;

      // Invoice Details (Left: Invoice No, Buyer; Right: Date, Sailing)
      // Row 8: Invoice No & Date
      sheet.mergeCells('A8:D8');
      sheet.getCell('A8').value = `Invoice No: ${invoiceConfig.invoiceNo}`;
      sheet.getCell('A8').font = { bold: true };
      sheet.mergeCells('H8:N8');
      sheet.getCell('H8').value = `Date: ${invoiceConfig.date}`;
      sheet.getCell('H8').font = { bold: true };

      // Row 9: Sailing
      sheet.mergeCells('H9:N9');
      sheet.getCell('H9').value = `Sailing: ${invoiceConfig.sailing}`;

      // Row 10-13: Buyer Info (Left Box)
      sheet.mergeCells('A10:D13');
      sheet.getCell('A10').value = `To:\n${invoiceConfig.buyerInfo}`;
      sheet.getCell('A10').alignment = { vertical: 'top', horizontal: 'left', wrapText: true };
      sheet.getCell('A10').border = borderStyle;

      // Row 14: Container & Seal
      sheet.mergeCells('A14:D14');
      sheet.getCell('A14').value = `Container No: ${invoiceConfig.containerNo}`;
      sheet.getCell('A14').font = { bold: true };
      sheet.getCell('A14').border = { bottom: { style: 'thin' } }; // Underline visual

      sheet.mergeCells('H14:N14');
      sheet.getCell('H14').value = `Seal No: ${invoiceConfig.sealNo}`;
      sheet.getCell('H14').font = { bold: true };
      sheet.getCell('H14').border = { bottom: { style: 'thin' } };

      // 3. Table Headers (Row 16)
      const headerRowIdx = 16;
      const headers = [
        'No.', 'Item NO', 'Description of Goods', 'HS CODE', 'CTNS', 'Package (pcs/ctn)', 
        'QTY (pcs)', 'Unit', 'Unit Price (RMB)', 'Amount (RMB)', 'G.W./ctn (kg)', 'Total G.W.', 
        'CBM/ctn', 'Total CBM'
      ];
      const headerRow = sheet.getRow(headerRowIdx);
      headerRow.values = headers;
      headerRow.font = { bold: true };
      headerRow.alignment = centerStyle;
      headerRow.eachCell((cell) => {
        cell.border = borderStyle;
        cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0E0E0' } };
      });

      // 4. Data Rows
      let currentRow = headerRowIdx + 1;
      let totalCtns = 0;
      let totalQty = 0;
      let totalAmount = 0;
      let totalGwSum = 0;
      let totalCbmSum = 0;

      for (let i = 0; i < products.length; i++) {
        const p = products[i];
        const metrics = calculateMetrics(p);

        const cartonQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
        const q = (cartonQty * p.pcsPerBox) || p.moq || 0;
        const amt = p.priceRmb * q;
        const tGw = (p.gwKg || 0) * cartonQty;
        const tCbm = (metrics.cbm || 0) * cartonQty;

        // Accumulate Totals
        totalCtns += cartonQty;
        totalQty += q;
        totalAmount += amt;
        totalGwSum += tGw;
        totalCbmSum += tCbm;

        const row = sheet.getRow(currentRow);
        row.values = [
          i + 1,
          p.sku,
          p.nameEn || p.nameCn,
          p.hsCode,
          cartonQty,
          p.pcsPerBox,
          q,
          'PCS',
          p.priceRmb,
          amt,
          p.gwKg || 0,
          Number(tGw.toFixed(2)),
          Number((metrics.cbm || 0).toFixed(3)),
          Number(tCbm.toFixed(3))
        ];

        // Alignment
        row.eachCell((cell, colNumber) => {
            cell.border = borderStyle;
            cell.alignment = colNumber === 3 ? leftStyle : centerStyle; // Description left align
        });

        currentRow++;
      }

      // 5. Total Row
      const totalRow = sheet.getRow(currentRow);
      totalRow.getCell(3).value = "TOTAL"; // Description column
      totalRow.getCell(3).font = { bold: true };
      totalRow.getCell(3).alignment = centerStyle;

      totalRow.getCell(5).value = totalCtns; // CTNS
      totalRow.getCell(7).value = totalQty; // QTY
      totalRow.getCell(10).value = totalAmount; // Amount
      totalRow.getCell(12).value = Number(totalGwSum.toFixed(2)); // Total GW
      totalRow.getCell(14).value = Number(totalCbmSum.toFixed(3)); // Total CBM

      // Style Total Row
      [3, 5, 7, 10, 12, 14].forEach(col => {
         const cell = totalRow.getCell(col);
         cell.font = { bold: true };
         cell.border = borderStyle;
      });

      // 6. Bank Details (Footer)
      currentRow += 2;
      sheet.getCell(`A${currentRow}`).value = "Bank Details:";
      sheet.getCell(`A${currentRow}`).font = { bold: true, size: 12 };

      const bankFields = [
        { label: "Beneficiary", val: invoiceConfig.bankBeneficiary },
        { label: "Bank Name", val: invoiceConfig.bankName },
        { label: "Bank Address", val: invoiceConfig.bankAddress },
        { label: "SWIFT", val: invoiceConfig.bankSwift },
        { label: "Account No.", val: invoiceConfig.bankAccount },
      ];

      currentRow++;
      bankFields.forEach(field => {
         sheet.mergeCells(`A${currentRow}:B${currentRow}`);
         sheet.getCell(`A${currentRow}`).value = field.label;
         sheet.getCell(`A${currentRow}`).font = { bold: true };
         sheet.getCell(`A${currentRow}`).border = borderStyle;

         sheet.mergeCells(`C${currentRow}:N${currentRow}`);
         sheet.getCell(`C${currentRow}`).value = field.val;
         sheet.getCell(`C${currentRow}`).border = borderStyle;
         currentRow++;
      });

      // Signature
      currentRow += 2;
      sheet.mergeCells(`A${currentRow}:F${currentRow}`);
      sheet.getCell(`A${currentRow}`).value = "For and on behalf of Seller (签字/盖章处)";
      sheet.getCell(`A${currentRow}`).font = { bold: true };
      sheet.getCell(`A${currentRow}`).border = { bottom: { style: 'thin' } };

    } else {
       // --- MASTER & PACKING LIST (Updated Image Logic) ---
       if (exportType === 'master') {
         // Same Master Columns as before...
         sheet.columns = [
          { header: 'Image', key: 'image', width: 25 }, // Increased width for better image viz
          { header: 'SKU', key: 'sku', width: 12, style: centerStyle },
          { header: 'Name (CN)', key: 'nameCn', width: 20, style: leftStyle },
          { header: 'Product Name (EN)', key: 'nameEn', width: 25, style: leftStyle },
          { header: 'Nombre Producto (ES)', key: 'nameEs', width: 25, style: leftStyle },
          { header: 'Category', key: 'catMain', width: 15, style: centerStyle },
          { header: 'Sub-Cat', key: 'catSub', width: 15, style: centerStyle },
          { header: 'Material', key: 'mat', width: 30, style: leftStyle }, 
          { header: 'HS Code', key: 'hs', width: 12, style: centerStyle },
          { header: 'L (cm)', key: 'l', width: 8, style: centerStyle },
          { header: 'W (cm)', key: 'w', width: 8, style: centerStyle },
          { header: 'H (cm)', key: 'h', width: 8, style: centerStyle },
          { header: 'Pcs/Box', key: 'pcs', width: 8, style: centerStyle },
          { header: 'CBM', key: 'cbm', width: 10, style: centerStyle },
          { header: 'G.W(kg)', key: 'gw', width: 8, style: centerStyle },
          { header: 'Cost (RMB)', key: 'rmb', width: 10, style: centerStyle },
          { header: 'Duty(%)', key: 'tax', width: 8, style: centerStyle },
          { header: 'Frt/Pc(€)', key: 'frt', width: 10, style: centerStyle },
          { header: 'Landed(€)', key: 'landed', width: 10, style: centerStyle },
          { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
        ];
       } else {
         // Packing List
         sheet.columns = [
          { header: 'Image', key: 'image', width: 25 },
          { header: 'No.', key: 'no', width: 6, style: centerStyle },
          { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
          { header: 'Description', key: 'desc', width: 35, style: leftStyle },
          { header: 'Qty (PCS)', key: 'qty', width: 10, style: centerStyle },
          { header: 'Cartons', key: 'cartons', width: 10, style: centerStyle },
          { header: 'CBM', key: 'totalCbm', width: 12, style: centerStyle },
          { header: 'G.W (KGS)', key: 'totalGw', width: 12, style: centerStyle },
        ];
       }

       // Header
       sheet.getRow(1).font = { bold: true, size: 11 };
       sheet.getRow(1).height = 30;

       // Rows
       for (let i = 0; i < products.length; i++) {
        const p = products[i];
        const metrics = calculateMetrics(p); 
        const rowIndex = i + 2;

        // ... (Data Mapping Logic Same as Before) ...
        const cartonQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
        const totalQty = (cartonQty * p.pcsPerBox) || p.moq || 0;
        const totalCbm = (metrics.cbm || 0) * cartonQty;
        const totalGw = (p.gwKg || 15) * cartonQty; 

        let rowValues = {};
        if (exportType === 'master') {
            rowValues = {
              sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, nameEs: p.nameEs,
              catMain: p.categoryMain, catSub: p.categorySub, mat: p.materialEn, hs: p.hsCode,
              l: p.boxLength, w: p.boxWidth, h: p.boxHeight, pcs: p.pcsPerBox, cbm: metrics.cbm,
              gw: p.gwKg || 0, rmb: p.priceRmb, tax: p.taxRate, frt: metrics.freightPerPc,
              landed: metrics.landedCostEuro, moq: p.moq
            };
        } else {
             rowValues = {
              no: i + 1, sku: p.sku, desc: p.nameEn || p.nameCn, qty: totalQty,
              cartons: cartonQty, totalCbm: totalCbm.toFixed(3), totalGw: totalGw.toFixed(2)
            };
        }

        const row = sheet.addRow(rowValues);
        // FIX: Increased Row Height for larger images
        row.height = 100; 
        row.alignment = centerStyle;

        // Image Embedding - Full Cell Fill
        if (p.photoUrl) {
          try {
            const base64 = p.photoUrl.split(',')[1];
            if (base64) {
              const imageId = workbook.addImage({ base64: base64, extension: 'jpeg' });
              sheet.addImage(imageId, {
                tl: { col: 0.05, row: rowIndex - 1 + 0.05 },
                br: { col: 0.95, row: rowIndex - 0.05 },
                editAs: 'oneCell' // This ensures it moves with cells but sizing depends on row height
              });
            }
          } catch (e) { console.warn(e); }
        }
       }
    }

    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_${exportType}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">

      {/* Invoice Configuration Modal */}
      {showInvoiceModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b flex justify-between items-center">
              <h2 className="text-xl font-bold flex items-center gap-2">
                <Settings size={20} /> Invoice Configuration
              </h2>
              <button onClick={() => setShowInvoiceModal(false)}><X /></button>
            </div>
            <div className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-xs font-bold text-gray-500 uppercase">Seller Name</label>
                  <input className="w-full border p-2 rounded" value={invoiceConfig.sellerName} onChange={e => setInvoiceConfig({...invoiceConfig, sellerName: e.target.value})} />
                </div>
                <div className="col-span-2">
                  <label className="text-xs font-bold text-gray-500 uppercase">Seller Address</label>
                  <input className="w-full border p-2 rounded" value={invoiceConfig.sellerAddress} onChange={e => setInvoiceConfig({...invoiceConfig, sellerAddress: e.target.value})} />
                </div>
                <div>
                   <label className="text-xs font-bold text-gray-500 uppercase">Seller Phone</label>
                   <input className="w-full border p-2 rounded" value={invoiceConfig.sellerPhone} onChange={e => setInvoiceConfig({...invoiceConfig, sellerPhone: e.target.value})} />
                </div>
                 <div>
                   <label className="text-xs font-bold text-gray-500 uppercase">Seller Email</label>
                   <input className="w-full border p-2 rounded" value={invoiceConfig.sellerEmail} onChange={e => setInvoiceConfig({...invoiceConfig, sellerEmail: e.target.value})} />
                </div>
              </div>

              <hr />

              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-xs font-bold text-gray-500 uppercase">Buyer Info (Multi-line)</label>
                  <textarea className="w-full border p-2 rounded h-24" value={invoiceConfig.buyerInfo} onChange={e => setInvoiceConfig({...invoiceConfig, buyerInfo: e.target.value})} />
                </div>
                <div>
                   <label className="text-xs font-bold text-gray-500 uppercase">Invoice No</label>
                   <input className="w-full border p-2 rounded" value={invoiceConfig.invoiceNo} onChange={e => setInvoiceConfig({...invoiceConfig, invoiceNo: e.target.value})} />
                </div>
                <div>
                   <label className="text-xs font-bold text-gray-500 uppercase">Date</label>
                   <input className="w-full border p-2 rounded" value={invoiceConfig.date} onChange={e => setInvoiceConfig({...invoiceConfig, date: e.target.value})} />
                </div>
                 <div>
                   <label className="text-xs font-bold text-gray-500 uppercase">Container No</label>
                   <input className="w-full border p-2 rounded" value={invoiceConfig.containerNo} onChange={e => setInvoiceConfig({...invoiceConfig, containerNo: e.target.value})} />
                </div>
              </div>
            </div>
            <div className="p-6 border-t bg-gray-50 flex justify-end gap-2">
               <button onClick={() => setShowInvoiceModal(false)} className="px-4 py-2 text-gray-600">Cancel</button>
               <button onClick={() => { setShowInvoiceModal(false); generateExcel('invoice'); }} className="px-4 py-2 bg-blue-600 text-white rounded shadow">
                 Save & Download Invoice
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Header & Actions */}
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-10 shadow-sm">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <Database className="text-blue-600" /> 
              Yiwu Product Master
            </h1>
            <p className="text-sm text-slate-500">
               {products.length} Products | {selectedIds.size} Selected
            </p>
          </div>

          <div className="flex gap-2">
             <button onClick={() => generateExcel('master')} className="btn-export bg-indigo-600">
               <Database size={16} /> Export Master
             </button>
             <button onClick={() => generateExcel('packinglist')} className="btn-export bg-green-600">
               <FileSpreadsheet size={16} /> Packing List
             </button>
             <button onClick={() => setShowInvoiceModal(true)} className="btn-export bg-blue-600">
               <Printer size={16} /> Invoice (Config)
             </button>
          </div>
        </div>

        {/* Action Bar (Bulk & Config) */}
        {selectedIds.size > 0 ? (
           <div className="bg-indigo-50 p-3 rounded-lg flex items-center justify-between border border-indigo-200 animate-in fade-in slide-in-from-top-2">
              <div className="flex items-center gap-2 text-indigo-800 font-bold">
                 <CheckSquare size={18} />
                 <span>{selectedIds.size} items selected</span>
              </div>
              <div className="flex gap-2">
                 <button 
                   onClick={handleBulkEnrich} 
                   disabled={isBulkProcessing}
                   className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded text-sm hover:bg-indigo-700"
                 >
                   {isBulkProcessing ? <RefreshCw className="animate-spin" size={14}/> : <Sparkles size={14}/>}
                   Bulk AI Enrich
                 </button>
                 <button 
                   onClick={handleBulkDelete}
                   className="flex items-center gap-2 px-3 py-1.5 bg-red-600 text-white rounded text-sm hover:bg-red-700"
                 >
                   <Trash2 size={14}/>
                   Delete
                 </button>
              </div>
           </div>
        ) : (
          <div className="bg-slate-100 p-3 rounded-lg flex flex-wrap gap-6 items-center text-sm border border-slate-200">
            <div className="flex items-center gap-2 text-slate-500 font-bold">
               <Settings size={14} /> Global Config:
            </div>
            <div className="flex items-center gap-1">
              <label>€/¥ Rate:</label>
              <input type="number" value={euroRmbRate} onChange={e => setEuroRmbRate(Number(e.target.value))} className="w-14 p-1 border rounded text-center"/>
            </div>
             <div className="flex items-center gap-1">
              <label>Frt ($/m³):</label>
              <input type="number" value={freightRateCbm} onChange={e => setFreightRateCbm(Number(e.target.value))} className="w-14 p-1 border rounded text-center"/>
            </div>
          </div>
        )}
      </header>

      {/* Main Data Grid */}
      <main className="flex-1 overflow-auto p-6">
        <div className="bg-white rounded-lg shadow border border-slate-200 overflow-x-auto">
          <table className="w-full text-left text-xs min-w-[1200px]">
            <thead className="bg-slate-100 text-slate-600 uppercase font-bold sticky top-0 z-0">
              <tr>
                <th className="p-3 w-10 text-center cursor-pointer" onClick={toggleSelectAll}>
                   {selectedIds.size > 0 && selectedIds.size === products.length ? <CheckSquare size={16}/> : <Square size={16}/>}
                </th>
                <th className="p-3 w-16">Img</th>
                <th className="p-3">Core Info</th>
                <th className="p-3">English / Spanish</th>
                <th className="p-3">Category</th>
                <th className="p-3">Specs (Box)</th>
                <th className="p-3 text-right">Cost (¥)</th>
                <th className="p-3 text-right">Landed (€)</th>
                <th className="p-3 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {products.map((p) => {
                const metrics = calculateMetrics(p); 
                const isProcessing = processingId === p.id;
                const isEditing = editingId === p.id;
                const isSelected = selectedIds.has(p.id);

                return (
                  <tr key={p.id} className={`hover:bg-slate-50 ${isEditing ? 'bg-indigo-50' : ''} ${isSelected ? 'bg-blue-50' : ''}`}>
                    {/* Checkbox */}
                    <td className="p-3 text-center cursor-pointer" onClick={() => toggleSelectRow(p.id)}>
                      {isSelected ? <CheckSquare size={16} className="text-blue-600"/> : <Square size={16} className="text-slate-300"/>}
                    </td>

                    <td className="p-3">
                      <img src={p.photoUrl} className="w-10 h-10 rounded border object-cover bg-white" />
                    </td>

                    {/* Core Info */}
                    <td className="p-3">
                      <div className="font-bold text-slate-800">{p.sku}</div>
                      {isEditing ? (
                        <input className="w-full p-1 border rounded text-xs mt-1" value={editForm.nameCn || ''} onChange={e => setEditForm({...editForm, nameCn: e.target.value})} placeholder="CN Name"/>
                      ) : (
                        <div className="text-slate-600">{p.nameCn}</div>
                      )}
                      <div className="text-xs text-gray-400">HS: {p.hsCode}</div>
                    </td>

                    {/* Translations */}
                    <td className="p-3 max-w-[200px]">
                      {isEditing ? (
                         <div className="space-y-1">
                           <input className="w-full p-1 border rounded text-xs" value={editForm.nameEn || ''} onChange={e => setEditForm({...editForm, nameEn: e.target.value})} placeholder="EN Name"/>
                           <input className="w-full p-1 border rounded text-xs" value={editForm.nameEs || ''} onChange={e => setEditForm({...editForm, nameEs: e.target.value})} placeholder="ES Name"/>
                         </div>
                      ) : (
                        <>
                           <div className="text-indigo-600 font-medium">{p.nameEn || "-"}</div>
                           <div className="text-emerald-600 italic">{p.nameEs || "-"}</div>
                        </>
                      )}
                    </td>

                    {/* Category */}
                    <td className="p-3">
                       {isEditing ? (
                         <div className="space-y-1">
                           <input className="w-full p-1 border rounded text-xs" value={editForm.categoryMain || ''} onChange={e => setEditForm({...editForm, categoryMain: e.target.value})} placeholder="Main Cat"/>
                           <input className="w-full p-1 border rounded text-xs" value={editForm.categorySub || ''} onChange={e => setEditForm({...editForm, categorySub: e.target.value})} placeholder="Sub Cat"/>
                         </div>
                       ) : (
                         <div className="space-y-1">
                            <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] block w-fit">{p.categoryMain || "N/A"}</span>
                            <span className="text-gray-400 text-[10px] block pl-1">&rarr; {p.categorySub || "N/A"}</span>
                         </div>
                       )}
                    </td>

                    {/* Specs */}
                    <td className="p-3">
                      {isEditing ? (
                         <div className="flex gap-1">
                            <input className="w-8 p-1 border rounded" placeholder="L" type="number" value={editForm.boxLength} onChange={e => setEditForm({...editForm, boxLength: Number(e.target.value)})} />
                            <input className="w-8 p-1 border rounded" placeholder="W" type="number" value={editForm.boxWidth} onChange={e => setEditForm({...editForm, boxWidth: Number(e.target.value)})} />
                            <input className="w-8 p-1 border rounded" placeholder="H" type="number" value={editForm.boxHeight} onChange={e => setEditForm({...editForm, boxHeight: Number(e.target.value)})} />
                         </div>
                      ) : (
                        <div>{p.boxLength}x{p.boxWidth}x{p.boxHeight} cm</div>
                      )}

                      <div className="text-slate-500 mt-1 flex items-center gap-2">
                        {isEditing ? (
                           <input className="w-12 p-1 border rounded" placeholder="Pcs" type="number" value={editForm.pcsPerBox} onChange={e => setEditForm({...editForm, pcsPerBox: Number(e.target.value)})} />
                        ) : (
                           <span>{p.pcsPerBox} pcs/ctn</span>
                        )}
                        <span className="font-mono text-xs text-gray-400">| {metrics.cbm.toFixed(3)} m³</span>
                      </div>
                    </td>

                    {/* Cost RMB */}
                    <td className="p-3 text-right font-medium text-slate-700">
                      {isEditing ? (
                        <input className="w-16 p-1 border rounded text-right" type="number" value={editForm.priceRmb} onChange={e => setEditForm({...editForm, priceRmb: Number(e.target.value)})} />
                      ) : (
                        `¥${p.priceRmb}`
                      )}
                    </td>

                    {/* Landed Euro */}
                    <td className="p-3 text-right">
                      <div className="font-bold text-green-600">€{metrics.landedCostEuro.toFixed(2)}</div>
                      <div className="text-slate-400 text-[10px]">Duty: {p.taxRate}%</div>
                    </td>

                    {/* Actions */}
                    <td className="p-3 text-center">
                      <div className="flex flex-col gap-2 items-center">
                        {isEditing ? (
                          <>
                            <button onClick={saveEdit} className="p-1.5 bg-green-100 text-green-700 rounded hover:bg-green-200" title="Save">
                              <SaveIcon size={14} />
                            </button>
                            <button onClick={cancelEdit} className="p-1.5 bg-red-100 text-red-700 rounded hover:bg-red-200" title="Cancel">
                              <X size={14} />
                            </button>
                          </>
                        ) : (
                          <>
                             <button onClick={() => handleEnrichment(p)} disabled={isProcessing} className="p-1.5 bg-indigo-50 text-indigo-600 rounded hover:bg-indigo-100 transition-colors" title="Auto-Fill with AI">
                                {isProcessing ? <RefreshCw size={14} className="animate-spin" /> : <Sparkles size={14} />}
                              </button>
                              <button onClick={() => startEditing(p)} className="p-1.5 bg-gray-50 text-gray-600 rounded hover:bg-gray-100 transition-colors" title="Edit Manually">
                                <Edit size={14} />
                              </button>
                          </>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </main>

      <style>{`
        .btn-export {
          @apply flex items-center gap-2 px-3 py-2 text-white rounded-md text-xs font-medium hover:opacity-90 transition-opacity shadow-sm;
        }
      `}</style>
    </div>
  );
};

