import React, { useState, useEffect } from 'react';
import MobileEntry from './components/MobileEntry';
import Dashboard from './components/Dashboard';
import { Product } from './types';
import { Smartphone, Monitor } from 'lucide-react';

export default function App() {
  const [viewMode, setViewMode] = useState<'mobile' | 'desktop'>('mobile');
  const [products, setProducts] = useState<Product[]>([]);

  // Load from local storage on mount (Simulation of DB)
  useEffect(() => {
    const saved = localStorage.getItem('yiwu_products');
    if (saved) {
      setProducts(JSON.parse(saved));
    }
  }, []);

  // Save to local storage whenever products change
  useEffect(() => {
    localStorage.setItem('yiwu_products', JSON.stringify(products));
  }, [products]);

  const handleAddProduct = (newProduct: Product) => {
    setProducts(prev => [newProduct, ...prev]);
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleDeleteProducts = (ids: string[]) => {
    setProducts(prev => prev.filter(p => !ids.includes(p.id)));
  };

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden font-sans text-slate-900">

      {/* Dev Switcher - For Demo Purposes */}
      <div className="bg-slate-900 text-white p-2 flex justify-center items-center gap-4 text-xs z-50">
        <span className="opacity-50 uppercase tracking-widest font-bold">Role Switcher:</span>
        <button 
          onClick={() => setViewMode('mobile')}
          className={`flex items-center gap-2 px-3 py-1 rounded-full transition-colors ${viewMode === 'mobile' ? 'bg-blue-600' : 'hover:bg-slate-700'}`}
        >
          <Smartphone size={14} /> Sourcing Agent (Mobile)
        </button>
        <button 
          onClick={() => setViewMode('desktop')}
          className={`flex items-center gap-2 px-3 py-1 rounded-full transition-colors ${viewMode === 'desktop' ? 'bg-indigo-600' : 'hover:bg-slate-700'}`}
        >
          <Monitor size={14} /> Office Admin (PC)
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden bg-slate-200 relative">

        {viewMode === 'mobile' ? (
          <div className="h-full w-full max-w-md mx-auto bg-white shadow-2xl overflow-hidden relative border-x border-gray-300">
             <MobileEntry onSave={handleAddProduct} />
          </div>
        ) : (
          <div className="h-full w-full bg-white">
            <Dashboard 
              products={products} 
              onUpdateProduct={handleUpdateProduct} 
              onDeleteProduct={handleDeleteProducts}
            />
          </div>
        )}

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText, Settings, Database, Edit, Save as SaveIcon, X, Trash2, CheckSquare, Square, Printer } from 'lucide-react';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void; // New prop for batch delete
}

// Default Invoice Configuration
const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832",
  bankBeneficiary: "YiWu Edas Import and Export Co., Ltd",
  bankName: "TED BANK, Yiwu Branch",
  bankAddress: "TED Address, Yiwu, China",
  bankSwift: "TEDXXXX",
  bankAccount: "TED-ACCOUNT-NUMBER",
};

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct, onDeleteProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Product>>({});

  // Batch Actions State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);

  // Invoice Config Modal State
  const [showInvoiceModal, setShowInvoiceModal] = useState(false);
  const [invoiceConfig, setInvoiceConfig] = useState(DEFAULT_INVOICE_CONFIG);

  // Global Settings for Calculation
  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150);
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2); 
  const [vatRate, setVatRate] = useState<number>(21);

  // --- Metrics Calculation ---
  const calculateMetrics = (p: Product, overrides?: { euroRate?: number, freight?: number, vat?: number }) => {
    const rate = overrides?.euroRate || euroRmbRate;
    const freight = overrides?.freight || freightRateCbm;
    const vat = overrides?.vat || vatRate;
    const usdRate = usdRmbRate;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const gwLb = (p.gwKg || 0) * 2.2046;

    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) 
      ? (freight * cbm) / p.pcsPerBox 
      : 0;

    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;
    const dutyCost = baseCostEuro * ((p.taxRate || 0) / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      gwLb: Number(gwLb.toFixed(2)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
      exRateEuroRmb: rate,
      freightRate: freight,
      vatRate: vat
    };
  };

  // --- Selection Handlers ---
  const toggleSelectAll = () => {
    if (selectedIds.size === products.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(products.map(p => p.id)));
    }
  };

  const toggleSelectRow = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedIds(newSet);
  };

  // --- Bulk Actions ---
  const handleBulkDelete = () => {
    if (confirm(`Are you sure you want to delete ${selectedIds.size} items?`)) {
      // In a real app we would call onDeleteProduct passed from props
      // Since we didn't add it to props in previous steps, let's just simulate or assume props updated
      // For now, we will manually filter local products if prop exists, else alert
      if (onDeleteProduct) {
        onDeleteProduct(Array.from(selectedIds));
        setSelectedIds(new Set());
      } else {
        alert("Delete function needs to be passed from parent.");
      }
    }
  };

  const handleBulkEnrich = async () => {
    setIsBulkProcessing(true);
    const itemsToProcess = products.filter(p => selectedIds.has(p.id));

    // Process sequentially to avoid rate limits, or Promise.all if API allows
    for (const product of itemsToProcess) {
       try {
         const result = await enrichProductData(product.nameCn);
         const metrics = calculateMetrics({ ...product, ...result });
         onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
       } catch (e) {
         console.error(`Failed to enrich ${product.id}`, e);
       }
    }
    setIsBulkProcessing(false);
    setSelectedIds(new Set());
    alert("Batch Processing Completed!");
  };

  // --- Single Item Actions ---
  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) return alert("API Key missing");
    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });
    try {
      const result = await enrichProductData(product.nameCn);
      const metrics = calculateMetrics({ ...product, ...result });
      onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
    } catch (error) {
      alert("AI Enrichment failed.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const startEditing = (product: Product) => {
    setEditingId(product.id);
    setEditForm({ ...product });
  };
  const saveEdit = () => {
    if (!editingId) return;
    const product = products.find(p => p.id === editingId);
    if (product) {
        const merged = { ...product, ...editForm };
        const metrics = calculateMetrics(merged);
        onUpdateProduct({ ...merged, ...metrics });
    }
    setEditingId(null);
    setEditForm({});
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  // --- EXCEL GENERATION ---
  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice') => {
    if (products.length === 0) return alert("No products to export.");

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet(exportType === 'invoice' ? 'INVOICE' : 'Sheet1');

    // Helper Styles
    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };
    const borderStyle = {
      top: { style: 'thin' },
      left: { style: 'thin' },
      bottom: { style: 'thin' },
      right: { style: 'thin' }
    };

    if (exportType === 'invoice') {
      // --- CUSTOM INVOICE FORMAT ---

      // 1. Setup Columns (A-N based on screenshot)
      sheet.columns = [
        { key: 'no', width: 5 },          // A: No.
        { key: 'sku', width: 12 },        // B: Item NO
        { key: 'desc', width: 40 },       // C: Description
        { key: 'hs', width: 15 },         // D: HS CODE
        { key: 'ctns', width: 8 },        // E: CTNS
        { key: 'pkg', width: 15 },        // F: Package (pcs/ctn)
        { key: 'qty', width: 10 },        // G: QTY (pcs)
        { key: 'unit', width: 6 },        // H: Unit
        { key: 'price', width: 12 },      // I: Unit Price (RMB)
        { key: 'amount', width: 15 },     // J: Amount (RMB)
        { key: 'gwCtn', width: 10 },      // K: G.W./ctn
        { key: 'totalGw', width: 12 },    // L: Total G.W.
        { key: 'cbmCtn', width: 10 },     // M: CBM/ctn
        { key: 'totalCbm', width: 12 },   // N: Total CBM
      ];

      // 2. Header Section (Seller Info)
      sheet.mergeCells('A1:N1');
      sheet.getCell('A1').value = invoiceConfig.sellerName; // Chinese/English name
      sheet.getCell('A1').font = { bold: true, size: 16 };
      sheet.getCell('A1').alignment = centerStyle;

      sheet.mergeCells('A2:N2');
      sheet.getCell('A2').value = invoiceConfig.sellerName; // English Name
      sheet.getCell('A2').font = { size: 12 };
      sheet.getCell('A2').alignment = centerStyle;

      sheet.mergeCells('A3:N3');
      sheet.getCell('A3').value = invoiceConfig.sellerAddress;
      sheet.getCell('A3').alignment = centerStyle;

      sheet.mergeCells('A4:N4');
      sheet.getCell('A4').value = `Telephone: ${invoiceConfig.sellerPhone}    E_mail address: ${invoiceConfig.sellerEmail}`;
      sheet.getCell('A4').alignment = centerStyle;

      // Title
      sheet.mergeCells('A6:N6');
      sheet.getCell('A6').value = "INVOICE";
      sheet.getCell('A6').font = { bold: true, size: 20 };
      sheet.getCell('A6').alignment = centerStyle;

      // Invoice Details (Left: Invoice No, Buyer; Right: Date, Sailing)
      // Row 8: Invoice No & Date
      sheet.mergeCells('A8:D8');
      sheet.getCell('A8').value = `Invoice No: ${invoiceConfig.invoiceNo}`;
      sheet.getCell('A8').font = { bold: true };
      sheet.mergeCells('H8:N8');
      sheet.getCell('H8').value = `Date: ${invoiceConfig.date}`;
      sheet.getCell('H8').font = { bold: true };

      // Row 9: Sailing
      sheet.mergeCells('H9:N9');
      sheet.getCell('H9').value = `Sailing: ${invoiceConfig.sailing}`;

      // Row 10-13: Buyer Info (Left Box)
      sheet.mergeCells('A10:D13');
      sheet.getCell('A10').value = `To:\n${invoiceConfig.buyerInfo}`;
      sheet.getCell('A10').alignment = { vertical: 'top', horizontal: 'left', wrapText: true };
      sheet.getCell('A10').border = borderStyle;

      // Row 14: Container & Seal
      sheet.mergeCells('A14:D14');
      sheet.getCell('A14').value = `Container No: ${invoiceConfig.containerNo}`;
      sheet.getCell('A14').font = { bold: true };
      sheet.getCell('A14').border = { bottom: { style: 'thin' } }; // Underline visual

      sheet.mergeCells('H14:N14');
      sheet.getCell('H14').value = `Seal No: ${invoiceConfig.sealNo}`;
      sheet.getCell('H14').font = { bold: true };
      sheet.getCell('H14').border = { bottom: { style: 'thin' } };

      // 3. Table Headers (Row 16)
      const headerRowIdx = 16;
      const headers = [
        'No.', 'Item NO', 'Description of Goods', 'HS CODE', 'CTNS', 'Package (pcs/ctn)', 
        'QTY (pcs)', 'Unit', 'Unit Price (RMB)', 'Amount (RMB)', 'G.W./ctn (kg)', 'Total G.W.', 
        'CBM/ctn', 'Total CBM'
      ];
      const headerRow = sheet.getRow(headerRowIdx);
      headerRow.values = headers;
      headerRow.font = { bold: true };
      headerRow.alignment = centerStyle;
      headerRow.eachCell((cell) => {
        cell.border = borderStyle;
        cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0E0E0' } };
      });

      // 4. Data Rows
      let currentRow = headerRowIdx + 1;
      let totalCtns = 0;
      let totalQty = 0;
      let totalAmount = 0;
      let totalGwSum = 0;
      let totalCbmSum = 0;

      for (let i = 0; i < products.length; i++) {
        const p = products[i];
        const metrics = calculateMetrics(p);

        const cartonQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
        const q = (cartonQty * p.pcsPerBox) || p.moq || 0;
        const amt = p.priceRmb * q;
        const tGw = (p.gwKg || 0) * cartonQty;
        const tCbm = (metrics.cbm || 0) * cartonQty;

        // Accumulate Totals
        totalCtns += cartonQty;
        totalQty += q;
        totalAmount += amt;
        totalGwSum += tGw;
        totalCbmSum += tCbm;

        const row = sheet.getRow(currentRow);
        row.values = [
          i + 1,
          p.sku,
          p.nameEn || p.nameCn,
          p.hsCode,
          cartonQty,
          p.pcsPerBox,
          q,
          'PCS',
          p.priceRmb,
          amt,
          p.gwKg || 0,
          Number(tGw.toFixed(2)),
          Number((metrics.cbm || 0).toFixed(3)),
          Number(tCbm.toFixed(3))
        ];

        // Alignment
        row.eachCell((cell, colNumber) => {
            cell.border = borderStyle;
            cell.alignment = colNumber === 3 ? leftStyle : centerStyle; // Description left align
        });

        currentRow++;
      }

      // 5. Total Row
      const totalRow = sheet.getRow(currentRow);
      totalRow.getCell(3).value = "TOTAL"; // Description column
      totalRow.getCell(3).font = { bold: true };
      totalRow.getCell(3).alignment = centerStyle;

      totalRow.getCell(5).value = totalCtns; // CTNS
      totalRow.getCell(7).value = totalQty; // QTY
      totalRow.getCell(10).value = totalAmount; // Amount
      totalRow.getCell(12).value = Number(totalGwSum.toFixed(2)); // Total GW
      totalRow.getCell(14).value = Number(totalCbmSum.toFixed(3)); // Total CBM

      // Style Total Row
      [3, 5, 7, 10, 12, 14].forEach(col => {
         const cell = totalRow.getCell(col);
         cell.font = { bold: true };
         cell.border = borderStyle;
      });

      // 6. Bank Details (Footer)
      currentRow += 2;
      sheet.getCell(`A${currentRow}`).value = "Bank Details:";
      sheet.getCell(`A${currentRow}`).font = { bold: true, size: 12 };

      const bankFields = [
        { label: "Beneficiary", val: invoiceConfig.bankBeneficiary },
        { label: "Bank Name", val: invoiceConfig.bankName },
        { label: "Bank Address", val: invoiceConfig.bankAddress },
        { label: "SWIFT", val: invoiceConfig.bankSwift },
        { label: "Account No.", val: invoiceConfig.bankAccount },
      ];

      currentRow++;
      bankFields.forEach(field => {
         sheet.mergeCells(`A${currentRow}:B${currentRow}`);
         sheet.getCell(`A${currentRow}`).value = field.label;
         sheet.getCell(`A${currentRow}`).font = { bold: true };
         sheet.getCell(`A${currentRow}`).border = borderStyle;

