          { header: 'Duty(%)', key: 'tax', width: 8, style: centerStyle },
          { header: 'Frt/Pc(€)', key: 'frt', width: 10, style: centerStyle },
          { header: 'Landed(€)', key: 'landed', width: 10, style: centerStyle },
          { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
        ];
       } else {
         // Packing List
         sheet.columns = [
          { header: 'Image', key: 'image', width: 25 },
          { header: 'No.', key: 'no', width: 6, style: centerStyle },
          { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
