                                <Edit size={14} />
                              </button>
                          </>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </main>

      <style>{`
        .btn-export {
          @apply flex items-center gap-2 px-3 py-2 text-white rounded-md text-xs font-medium hover:opacity-90 transition-opacity shadow-sm;
        }
      `}</style>
    </div>
  );
};

