import React, { useState, useEffect } from 'react';
import { Product, ProcessingStatus } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, AlertCircle, CheckCircle2, FileSpreadsheet, FileText, Settings, Database, Edit, Save as SaveIcon, X, Trash2, CheckSquare, Square, Printer } from 'lucide-react';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
}

// Default Invoice Configuration
const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832",
  bankBeneficiary: "YiWu Edas Import and Export Co., Ltd",
  bankName: "TED BANK, Yiwu Branch",
  bankAddress: "TED Address, Yiwu, China",
  bankSwift: "TEDXXXX",
  bankAccount: "TED-ACCOUNT-NUMBER",
};

const Dashboard: React.FC<DashboardProps> = ({ products, onUpdateProduct, onDeleteProduct }) => {
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Product>>({});

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);

  const [showInvoiceModal, setShowInvoiceModal] = useState(false);
  const [invoiceConfig, setInvoiceConfig] = useState(DEFAULT_INVOICE_CONFIG);

  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150);
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2); 
  const [vatRate, setVatRate] = useState<number>(21);

  const calculateMetrics = (p: Product, overrides?: { euroRate?: number, freight?: number, vat?: number }) => {
    const rate = overrides?.euroRate || euroRmbRate;
    const freight = overrides?.freight || freightRateCbm;
    const vat = overrides?.vat || vatRate;
    const usdRate = usdRmbRate;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const gwLb = (p.gwKg || 0) * 2.2046;

    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) 
      ? (freight * cbm) / p.pcsPerBox 
      : 0;

    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;
    const dutyCost = baseCostEuro * ((p.taxRate || 0) / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      gwLb: Number(gwLb.toFixed(2)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
      exRateEuroRmb: rate,
      freightRate: freight,
      vatRate: vat
    };
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === products.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(products.map(p => p.id)));
    }
  };

  const toggleSelectRow = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedIds(newSet);
  };

  const handleBulkDelete = () => {
    if (confirm(`Are you sure you want to delete ${selectedIds.size} items?`)) {
      if (onDeleteProduct) {
        onDeleteProduct(Array.from(selectedIds));
        setSelectedIds(new Set());
      } else {
        alert("Delete function needs to be passed from parent.");
      }
    }
  };

  const handleBulkEnrich = async () => {
    setIsBulkProcessing(true);
    const itemsToProcess = products.filter(p => selectedIds.has(p.id));

    for (const product of itemsToProcess) {
       try {
         const result = await enrichProductData(product.nameCn);
         const metrics = calculateMetrics({ ...product, ...result });
         onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
       } catch (e) {
         console.error(`Failed to enrich ${product.id}`, e);
       }
    }
    setIsBulkProcessing(false);
    setSelectedIds(new Set());
    alert("Batch Processing Completed!");
  };

  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) return alert("API Key missing");
    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });
    try {
      const result = await enrichProductData(product.nameCn);
      const metrics = calculateMetrics({ ...product, ...result });
      onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
    } catch (error) {
      alert("AI Enrichment failed.");
      onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally {
      setProcessingId(null);
    }
  };

  const startEditing = (product: Product) => {
    setEditingId(product.id);
    setEditForm({ ...product });
  };
  const saveEdit = () => {
    if (!editingId) return;
    const product = products.find(p => p.id === editingId);
    if (product) {
        const merged = { ...product, ...editForm };
        const metrics = calculateMetrics(merged);
        onUpdateProduct({ ...merged, ...metrics });
    }
    setEditingId(null);
    setEditForm({});
  };
  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice') => {
    if (products.length === 0) return alert("No products to export.");

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet(exportType === 'invoice' ? 'INVOICE' : 'Sheet1');

    // Basic Styling Helpers
    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };
    const borderStyle = {
      top: { style: 'thin' },
      left: { style: 'thin' },
      bottom: { style: 'thin' },
      right: { style: 'thin' }
    };

    if (exportType === 'invoice') {
      // (Keep existing Invoice Logic, it's specific to the template)
      sheet.columns = [
        { key: 'no', width: 5 }, { key: 'sku', width: 12 }, { key: 'desc', width: 40 },
        { key: 'hs', width: 15 }, { key: 'ctns', width: 8 }, { key: 'pkg', width: 15 },
        { key: 'qty', width: 10 }, { key: 'unit', width: 6 }, { key: 'price', width: 12 },
        { key: 'amount', width: 15 }, { key: 'gwCtn', width: 10 }, { key: 'totalGw', width: 12 },
        { key: 'cbmCtn', width: 10 }, { key: 'totalCbm', width: 12 },
      ];

      // Headers (Seller Info)
      sheet.mergeCells('A1:N1'); sheet.getCell('A1').value = invoiceConfig.sellerName;
      sheet.getCell('A1').font = { bold: true, size: 16 }; sheet.getCell('A1').alignment = centerStyle;

      sheet.mergeCells('A2:N2'); sheet.getCell('A2').value = invoiceConfig.sellerName;
      sheet.getCell('A2').alignment = centerStyle;

      sheet.mergeCells('A3:N3'); sheet.getCell('A3').value = invoiceConfig.sellerAddress;
      sheet.getCell('A3').alignment = centerStyle;

      sheet.mergeCells('A4:N4'); sheet.getCell('A4').value = `Tel: ${invoiceConfig.sellerPhone}  Email: ${invoiceConfig.sellerEmail}`;
      sheet.getCell('A4').alignment = centerStyle;

      sheet.mergeCells('A6:N6'); sheet.getCell('A6').value = "INVOICE";
      sheet.getCell('A6').font = { bold: true, size: 20 }; sheet.getCell('A6').alignment = centerStyle;

      // Meta Info
      sheet.mergeCells('A8:D8'); sheet.getCell('A8').value = `Invoice No: ${invoiceConfig.invoiceNo}`; sheet.getCell('A8').font = { bold: true };
      sheet.mergeCells('H8:N8'); sheet.getCell('H8').value = `Date: ${invoiceConfig.date}`; sheet.getCell('H8').font = { bold: true };

      sheet.mergeCells('H9:N9'); sheet.getCell('H9').value = `Sailing: ${invoiceConfig.sailing}`;

      sheet.mergeCells('A10:D13'); sheet.getCell('A10').value = `To:\n${invoiceConfig.buyerInfo}`;
      sheet.getCell('A10').alignment = { vertical: 'top', horizontal: 'left', wrapText: true };
      sheet.getCell('A10').border = borderStyle;

      sheet.mergeCells('A14:D14'); sheet.getCell('A14').value = `Container: ${invoiceConfig.containerNo}`; sheet.getCell('A14').font = { bold: true };
      sheet.getCell('A14').border = { bottom: { style: 'thin' } };
      sheet.mergeCells('H14:N14'); sheet.getCell('H14').value = `Seal: ${invoiceConfig.sealNo}`; sheet.getCell('H14').font = { bold: true };
      sheet.getCell('H14').border = { bottom: { style: 'thin' } };

      const headerRowIdx = 16;
      const headerRow = sheet.getRow(headerRowIdx);
      headerRow.values = ['No.', 'Item NO', 'Description', 'HS CODE', 'CTNS', 'Pkg', 'QTY', 'Unit', 'Price(¥)', 'Amount(¥)', 'GW/ctn', 'Total GW', 'CBM/ctn', 'Total CBM'];
      headerRow.font = { bold: true }; headerRow.alignment = centerStyle;
      headerRow.eachCell(cell => { cell.border = borderStyle; cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0E0E0' } }; });

      let currentRow = headerRowIdx + 1;
      let tCtns = 0, tQty = 0, tAmt = 0, tGw = 0, tCbm = 0;

      products.forEach((p, i) => {
        const m = calculateMetrics(p);
        const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
        const q = (cQty * p.pcsPerBox) || p.moq || 0;
        const amt = p.priceRmb * q;
        const gw = (p.gwKg || 0) * cQty;
        const cbm = (m.cbm || 0) * cQty;

        tCtns += cQty; tQty += q; tAmt += amt; tGw += gw; tCbm += cbm;

        const row = sheet.getRow(currentRow);
        row.values = [i+1, p.sku, p.nameEn||p.nameCn, p.hsCode, cQty, p.pcsPerBox, q, 'PCS', p.priceRmb, amt, p.gwKg||0, gw.toFixed(2), (m.cbm||0).toFixed(3), cbm.toFixed(3)];
        row.eachCell((c, col) => { c.border = borderStyle; c.alignment = col===3 ? leftStyle : centerStyle; });
        currentRow++;
      });

      const totalRow = sheet.getRow(currentRow);
      totalRow.getCell(3).value = "TOTAL"; totalRow.getCell(3).font = { bold: true, size: 12 }; totalRow.getCell(3).alignment = centerStyle;
      totalRow.getCell(5).value = tCtns;
      totalRow.getCell(7).value = tQty;
      totalRow.getCell(10).value = tAmt;
      totalRow.getCell(12).value = Number(tGw.toFixed(2));
      totalRow.getCell(14).value = Number(tCbm.toFixed(3));
      [3,5,7,10,12,14].forEach(c => { totalRow.getCell(c).font={bold:true}; totalRow.getCell(c).border=borderStyle; });

    } else {
      // --- MASTER & PACKING LIST FIX ---

      if (exportType === 'master') {
         sheet.columns = [
          { header: 'Image', key: 'image', width: 22 }, // Approx 160px wide
          { header: 'SKU', key: 'sku', width: 12, style: centerStyle },
          { header: 'Name (CN)', key: 'nameCn', width: 20, style: leftStyle },
          { header: 'Product Name (EN)', key: 'nameEn', width: 25, style: leftStyle },
          { header: 'Nombre Producto (ES)', key: 'nameEs', width: 25, style: leftStyle },
          { header: 'Category', key: 'catMain', width: 15, style: centerStyle },
          { header: 'Sub-Cat', key: 'catSub', width: 15, style: centerStyle },
          { header: 'Material', key: 'mat', width: 25, style: leftStyle }, 
          { header: 'HS Code', key: 'hs', width: 12, style: centerStyle },
          { header: 'L', key: 'l', width: 8, style: centerStyle },
          { header: 'W', key: 'w', width: 8, style: centerStyle },
          { header: 'H', key: 'h', width: 8, style: centerStyle },
          { header: 'Pcs/Box', key: 'pcs', width: 8, style: centerStyle },
          { header: 'CBM', key: 'cbm', width: 10, style: centerStyle },
          { header: 'G.W', key: 'gw', width: 8, style: centerStyle },
          { header: 'Cost (RMB)', key: 'rmb', width: 12, style: centerStyle },
          { header: 'Duty(%)', key: 'tax', width: 8, style: centerStyle },
          { header: 'Frt(€)', key: 'frt', width: 10, style: centerStyle },
          { header: 'Landed(€)', key: 'landed', width: 10, style: centerStyle },
          { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
        ];
      } else {
         sheet.columns = [
          { header: 'Image', key: 'image', width: 22 },
          { header: 'No.', key: 'no', width: 6, style: centerStyle },
          { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
          { header: 'Description', key: 'desc', width: 35, style: leftStyle },
          { header: 'Qty', key: 'qty', width: 10, style: centerStyle },
          { header: 'Cartons', key: 'cartons', width: 10, style: centerStyle },
          { header: 'CBM', key: 'totalCbm', width: 12, style: centerStyle },
          { header: 'G.W', key: 'totalGw', width: 12, style: centerStyle },
        ];
      }

      sheet.getRow(1).font = { bold: true, size: 11 };
      sheet.getRow(1).height = 30;
      sheet.getRow(1).alignment = centerStyle;

      for (let i = 0; i < products.length; i++) {
        const p = products[i];
        const m = calculateMetrics(p); 
        const rowIndex = i + 2;

        const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
        const tQty = (cQty * p.pcsPerBox) || p.moq || 0;
        const tCbm = (m.cbm || 0) * cQty;
        const tGw = (p.gwKg || 15) * cQty; 

        let rowValues = {};
        if (exportType === 'master') {
          rowValues = {
            sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, nameEs: p.nameEs,
            catMain: p.categoryMain, catSub: p.categorySub, mat: p.materialEn, hs: p.hsCode,
            l: p.boxLength || 0, w: p.boxWidth || 0, h: p.boxHeight || 0, // Ensure not undefined
            pcs: p.pcsPerBox, cbm: m.cbm, gw: p.gwKg || 0,
            rmb: p.priceRmb, tax: p.taxRate, frt: m.freightPerPc, landed: m.landedCostEuro, moq: p.moq
          };
        } else {
          rowValues = {
            no: i + 1, sku: p.sku, desc: p.nameEn || p.nameCn, qty: tQty,
            cartons: cQty, totalCbm: tCbm.toFixed(3), totalGw: tGw.toFixed(2)
          };
        }

        const row = sheet.addRow(rowValues);
        // CRITICAL FIX: Set explicit row height for image container
        row.height = 110; 
        row.alignment = centerStyle;

        // Add Borders
        row.eachCell((cell) => { cell.border = borderStyle; });

        if (p.photoUrl) {
          try {
            const base64 = p.photoUrl.split(',')[1];
            if (base64) {
              const imageId = workbook.addImage({ base64: base64, extension: 'jpeg' });

              // Anchor image to column 0 (A), filling the cell with padding
              sheet.addImage(imageId, {
                tl: { col: 0.05, row: rowIndex - 1 + 0.05 }, // Start slightly inside top-left
                br: { col: 0.95, row: rowIndex - 0.05 },     // End slightly inside bottom-right
                editAs: 'oneCell' // Ensures image scales with cell
              });
            }
          } catch (e) { console.warn("Img Error", e); }
        }
      }
    }

    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_${exportType}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
