import React, { useState, useEffect } from 'react';
import MobileEntry from './components/MobileEntry';
import Dashboard from './components/Dashboard';
import { Product } from './types';
import { Smartphone, Monitor, LayoutGrid, UserCircle2 } from 'lucide-react';

export default function App() {
  const [viewMode, setViewMode] = useState<'mobile' | 'desktop'>('mobile');
  const [products, setProducts] = useState<Product[]>([]);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('yiwu_products');
    if (saved) {
      setProducts(JSON.parse(saved));
    }
  }, []);

  // Save to local storage whenever products change
  useEffect(() => {
    localStorage.setItem('yiwu_products', JSON.stringify(products));
  }, [products]);

  const handleAddProduct = (newProduct: Product) => {
    setProducts(prev => [newProduct, ...prev]);
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleDeleteProducts = (ids: string[]) => {
    setProducts(prev => prev.filter(p => !ids.includes(p.id)));
  };

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden text-slate-900 bg-slate-100">

      {/* Premium Floating Role Switcher */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-1 p-1 bg-white/90 backdrop-blur border border-slate-200 shadow-lg rounded-full">
        <button 
          onClick={() => setViewMode('mobile')}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-semibold transition-all duration-300 ${
            viewMode === 'mobile' 
              ? 'bg-indigo-600 text-white shadow-md' 
              : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
          }`}
        >
          <Smartphone size={14} /> Mobile
        </button>
        <button 
          onClick={() => setViewMode('desktop')}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-semibold transition-all duration-300 ${
            viewMode === 'desktop' 
              ? 'bg-indigo-600 text-white shadow-md' 
              : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
          }`}
        >
          <Monitor size={14} /> Desktop
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative">

        {viewMode === 'mobile' ? (
          <div className="h-full w-full flex justify-center bg-slate-200/50 backdrop-blur-sm pt-0 sm:pt-8 pb-0 sm:pb-8">
            {/* Mobile Device Frame Simulation on Desktop screens */}
            <div className="h-full w-full sm:max-w-[400px] bg-white sm:rounded-[2.5rem] shadow-2xl overflow-hidden relative border-[8px] border-slate-900/5 ring-1 ring-black/5">
               <MobileEntry onSave={handleAddProduct} />
            </div>
          </div>
        ) : (
          <div className="h-full w-full bg-slate-50 flex flex-col">
            <Dashboard 
              products={products} 
              onUpdateProduct={handleUpdateProduct} 
              onDeleteProduct={handleDeleteProducts}
            />
          </div>
        )}

      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign } from 'lucide-react';
import { Product, ProcessingStatus } from '../types';
import { analyzeImage } from '../services/geminiService';

interface MobileEntryProps {
  onSave: (product: Product) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPhotoPreview(ev.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setIsBatchProcessing(true);
      const files = Array.from(e.target.files);

      try {
        const promises = files.map(async (file) => {
          return new Promise<void>((resolve) => {
            const reader = new FileReader();
            reader.onload = async (ev) => {
              const base64 = ev.target?.result as string;
              let aiData;
              try {
                aiData = await analyzeImage(base64);
              } catch (err) {
                 aiData = { 
                   nameCn: "Unknown Item", priceRmb: 0, moq: 0, nameEn: "Unknown", materialEn: "",
                   boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0
                 };
              }

              const newProduct: Product = {
                id: Date.now().toString() + Math.random(),
                sku: `YW-${Math.floor(Math.random() * 10000)}`,
                photoUrl: base64,
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn, 
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || "TBD",
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
              };
              onSave(newProduct);
              resolve();
            };
            reader.readAsDataURL(file);
          });
        });

        await Promise.all(promises);
        alert(`Successfully scanned ${files.length} images!`);
        setActiveTab('list');
      } catch (error) {
        console.error(error);
        alert("Batch processing had some errors.");
      } finally {
        setIsBatchProcessing(false);
      }
    }
  };

  const handleSimulateOCR = () => {
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0;
    const w = parts[1] || 0;
    const h = parts[2] || 0;

    const newProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      nameCn,
      priceRmb: Number(priceRmb) || 0,
