import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

// Safe access to environment variables
const getApiKey = () => {
  try {
    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      return process.env.API_KEY;
    }
  } catch (e) {
    // Ignore ReferenceError if process is not defined
  }
  return undefined;
};

const getClient = () => {
  const apiKey = getApiKey();
  if (!apiKey) {
    // For local dev or environments where process.env is not polyfilled
    console.warn("API Key missing. Check process.env.API_KEY");
    throw new Error("API Key configuration missing. Please check settings.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to safely parse JSON from AI response, stripping Markdown code blocks if present
const safeJsonParse = (text: string | undefined) => {
  if (!text) throw new Error("No response from AI");
  try {
    // Remove ```json and ``` wrapping if they exist
    const cleanText = text.replace(/```json\n?|```/g, '').trim();
    // Handle cases where AI returns plain text instead of JSON
    if (!cleanText.startsWith('{') && !cleanText.startsWith('[')) {
       throw new Error("Response is not JSON");
    }
    return JSON.parse(cleanText);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    console.error("Raw Text:", text);
    throw new Error("Failed to parse AI response as JSON");
  }
};

// Text-based enrichment: Now acts as a Customs Expert & Translator
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  try {
    const ai = getClient();
    const prompt = `
      You are a Senior Customs Broker and Sourcing Agent.
      Product Chinese Name: "${nameCn}".

      Task:
      1. Translate to professional English Trade Name.
      2. Translate to Spanish Product Name (Nombre de Producto).
      3. Categorize (Main Category usually material or use, Sub Category specific item).
      4. Identify Material Composition.
      5. Assign HS Code (China export).
      6. Estimate EU Import Duty Rate (%).

      Output JSON.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "English Name" },
            nameEs: { type: Type.STRING, description: "Spanish Name" },
            categoryMain: { type: Type.STRING, description: "Main Category (e.g. Kitchenware)" },
            categorySub: { type: Type.STRING, description: "Sub Category (e.g. Pots)" },
            materialEn: { type: Type.STRING, description: "Material Composition" },
            hsCode: { type: Type.STRING, description: "HS Code" },
            usage: { type: Type.STRING, description: "Usage" },
            taxRate: { type: Type.NUMBER, description: "EU Duty Rate (%)" }
          },
          required: ["nameEn", "nameEs", "categoryMain", "categorySub", "materialEn", "hsCode", "taxRate"]
        }
      }
    });

    return safeJsonParse(response.text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

export interface ImageAnalysisResult {
  nameCn: string;
  priceRmb: number;
  moq: number;
  nameEn: string;
  materialEn: string;
  boxLength: number;
  boxWidth: number;
  boxHeight: number;
  pcsPerBox: number;
}

// Image-based analysis: Enhanced for Tag/Label Reading (OCR)
export const analyzeImage = async (base64Image: string): Promise<ImageAnalysisResult> => {
  try {
    const ai = getClient();
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: `
            You are a Data Entry Clerk at Yiwu Market. Your job is to extract data from the PHOTO of the product and its TAG/LABEL.

            1. **FIND THE TAG**: Look for a white handwritten or printed card.
            2. **EXTRACT DATA**:
               - **Name**: Read Chinese name.
               - **Price**: Look for '¥', 'RMB', 'Price', '单价'.
               - **Packing (Pcs/Ctn)**: Look for 'Qty', '装箱数', 'Pcs/Ctn', 'PCS'.
               - **Dimensions (Meas)**: Look for 'Meas', 'Size', '规格', 'CBM'. Format is usually Length*Width*Height (e.g., 60*50*40). Extract these numbers accurately.

            3. **ESTIMATE (Only if tag is missing)**: 
               - Guess Material and English Name.
               - If Price/MOQ/Dimensions are strictly NOT visible, return 0. Do not hallucinate numbers.

            Output JSON format.
            ` 
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameCn: { type: Type.STRING, description: "Product Name (CN)" },
            priceRmb: { type: Type.NUMBER, description: "Price (RMB)" },
            moq: { type: Type.NUMBER, description: "MOQ" },
            nameEn: { type: Type.STRING, description: "English Name" },
            materialEn: { type: Type.STRING, description: "Material" },
            boxLength: { type: Type.NUMBER, description: "Box Length (cm)" },
            boxWidth: { type: Type.NUMBER, description: "Box Width (cm)" },
            boxHeight: { type: Type.NUMBER, description: "Box Height (cm)" },
            pcsPerBox: { type: Type.NUMBER, description: "Items per carton (Qty)" },
          },
          required: ["nameCn", "priceRmb", "moq", "nameEn", "materialEn", "boxLength", "boxWidth", "boxHeight", "pcsPerBox"]
        }
      }
    });

    return safeJsonParse(response.text) as ImageAnalysisResult;
  } catch (error) {
    console.error("Image Analysis failed:", error);
    // Return a safe default object so the app doesn't crash
    return {
      nameCn: "待识别商品",
      priceRmb: 0,
      moq: 0,
      nameEn: "Pending Analysis",
      materialEn: "",
      boxLength: 0,
      boxWidth: 0,
      boxHeight: 0,
      pcsPerBox: 0
    };
  }
};

import React, { useState } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign } from 'lucide-react';
import { Product, ProcessingStatus } from '../types';
import { analyzeImage } from '../services/geminiService';

interface MobileEntryProps {
  onSave: (product: Product) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPhotoPreview(ev.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // Helper to read file as base64 promise
  const readFileAsBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        // Process Sequentially to avoid crashing the browser or hitting API limits
        for (let i = 0; i < files.length; i++) {
          setProcessingCount({ current: i + 1, total: files.length });

          // Yield to UI thread to prevent freeze/white screen
          await new Promise(resolve => setTimeout(resolve, 50));

          const file = files[i];

          try {
            const base64 = await readFileAsBase64(file);
            let aiData;
            try {
              aiData = await analyzeImage(base64);
            } catch (err) {
              console.warn("AI Analysis error for file " + i, err);
              aiData = { 
                nameCn: "Scan Failed", priceRmb: 0, moq: 0, nameEn: "Error", materialEn: "",
                boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0
              };
            }

            const newProduct: Product = {
              id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9), // Unique ID
              sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
              photoUrl: base64,
              nameCn: aiData.nameCn || "Unknown",
              nameEn: aiData.nameEn, 
              materialEn: aiData.materialEn,
              priceRmb: aiData.priceRmb || 0,
              moq: aiData.moq || 0,
              shopNo: shopNo || "TBD",
              boxLength: aiData.boxLength || 0,
              boxWidth: aiData.boxWidth || 0,
              boxHeight: aiData.boxHeight || 0,
              pcsPerBox: aiData.pcsPerBox || 0,
              status: ProcessingStatus.DRAFT,
              timestamp: Date.now()
            };

            onSave(newProduct);
          } catch (fileError) {
            console.error("Error reading file:", fileError);
          }
        }

        // Small delay before switching tab to let user see 100% completion
        await new Promise(resolve => setTimeout(resolve, 300));
        setActiveTab('list');
      } catch (error) {
        console.error("Batch processing critical error:", error);
        alert("Batch processing stopped due to an error.");
      } finally {
        setIsBatchProcessing(false);
        // Reset file input value so same files can be selected again if needed
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => {
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0;
    const w = parts[1] || 0;
    const h = parts[2] || 0;

    const newProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l,
      boxWidth: w,
      boxHeight: h,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    onSave(newProduct);
    setNameCn(''); setPriceRmb(''); setMoq(''); setShopNo(''); setBoxDims(''); setPcsPerBox(''); setPhotoPreview(null);
    alert("Saved!");
  };

  if (activeTab === 'list') {
    return (
      <div className="flex flex-col h-full bg-slate-50">
        <div className="px-6 py-5 bg-white shadow-sm z-10">
          <h2 className="text-xl font-bold text-slate-800 tracking-tight">Recent Scans</h2>
          <p className="text-sm text-slate-500 mt-1">Review items in Desktop Dashboard</p>
        </div>
        <div className="flex-1 p-6 flex flex-col items-center justify-center text-slate-400">
           <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4 shadow-inner">
             <Box size={32} className="text-slate-300" />
           </div>
           <p className="font-medium">Items saved locally.</p>
           <p className="text-xs mt-1 text-center max-w-[200px]">Switch to Desktop view to organize and export your data.</p>
        </div>
        <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-8 flex justify-between items-center z-20">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-slate-400 hover:text-indigo-600 transition-colors">
            <Plus size={24} />
            <span className="text-[10px] font-medium tracking-wide">NEW</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-indigo-600">
            <Layers size={24} />
            <span className="text-[10px] font-medium tracking-wide">LIST</span>
          </button>
        </nav>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-slate-50 relative font-sans">
      {isBatchProcessing && (
        <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center text-indigo-600">
