import { Product } from '../types';

const DB_NAME = 'YiwuSourcingDB';
const STORE_NAME = 'products';
const DB_VERSION = 1;

// Open or create the database
const getDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => {
      console.error("Database error:", request.error);
      reject(request.error);
    };

    request.onsuccess = () => {
      resolve(request.result);
    };

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };
  });
};

export const dbService = {
  // Get all products
  getAll: async (): Promise<Product[]> => {
    const db = await getDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();

      request.onsuccess = () => resolve(request.result || []);
      request.onerror = () => reject(request.error);
    });
  },

  // Add or Update a product (put handles both)
  save: async (product: Product): Promise<void> => {
    const db = await getDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.put(product);

      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  // Delete a product by ID
  delete: async (id: string): Promise<void> => {
    const db = await getDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.delete(id);

      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  // Bulk delete
  deleteMany: async (ids: string[]): Promise<void> => {
    const db = await getDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);

      let completed = 0;
      let errors = false;

      if (ids.length === 0) return resolve();

      ids.forEach(id => {
        const req = store.delete(id);
        req.onsuccess = () => {
          completed++;
          if (completed === ids.length) resolve();
        };
        req.onerror = () => {
          errors = true;
          console.error(`Failed to delete ${id}`);
        };
      });

      transaction.oncomplete = () => resolve();
      transaction.onerror = () => reject(transaction.error);
    });
  }
};

import React, { useState, useEffect } from 'react';
import MobileEntry from './components/MobileEntry';
import Dashboard from './components/Dashboard';
import { Product } from './types';
import { Smartphone, Monitor, LayoutGrid, UserCircle2 } from 'lucide-react';
import { dbService } from './services/db';

export default function App() {
  const [viewMode, setViewMode] = useState<'mobile' | 'desktop'>('mobile');
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Load from IndexedDB on mount
  useEffect(() => {
    const loadData = async () => {
      try {
        const storedProducts = await dbService.getAll();
        // Sort by newest first
        setProducts(storedProducts.sort((a, b) => b.timestamp - a.timestamp));
      } catch (error) {
        console.error("Failed to load products from DB:", error);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  // Handlers now update both Local State (for UI) and IndexedDB (for storage)

  const handleAddProduct = async (newProduct: Product) => {
    // Optimistic UI update
    setProducts(prev => [newProduct, ...prev]);
    // Persist to DB
    try {
      await dbService.save(newProduct);
    } catch (error) {
      console.error("Failed to save product:", error);
      alert("Error saving data. Please check storage space.");
    }
  };

  const handleUpdateProduct = async (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
    try {
      await dbService.save(updatedProduct);
    } catch (error) {
      console.error("Failed to update product:", error);
    }
  };

  const handleDeleteProducts = async (ids: string[]) => {
    setProducts(prev => prev.filter(p => !ids.includes(p.id)));
    try {
      await dbService.deleteMany(ids);
    } catch (error) {
      console.error("Failed to delete products:", error);
    }
  };

  if (isLoading) {
    return (
       <div className="h-screen w-screen flex items-center justify-center bg-slate-50">
          <div className="animate-pulse flex flex-col items-center">
             <div className="w-12 h-12 bg-indigo-100 rounded-full mb-3"></div>
             <div className="h-4 w-32 bg-slate-200 rounded"></div>
          </div>
       </div>
    );
  }

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden text-slate-900 bg-slate-100">

      {/* Premium Floating Role Switcher */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-1 p-1 bg-white/90 backdrop-blur border border-slate-200 shadow-lg rounded-full">
        <button 
          onClick={() => setViewMode('mobile')}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-semibold transition-all duration-300 ${
            viewMode === 'mobile' 
              ? 'bg-indigo-600 text-white shadow-md' 
              : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
          }`}
        >
          <Smartphone size={14} /> Mobile
        </button>
        <button 
          onClick={() => setViewMode('desktop')}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-semibold transition-all duration-300 ${
            viewMode === 'desktop' 
              ? 'bg-indigo-600 text-white shadow-md' 
              : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
          }`}
        >
          <Monitor size={14} /> Desktop
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative">

        {viewMode === 'mobile' ? (
          <div className="h-full w-full flex justify-center bg-slate-200/50 backdrop-blur-sm pt-0 sm:pt-8 pb-0 sm:pb-8">
            {/* Mobile Device Frame Simulation on Desktop screens */}
            <div className="h-full w-full sm:max-w-[400px] bg-white sm:rounded-[2.5rem] shadow-2xl overflow-hidden relative border-[8px] border-slate-900/5 ring-1 ring-black/5">
               <MobileEntry onSave={handleAddProduct} />
            </div>
