import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

// Safe access to environment variables
const getApiKey = () => {
  try {
    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      return process.env.API_KEY;
    }
  } catch (e) {
    // Ignore ReferenceError if process is not defined
  }
  return undefined;
};

const getClient = () => {
  const apiKey = getApiKey();
  if (!apiKey) {
    // For local dev or environments where process.env is not polyfilled
    console.warn("API Key missing. Check process.env.API_KEY");
    throw new Error("API Key configuration missing. Please check settings.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to safely parse JSON from AI response, stripping Markdown code blocks if present
const safeJsonParse = (text: string | undefined) => {
  if (!text) throw new Error("No response from AI");
  try {
    // Remove ```json and ``` wrapping if they exist
    const cleanText = text.replace(/```json\n?|```/g, '').trim();
    // Handle cases where AI returns plain text instead of JSON
    if (!cleanText.startsWith('{') && !cleanText.startsWith('[')) {
       throw new Error("Response is not JSON");
    }
    return JSON.parse(cleanText);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    console.error("Raw Text:", text);
    throw new Error("Failed to parse AI response as JSON");
  }
};

// Text-based enrichment: Now acts as a Customs Expert & Translator
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  try {
    const ai = getClient();
    const prompt = `
      You are a Senior Customs Broker and Sourcing Agent.
      Product Chinese Name: "${nameCn}".

      Task:
      1. Translate to professional English Trade Name.
      2. Translate to Spanish Product Name (Nombre de Producto).
      3. Categorize (Main Category usually material or use, Sub Category specific item).
      4. Identify Material Composition.
      5. Assign HS Code (China export).
      6. Estimate EU Import Duty Rate (%).

      Output JSON.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "English Name" },
            nameEs: { type: Type.STRING, description: "Spanish Name" },
            categoryMain: { type: Type.STRING, description: "Main Category (e.g. Kitchenware)" },
            categorySub: { type: Type.STRING, description: "Sub Category (e.g. Pots)" },
            materialEn: { type: Type.STRING, description: "Material Composition" },
            hsCode: { type: Type.STRING, description: "HS Code" },
            usage: { type: Type.STRING, description: "Usage" },
            taxRate: { type: Type.NUMBER, description: "EU Duty Rate (%)" }
          },
          required: ["nameEn", "nameEs", "categoryMain", "categorySub", "materialEn", "hsCode", "taxRate"]
        }
      }
    });

    return safeJsonParse(response.text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

export interface ImageAnalysisResult {
  nameCn: string;
  priceRmb: number;
  moq: number;
  nameEn: string;
  materialEn: string;
  boxLength: number;
  boxWidth: number;
  boxHeight: number;
  pcsPerBox: number;
}

// Image-based analysis: Enhanced for Tag/Label Reading (OCR) AND Visual Estimation
export const analyzeImage = async (base64Image: string): Promise<ImageAnalysisResult> => {
  try {
    const ai = getClient();
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: `
            ROLE: Experienced Yiwu Market Agent.
            TASK: Extract product data.

            CRITICAL RULES:
            1. **NEVER RETURN 0** for dimensions, packing, or price.
            2. If tag is readable -> Extract exact data.
            3. If tag is MISSING/BLURRY -> **GUESS/ESTIMATE** based on the object type. 
               - See a cup? Guess 50x40x30cm box, 48pcs/ctn, Price ¥5.
               - See a toy? Guess 60x50x50cm box, 120pcs/ctn, Price ¥3.
            4. ACCURACY of "Name" is important. ACCURACY of "Numbers" is secondary (filling the spreadsheet is the priority).

            OUTPUT REQUIREMENTS:
            - nameCn: Chinese Name (e.g. "不锈钢保温杯").
            - nameEn: English Name.
            - materialEn: Material (e.g. "Stainless Steel").
            - priceRmb: Wholesale price estimate (e.g. 2.50 to 50.00).
            - moq: Minimum Order Qty (usually 1-5 cartons).
            - boxLength/Width/Height: Export carton size (cm).
            - pcsPerBox: Items per carton (e.g. 24, 48, 96, 120).
            ` 
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameCn: { type: Type.STRING, description: "Product Name (CN)" },
            priceRmb: { type: Type.NUMBER, description: "Price (RMB) > 0" },
            moq: { type: Type.NUMBER, description: "MOQ" },
            nameEn: { type: Type.STRING, description: "English Name" },
            materialEn: { type: Type.STRING, description: "Material" },
            boxLength: { type: Type.NUMBER, description: "Box Length (cm) > 0" },
            boxWidth: { type: Type.NUMBER, description: "Box Width (cm) > 0" },
            boxHeight: { type: Type.NUMBER, description: "Box Height (cm) > 0" },
            pcsPerBox: { type: Type.NUMBER, description: "Items per carton (Qty) > 0" },
          },
          required: ["nameCn", "priceRmb", "moq", "nameEn", "materialEn", "boxLength", "boxWidth", "boxHeight", "pcsPerBox"]
        }
      }
    });

    const result = safeJsonParse(response.text) as ImageAnalysisResult;

    // --- FALLBACK LAYER: Ensure no Zeros ---
    // If AI still returned 0 despite instructions, fill with "Safe Yiwu Defaults"
    if (!result.priceRmb || result.priceRmb === 0) result.priceRmb = 5.50;
    if (!result.moq || result.moq === 0) result.moq = 120;
    if (!result.boxLength || result.boxLength === 0) result.boxLength = 50;
    if (!result.boxWidth || result.boxWidth === 0) result.boxWidth = 40;
    if (!result.boxHeight || result.boxHeight === 0) result.boxHeight = 30;
    if (!result.pcsPerBox || result.pcsPerBox === 0) result.pcsPerBox = 60;
    if (!result.nameCn || result.nameCn === "Unknown") result.nameCn = "义乌百货商品 (待核实)";

    return result;

  } catch (error) {
    console.error("Image Analysis failed:", error);
    // Return a populated default object instead of empty zeros
    return {
      nameCn: "待识别商品 (Auto-Fill)",
      priceRmb: 10.00,
      moq: 60,
      nameEn: "Unidentified Item",
      materialEn: "General",
      boxLength: 50,
      boxWidth: 40,
      boxHeight: 40,
      pcsPerBox: 60
    };
  }
};

import React, { useState } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap } from 'lucide-react';
