interface MobileEntryProps {
  onSave: (product: Product) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  // Quick calculate metrics so data is "hot" when hitting the dashboard
  const calculateInitialMetrics = (p: Partial<Product>) => {
    // Default assumptions for instant calculation
    const rate = 7.8; // Euro Rate
    const freight = 150; // $150/CBM
    const vat = 21; // 21%
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
    };
  };

  // Helper to read file and COMPRESS it (Optimized for Speed)
  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);

      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;

        img.onload = () => {
          // Resize Logic: Reduced to 800px for faster batch AI processing
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;

          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;

          const ctx = canvas.getContext('2d');
          if (!ctx) {
            resolve(event.target?.result as string); // Fallback to original
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          // Compress to JPEG with 0.6 quality (Faster upload, sufficient for AI)
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
          resolve(dataUrl);
        };

        img.onerror = (err) => reject(err);
      };

      reader.onerror = (err) => reject(err);
    });
  };

  const handlePhotoSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const compressedBase64 = await processImageFile(file);
        setPhotoPreview(compressedBase64);
      } catch (e) {
        console.error("Image processing error", e);
      }
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        // --- HIGH PERFORMANCE PARALLEL PROCESSING ---
        // Concurrency increased to 12 for bulk operations
        const CONCURRENCY_LIMIT = 12;
        let processedCount = 0;

        // Task function for a single file
        const processFileItem = async (file: File) => {
           try {
             const base64 = await processImageFile(file);

             let aiData;
             try {
                aiData = await analyzeImage(base64);
             } catch (err: any) {
                console.warn("AI Analysis error", err);
                // Fallback is handled in geminiService now, but just in case:
                aiData = { 
                  nameCn: "Processing Error", priceRmb: 5, moq: 60, nameEn: "Review Needed", materialEn: "Unknown",
                  boxLength: 50, boxWidth: 40, boxHeight: 30, pcsPerBox: 60
                };
             }

             const partialProduct: Product = {
                id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9),
                sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
                photoUrl: base64,
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn,
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || "TBD",
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
             };

             // Calculate metrics immediately so they appear in Dashboard/Excel
             const metrics = calculateInitialMetrics(partialProduct);

             onSave({ ...partialProduct, ...metrics });

           } catch (e) {
             console.error("File processing critical error", e);
           } finally {
             processedCount++;
             setProcessingCount(prev => ({ ...prev, current: processedCount }));
           }
        };

        // Create a worker queue
        const queue = [...files];
        const workers = Array(Math.min(CONCURRENCY_LIMIT, files.length))
          .fill(null)
          .map(async () => {
            while (queue.length > 0) {
              const file = queue.shift();
              if (file) await processFileItem(file);
            }
          });

        // Wait for all workers to finish
        await Promise.all(workers);

        // Success transition
        await new Promise(resolve => setTimeout(resolve, 500));
        setActiveTab('list');

      } catch (error) {
        console.error("Batch processing critical error:", error);
        alert("Batch processing stopped due to an error.");
      } finally {
        setIsBatchProcessing(false);
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => {
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0;
    const w = parts[1] || 0;
    const h = parts[2] || 0;

    const partialProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l,
      boxWidth: w,
      boxHeight: h,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    const metrics = calculateInitialMetrics(partialProduct);
    onSave({ ...partialProduct, ...metrics });

    setNameCn(''); setPriceRmb(''); setMoq(''); setShopNo(''); setBoxDims(''); setPcsPerBox(''); setPhotoPreview(null);
    alert("Saved!");
  };

  if (activeTab === 'list') {
    return (
      <div className="flex flex-col h-full bg-slate-50">
        <div className="px-6 py-5 bg-white shadow-sm z-10">
          <h2 className="text-xl font-bold text-slate-800 tracking-tight">Recent Scans</h2>
          <p className="text-sm text-slate-500 mt-1">Review items in Desktop Dashboard</p>
        </div>
        <div className="flex-1 p-6 flex flex-col items-center justify-center text-slate-400">
           <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4 shadow-inner">
             <Box size={32} className="text-slate-300" />
           </div>
           <p className="font-medium">Items saved locally.</p>
           <p className="text-xs mt-1 text-center max-w-[200px]">Switch to Desktop view to organize and export your data.</p>
        </div>
        <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-8 flex justify-between items-center z-20">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-slate-400 hover:text-indigo-600 transition-colors">
            <Plus size={24} />
            <span className="text-[10px] font-medium tracking-wide">NEW</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-indigo-600">
            <Layers size={24} />
            <span className="text-[10px] font-medium tracking-wide">LIST</span>
          </button>
        </nav>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-slate-50 relative font-sans">
      {isBatchProcessing && (
        <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center text-indigo-600">
           <div className="relative">
             <div className="absolute inset-0 bg-indigo-200 blur-xl opacity-50 rounded-full animate-pulse"></div>
             <Loader2 className="animate-spin mb-4 relative z-10" size={48} />
           </div>
           <p className="font-bold text-lg text-slate-800">Processing {processingCount.current} / {processingCount.total}</p>
           <p className="text-sm text-indigo-600 font-medium mt-2 flex items-center gap-1">
              <Zap size={14} fill="currentColor"/> Hyper-Batch Active
           </p>
           <p className="text-xs text-slate-400 mt-1">Max Concurrency Enabled</p>
        </div>
      )}

      {/* Header */}
      <div className="bg-white px-6 pt-6 pb-4 shadow-sm border-b border-slate-100 z-10">
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">New Sourcing</h1>
            <div className="flex items-center gap-1 text-xs font-medium text-indigo-600 mt-0.5">
               <Store size={12} />
               <span>Yiwu District 4</span>
            </div>
          </div>
          <div className="h-8 w-8 rounded-full bg-indigo-50 flex items-center justify-center border border-indigo-100">
             <Tag size={16} className="text-indigo-600"/>
