import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

// Safe access to environment variables
const getApiKey = () => {
  try {
    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      return process.env.API_KEY;
    }
  } catch (e) {
    // Ignore ReferenceError if process is not defined
  }
  return undefined;
};

const getClient = () => {
  const apiKey = getApiKey();
  if (!apiKey) {
    // For local dev or environments where process.env is not polyfilled
    console.warn("API Key missing. Check process.env.API_KEY");
    throw new Error("API Key configuration missing. Please check settings.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to safely parse JSON from AI response, stripping Markdown code blocks if present
const safeJsonParse = (text: string | undefined) => {
  if (!text) throw new Error("No response from AI");
  try {
    // Remove ```json and ``` wrapping if they exist
    const cleanText = text.replace(/```json\n?|```/g, '').trim();
    // Handle cases where AI returns plain text instead of JSON
    if (!cleanText.startsWith('{') && !cleanText.startsWith('[')) {
       throw new Error("Response is not JSON");
    }
    return JSON.parse(cleanText);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    console.error("Raw Text:", text);
    throw new Error("Failed to parse AI response as JSON");
  }
};

// Text-based enrichment: Now acts as a Customs Expert & Translator
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  try {
    const ai = getClient();
    const prompt = `
      You are a Senior Customs Broker and Sourcing Agent.
      Product Chinese Name: "${nameCn}".

      Task:
      1. Translate to professional English Trade Name.
      2. Translate to Spanish Product Name (Nombre de Producto).
      3. Categorize (Main Category usually material or use, Sub Category specific item).
      4. Identify Material Composition.
      5. Assign HS Code (China export).
      6. Estimate EU Import Duty Rate (%).

      Output JSON.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "English Name" },
            nameEs: { type: Type.STRING, description: "Spanish Name" },
            categoryMain: { type: Type.STRING, description: "Main Category (e.g. Kitchenware)" },
            categorySub: { type: Type.STRING, description: "Sub Category (e.g. Pots)" },
            materialEn: { type: Type.STRING, description: "Material Composition" },
            hsCode: { type: Type.STRING, description: "HS Code" },
            usage: { type: Type.STRING, description: "Usage" },
            taxRate: { type: Type.NUMBER, description: "EU Duty Rate (%)" }
          },
          required: ["nameEn", "nameEs", "categoryMain", "categorySub", "materialEn", "hsCode", "taxRate"]
        }
      }
    });

    return safeJsonParse(response.text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

export interface ImageAnalysisResult {
  nameCn: string;
  priceRmb: number;
  moq: number;
  nameEn: string;
  materialEn: string;
  boxLength: number;
  boxWidth: number;
  boxHeight: number;
  pcsPerBox: number;
}

// Image-based analysis: Enabled Google Search for Grounding
export const analyzeImage = async (base64Image: string): Promise<ImageAnalysisResult> => {
  try {
    const ai = getClient();
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    // Using gemini-3-pro-image-preview to enable Google Search Tools + Vision
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-image-preview", 
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: `
            ROLE: Expert Sourcing Agent with access to Google Search.
            TASK: Identify this product and find its STANDARD PACKING DATA and MARKET PRICE.

            INSTRUCTIONS:
            1. **IDENTIFY**: Look at the image. Identify the product name (Chinese/English).
            2. **SEARCH**: Use Google Search to find this exact item or a very similar "Yiwu Market" commodity online (e.g. Alibaba, 1688, Amazon specs).
            3. **EXTRACT REAL DATA**:
               - **Dimensions**: Find the "Carton Size" / "Meas" (Length/Width/Height in cm).
               - **Packing**: Find "Qty/Ctn" or "Pcs/Box".
               - **Price**: Find a typical wholesale EXW Yiwu price (RMB).
            4. **ACCURACY RULE**: 
               - Do NOT make up random numbers (like 50x40x30) unless that is the ACTUAL standard size for this item found online.
               - If the exact brand is not found, use the specs of the *most similar* standard product available in the market.
               - If search fails, leave as 0.

            OUTPUT JSON:
            - nameCn: Product Name in Chinese.
            - nameEn: Product Name in English.
            - materialEn: Material.
            - priceRmb: Found Wholesale Price (RMB).
            - moq: Standard MOQ (e.g. 1 carton qty).
            - boxLength/Width/Height: Carton Dimensions (cm).
            - pcsPerBox: Items per carton.
            ` 
          }
        ]
      },
      config: {
        tools: [{ googleSearch: {} }], // Enable Search Grounding
        // Note: responseMimeType: "application/json" is NOT supported with Search tool in some versions,
        // but we will try to parse the text response which usually adheres to the structure requested.
      }
    });

    // When using Tools, response.text might contain the search log, but the model usually answers in the requested format at the end.
    // We need to be robust in parsing.
    let jsonText = response.text || "";

    // Extract JSON block if wrapped in markdown
    const jsonMatch = jsonText.match(/```json\n([\s\S]*?)\n```/) || jsonText.match(/```\n([\s\S]*?)\n```/);
    if (jsonMatch) {
      jsonText = jsonMatch[1];
    } else {
      // Fallback: Try to find the first '{' and last '}'
      const firstBrace = jsonText.indexOf('{');
      const lastBrace = jsonText.lastIndexOf('}');
      if (firstBrace !== -1 && lastBrace !== -1) {
        jsonText = jsonText.substring(firstBrace, lastBrace + 1);
      }
    }

    const result = JSON.parse(jsonText) as ImageAnalysisResult;

    // Sanity check: Ensure we return numbers, not strings for dimensions
    return {
      nameCn: result.nameCn || "待识别商品",
      nameEn: result.nameEn || "Unknown Product",
      materialEn: result.materialEn || "General",
      priceRmb: Number(result.priceRmb) || 0,
      moq: Number(result.moq) || 0,
      boxLength: Number(result.boxLength) || 0,
      boxWidth: Number(result.boxWidth) || 0,
      boxHeight: Number(result.boxHeight) || 0,
      pcsPerBox: Number(result.pcsPerBox) || 0
    };

  } catch (error) {
    console.error("Image Analysis failed:", error);
    // Return empty safe object, allowing user to fill manually rather than wrong data
    return {
      nameCn: "识别失败 (Manual Entry)",
      priceRmb: 0,
      moq: 0,
      nameEn: "",
      materialEn: "",
      boxLength: 0,
      boxWidth: 0,
      boxHeight: 0,
      pcsPerBox: 0
    };
  }
};

import React, { useState, useEffect } from 'react';
import MobileEntry from './components/MobileEntry';
import Dashboard from './components/Dashboard';
import { Product } from './types';
import { dbService } from './services/db';

export default function App() {
  const [isMobile, setIsMobile] = useState(false);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Load from IndexedDB on mount & Detect Screen Size
  useEffect(() => {
    // 1. Device Detection
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 768);
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);

    // 2. Load Data
    const loadData = async () => {
      try {
        const storedProducts = await dbService.getAll();
        // Sort by newest first
        setProducts(storedProducts.sort((a, b) => b.timestamp - a.timestamp));
      } catch (error) {
        console.error("Failed to load products from DB:", error);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();

    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleAddProduct = async (newProduct: Product) => {
    // Optimistic UI update
    setProducts(prev => [newProduct, ...prev]);
    // Persist to DB
    try {
      await dbService.save(newProduct);
    } catch (error) {
      console.error("Failed to save product:", error);
      alert("Error saving data. Please check storage space.");
    }
  };

  const handleUpdateProduct = async (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
    try {
      await dbService.save(updatedProduct);
    } catch (error) {
      console.error("Failed to update product:", error);
    }
  };

  const handleDeleteProducts = async (ids: string[]) => {
    setProducts(prev => prev.filter(p => !ids.includes(p.id)));
    try {
      await dbService.deleteMany(ids);
    } catch (error) {
      console.error("Failed to delete products:", error);
    }
  };

  if (isLoading) {
    return (
       <div className="h-screen w-screen flex items-center justify-center bg-slate-50">
          <div className="animate-pulse flex flex-col items-center">
             <div className="w-12 h-12 bg-indigo-100 rounded-full mb-3"></div>
             <div className="h-4 w-32 bg-slate-200 rounded"></div>
          </div>
       </div>
    );
  }

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden text-slate-900 bg-slate-100">
      {/* Main Content Area - Automatically routed based on device */}
      <div className="flex-1 overflow-hidden relative">
        {isMobile ? (
          <div className="h-full w-full bg-slate-50">
             <MobileEntry onSave={handleAddProduct} />
          </div>
        ) : (
          <div className="h-full w-full bg-slate-50 flex flex-col">
            <Dashboard 
              products={products} 
              onUpdateProduct={handleUpdateProduct} 
              onDeleteProduct={handleDeleteProducts}
              onAddProduct={handleAddProduct}
            />
          </div>
        )}
      </div>
    </div>
  );
}

