                     <input className="w-full mt-1 border border-slate-200 p-2.5 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none" value={invoiceConfig.sellerAddress} onChange={e => setInvoiceConfig({...invoiceConfig, sellerAddress: e.target.value})} />
                   </div>
                 </div>
              </div>
              <div className="space-y-4 pt-4 border-t border-slate-100">
                 <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Shipment Details</h3>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="col-span-2">
                      <label className="text-sm font-medium text-slate-700">Buyer Info (Multi-line)</label>
                      <textarea className="w-full mt-1 border border-slate-200 p-2.5 rounded-lg text-sm h-24 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none" value={invoiceConfig.buyerInfo} onChange={e => setInvoiceConfig({...invoiceConfig, buyerInfo: e.target.value})} />
                    </div>
                    <div><label className="text-sm font-medium text-slate-700">Invoice No</label><input className="w-full mt-1 border border-slate-200 p-2.5 rounded-lg text-sm" value={invoiceConfig.invoiceNo} onChange={e => setInvoiceConfig({...invoiceConfig, invoiceNo: e.target.value})} /></div>
                    <div><label className="text-sm font-medium text-slate-700">Date</label><input className="w-full mt-1 border border-slate-200 p-2.5 rounded-lg text-sm" value={invoiceConfig.date} onChange={e => setInvoiceConfig({...invoiceConfig, date: e.target.value})} /></div>
                 </div>
              </div>
            </div>
            <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end gap-3 sticky bottom-0">
               <button onClick={() => setShowInvoiceModal(false)} className="px-5 py-2.5 text-slate-600 font-medium hover:bg-white hover:shadow-sm rounded-lg transition-all">Cancel</button>
               <button onClick={() => { setShowInvoiceModal(false); generateExcel('invoice'); }} className="px-5 py-2.5 bg-indigo-600 text-white font-medium rounded-lg shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center gap-2">
                 <Download size={16} /> Save & Download
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Main App Bar */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm/50">
        <div className="px-8 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg shadow-indigo-200">
               <Database size={20} />
             </div>
             <div>
                <h1 className="text-lg font-bold text-slate-900 leading-tight">Product Master</h1>
                <p className="text-xs text-slate-500 font-medium">{products.length} records found</p>
             </div>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={() => setShowUploadModal(true)}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-xs font-bold uppercase tracking-wide rounded-lg hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all mr-4"
             >
                <UploadCloud size={16} /> New Sourcing / Batch
             </button>

             <div className="flex bg-slate-100 p-1 rounded-lg">
                <button onClick={() => generateExcel('master')} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white hover:text-indigo-600 hover:shadow-sm rounded-md transition-all">
                  <Database size={14} /> Master
                </button>
                <div className="w-px bg-slate-300 my-1 mx-1"></div>
                <button onClick={() => generateExcel('packinglist')} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white hover:text-green-600 hover:shadow-sm rounded-md transition-all">
                  <Package size={14} /> Packing
                </button>
                <div className="w-px bg-slate-300 my-1 mx-1"></div>
                <button onClick={() => setShowInvoiceModal(true)} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white hover:text-blue-600 hover:shadow-sm rounded-md transition-all">
                  <Printer size={14} /> Invoice
                </button>
             </div>
          </div>
        </div>

        {/* Filters & Bulk Bar */}
        <div className="px-8 py-3 bg-slate-50/50 border-t border-slate-200 flex items-center justify-between">
           {selectedIds.size > 0 ? (
             <div className="flex items-center gap-4 bg-indigo-50 border border-indigo-100 px-4 py-1.5 rounded-lg animate-in fade-in slide-in-from-top-1">
                <span className="text-sm font-bold text-indigo-700 flex items-center gap-2">
                   <CheckSquare size={16} /> {selectedIds.size} Selected
                </span>
                <div className="h-4 w-px bg-indigo-200"></div>
                <button onClick={handleBulkEnrich} disabled={isBulkProcessing} className="text-xs font-medium text-indigo-600 hover:text-indigo-800 flex items-center gap-1.5 transition-colors">
                   {isBulkProcessing ? <RefreshCw className="animate-spin" size={14}/> : <Sparkles size={14}/>} AI Enrich
                </button>
                <button onClick={handleBulkDelete} className="text-xs font-medium text-red-600 hover:text-red-800 flex items-center gap-1.5 transition-colors ml-2">
                   <Trash2 size={14}/> Delete
                </button>
             </div>
           ) : (
             <div className="flex items-center gap-6 text-sm text-slate-500">
               <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-md px-3 py-1 shadow-sm">
                  <span className="text-xs font-bold text-slate-400 uppercase">Rate (EUR)</span>
                  <input type="number" value={euroRmbRate} onChange={e => setEuroRmbRate(Number(e.target.value))} className="w-12 text-slate-800 font-mono text-center outline-none border-b border-transparent focus:border-indigo-500" />
