                       {selectedIds.size > 0 && selectedIds.size === products.length ? <CheckSquare size={18}/> : <Square size={18}/>}
                     </button>
                  </th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Product</th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Details (EN/ES)</th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Category</th>
