                  return (
                    <tr key={p.id} className={`group transition-colors ${isEditing ? 'bg-indigo-50/50' : isSelected ? 'bg-blue-50/30' : 'hover:bg-slate-50'}`}>
                      <td className="px-6 py-4 text-center">
