             </button>

             <div className="flex bg-slate-100 p-1 rounded-lg">
                <button onClick={() => generateExcel('master')} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white hover:text-indigo-600 hover:shadow-sm rounded-md transition-all">
