               <input type="text" value={boxDims} onChange={(e) => setBoxDims(e.target.value)} placeholder="60*40*50" className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium focus:bg-white focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none transition-all" />
