      {/* Mobile Floating Save Button (Fixed at Bottom) */}
      {!isDesktopMode && (
        <div className="absolute bottom-24 left-0 right-0 px-6 z-20 pointer-events-none">
           <button 
              onClick={handleSubmit}
              className="w-full pointer-events-auto bg-slate-900 text-white rounded-xl py-3.5 shadow-xl shadow-slate-200 flex items-center justify-center gap-2 font-bold text-sm tracking-wide active:scale-[0.98] transition-all hover:bg-slate-800"
            >
              <Save size={18} />
              SAVE PRODUCT
            </button>
        </div>
      )}

      {/* Mobile Bottom Nav */}
      {!isDesktopMode && (
        <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-12 flex justify-between items-center z-30">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-indigo-600">
            <Plus size={24} strokeWidth={2.5} />
            <span className="text-[10px] font-bold tracking-wide">NEW</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-slate-300 hover:text-slate-500 transition-colors">
            <Layers size={24} />
            <span className="text-[10px] font-bold tracking-wide">LIST</span>
