import { GoogleGenAI, Type } from "@google/genai";
import { AIEnrichmentResult } from "../types";

// Safe access to environment variables
const getApiKey = () => {
  try {
    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      return process.env.API_KEY;
    }
  } catch (e) {
    // Ignore ReferenceError if process is not defined
  }
  return undefined;
};

const getClient = () => {
  const apiKey = getApiKey();
  if (!apiKey) {
    // For local dev or environments where process.env is not polyfilled
    console.warn("API Key missing. Check process.env.API_KEY");
    throw new Error("API Key configuration missing. Please check settings.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to safely parse JSON from AI response, stripping Markdown code blocks if present
const safeJsonParse = (text: string | undefined) => {
  if (!text) throw new Error("No response from AI");
  try {
    // Remove ```json and ``` wrapping if they exist
    const cleanText = text.replace(/```json\n?|```/g, '').trim();
    // Handle cases where AI returns plain text instead of JSON
    if (!cleanText.startsWith('{') && !cleanText.startsWith('[')) {
       // If strict JSON mode is on, this shouldn't happen, but good fallback
       const firstBrace = cleanText.indexOf('{');
       const lastBrace = cleanText.lastIndexOf('}');
       if (firstBrace !== -1 && lastBrace !== -1) {
          return JSON.parse(cleanText.substring(firstBrace, lastBrace + 1));
       }
       throw new Error("Response is not JSON");
    }
    return JSON.parse(cleanText);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    console.error("Raw Text:", text);
    throw new Error("Failed to parse AI response as JSON");
  }
};

// Text-based enrichment: Now acts as a Customs Expert & Translator
export const enrichProductData = async (nameCn: string): Promise<AIEnrichmentResult> => {
  try {
    const ai = getClient();
    const prompt = `
      You are a Senior Customs Classification Specialist for China-EU Trade.
      Product Chinese Name: "${nameCn}".

      TASK:
      1. **Analyze**: Identify the material (e.g., Plastic, Metal, Textile) and intended use.
      2. **Translation**: Professional English & Spanish Trade Names.
      3. **HS Code (CRITICAL)**: Assign the most accurate **6-digit International Harmonized System Code**.
         - If Textile/Garment, check Chapter 61-63.
         - If Plastic Houseware, check Chapter 39 (e.g., 3924).
         - If Metal Houseware, check Chapter 73/74/76 (e.g., 7323).
         - If Electronic, check Chapter 84/85.
         - *Do not return empty.* If unsure, use the closest general category code.
      4. **Duty**: Estimate EU Import Duty Rate (%).

      Output JSON only.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nameEn: { type: Type.STRING, description: "English Name" },
            nameEs: { type: Type.STRING, description: "Spanish Name" },
            categoryMain: { type: Type.STRING, description: "Main Category (Material/Use)" },
            categorySub: { type: Type.STRING, description: "Sub Category" },
            materialEn: { type: Type.STRING, description: "Material Composition" },
            hsCode: { type: Type.STRING, description: "6-digit HS Code" },
            usage: { type: Type.STRING, description: "Usage" },
            taxRate: { type: Type.NUMBER, description: "EU Duty Rate (%)" }
          },
          required: ["nameEn", "nameEs", "categoryMain", "categorySub", "materialEn", "hsCode", "taxRate"]
        }
      }
    });

    return safeJsonParse(response.text) as AIEnrichmentResult;
  } catch (error) {
    console.error("AI Enrichment failed:", error);
    throw error;
  }
};

export interface ImageAnalysisResult {
  nameCn: string;
  priceRmb: number;
  moq: number;
  nameEn: string;
