// Image-based analysis: Switched to gemini-2.5-flash for reliability and native JSON
export const analyzeImage = async (base64Image: string): Promise<ImageAnalysisResult> => {
  try {
    const ai = getClient();
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    // Using gemini-2.5-flash which is faster, cheaper, and more stable.
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", 
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: `
            Role: Yiwu Sourcing & Customs Expert.

            TASK: 
            Analyze this product image and provide ESTIMATED standard market data.

            1. **Identify**: Name (CN/EN) and Main Material.
            2. **HS Code**: Determine the likely **6-digit HS Code** based on visual material and function.
            3. **Specs**: Estimate carton dims and packing qty.
            4. **Price**: Estimate low-end wholesale RMB price.
            ` 
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
             nameCn: { type: Type.STRING, description: "Product Name in Chinese" },
             nameEn: { type: Type.STRING, description: "Product Name in English" },
             materialEn: { type: Type.STRING, description: "Main Material" },
             hsCode: { type: Type.STRING, description: "Estimated 6-digit HS Code" },
             priceRmb: { type: Type.NUMBER, description: "Estimated Wholesale Price RMB" },
             moq: { type: Type.NUMBER, description: "Standard MOQ (e.g. 1 carton)" },
             boxLength: { type: Type.NUMBER, description: "Carton Length cm" },
             boxWidth: { type: Type.NUMBER, description: "Carton Width cm" },
             boxHeight: { type: Type.NUMBER, description: "Carton Height cm" },
             pcsPerBox: { type: Type.NUMBER, description: "Pieces per Carton" }
          },
          required: ["nameCn", "nameEn", "hsCode", "priceRmb", "boxLength", "boxWidth", "boxHeight", "pcsPerBox"]
        }
      }
    });

    // With responseMimeType: application/json, parsing is much safer
    const result = safeJsonParse(response.text) as ImageAnalysisResult;

    // Sanity check: Ensure we return numbers, not strings for dimensions
    return {
      nameCn: result.nameCn || "待识别商品",
      nameEn: result.nameEn || "Unknown Product",
      materialEn: result.materialEn || "General",
      hsCode: result.hsCode || "",
      priceRmb: Number(result.priceRmb) || 0,
      moq: Number(result.moq) || 0,
      boxLength: Number(result.boxLength) || 0,
      boxWidth: Number(result.boxWidth) || 0,
      boxHeight: Number(result.boxHeight) || 0,
      pcsPerBox: Number(result.pcsPerBox) || 0
    };

  } catch (error) {
    console.error("Image Analysis failed:", error);
    // Return empty safe object
    return {
      nameCn: "识别失败 (Manual Entry)",
      priceRmb: 0,
      moq: 0,
      nameEn: "",
      materialEn: "",
      hsCode: "",
      boxLength: 0,
      boxWidth: 0,
      boxHeight: 0,
      pcsPerBox: 0
    };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft } from 'lucide-react';
import { Product, ProcessingStatus } from '../types';
import { analyzeImage } from '../services/geminiService';

interface MobileEntryProps {
  onSave: (product: Product) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave, isDesktopMode, onClose }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Ref to track if component is mounted to prevent memory leaks/errors on unmount
  const isMounted = useRef(true);

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // Quick calculate metrics so data is "hot" when hitting the dashboard
  const calculateInitialMetrics = (p: Partial<Product>) => {
    // Default assumptions for instant calculation
    const rate = 7.8; // Euro Rate
    const freight = 150; // $150/CBM
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
    };
  };

  // Helper to read file and COMPRESS it (Optimized for Speed)
  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);

      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;

        img.onload = () => {
          // Resize Logic: Reduced to 800px for faster batch AI processing
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;

          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;

          const ctx = canvas.getContext('2d');
          if (!ctx) {
            resolve(event.target?.result as string); // Fallback to original
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          // Compress to JPEG with 0.6 quality (Faster upload, sufficient for AI)
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
          resolve(dataUrl);
        };

        img.onerror = (err) => reject(err);
      };

      reader.onerror = (err) => reject(err);
    });
  };

  const handlePhotoSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const compressedBase64 = await processImageFile(file);
        if (isMounted.current) setPhotoPreview(compressedBase64);
      } catch (e) {
        console.error("Image processing error", e);
      }
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        // --- RATE LIMIT PROTECTION ---
        // Reduced concurrency to 2 to prevent "Quota Exceeded" errors (429)
        // Added 2000ms delay between requests
        const CONCURRENCY_LIMIT = 2;
        let processedCount = 0;

        // Task function for a single file
        const processFileItem = async (file: File) => {
           try {
             const base64 = await processImageFile(file);

             let aiData;
             try {
                // Calls the updated geminiService with search capabilities
                aiData = await analyzeImage(base64);
             } catch (err: any) {
                console.warn("AI Analysis error", err);
                aiData = { 
                  nameCn: "Processing Error", priceRmb: 0, moq: 0, nameEn: "Error", materialEn: "Unknown", hsCode: "",
                  boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0
                };
             }

             const partialProduct: Product = {
                id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9),
                sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
                photoUrl: base64,
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn,
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || "TBD",
                hsCode: aiData.hsCode, // Map HS Code from Image Analysis
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
             };

             // Calculate metrics immediately
             const metrics = calculateInitialMetrics(partialProduct);

             if (isMounted.current) {
                onSave({ ...partialProduct, ...metrics });
             }

           } catch (e) {
             console.error("File processing critical error", e);
           } finally {
             processedCount++;
             if (isMounted.current) {
               setProcessingCount(prev => ({ ...prev, current: processedCount }));
             }
           }
        };

        // Create a worker queue
        const queue = [...files];
        const workers = Array(Math.min(CONCURRENCY_LIMIT, files.length))
          .fill(null)
          .map(async () => {
            while (queue.length > 0 && isMounted.current) {
              const file = queue.shift();
              if (file) {
                await processFileItem(file);
                // THROTTLE: Wait 2 seconds between processing items to respect API limits
                if (isMounted.current) await new Promise(resolve => setTimeout(resolve, 2000));
              }
            }
          });

        // Wait for all workers to finish
        await Promise.all(workers);

        // Success transition
        if (isMounted.current) {
          await new Promise(resolve => setTimeout(resolve, 500));

          // If in desktop mode, we might want to close the modal or just show success
          if (isDesktopMode) {
            alert(`Batch Complete! Processed ${files.length} images.`);
            if (onClose) onClose();
          } else {
            setActiveTab('list');
          }
        }

      } catch (error) {
        console.error("Batch processing critical error:", error);
        alert("Batch processing stopped due to an error.");
      } finally {
        if (isMounted.current) setIsBatchProcessing(false);
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => {
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0;
    const w = parts[1] || 0;
    const h = parts[2] || 0;

    const partialProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l,
      boxWidth: w,
      boxHeight: h,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    const metrics = calculateInitialMetrics(partialProduct);
    onSave({ ...partialProduct, ...metrics });

    setNameCn(''); setPriceRmb(''); setMoq(''); setShopNo(''); setBoxDims(''); setPcsPerBox(''); setPhotoPreview(null);

    if (isDesktopMode) {
      alert("Product Saved!");
      if(onClose) onClose();
    } else {
      alert("Saved!");
    }
  };

  // If in List mode (History) - Only show if NOT in Desktop Mode
  // (In desktop mode, we use the dashboard for lists)
  if (activeTab === 'list' && !isDesktopMode) {
    return (
      <div className="flex flex-col h-full bg-slate-50">
        <div className="px-6 py-5 bg-white shadow-sm z-10">
          <h2 className="text-xl font-bold text-slate-800 tracking-tight">Recent Scans</h2>
          <p className="text-sm text-slate-500 mt-1">Review items in Desktop Dashboard</p>
        </div>
        <div className="flex-1 p-6 flex flex-col items-center justify-center text-slate-400">
           <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4 shadow-inner">
             <Box size={32} className="text-slate-300" />
           </div>
           <p className="font-medium">Items saved locally.</p>
           <p className="text-xs mt-1 text-center max-w-[200px]">Switch to Desktop view to organize and export your data.</p>
        </div>
        <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-8 flex justify-between items-center z-20">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-slate-400 hover:text-indigo-600 transition-colors">
            <Plus size={24} />
            <span className="text-[10px] font-medium tracking-wide">NEW</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-indigo-600">
            <Layers size={24} />
            <span className="text-[10px] font-medium tracking-wide">LIST</span>
          </button>
        </nav>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-slate-50 relative font-sans">
      {isBatchProcessing && (
        <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center text-indigo-600">
           <div className="relative">
             <div className="absolute inset-0 bg-indigo-200 blur-xl opacity-50 rounded-full animate-pulse"></div>
             <Loader2 className="animate-spin mb-4 relative z-10" size={48} />
           </div>
           <p className="font-bold text-lg text-slate-800">Processing {processingCount.current} / {processingCount.total}</p>
           <p className="text-sm text-indigo-600 font-medium mt-2 flex items-center gap-1">
              <Zap size={14} fill="currentColor"/> Hyper-Batch Active
           </p>
           <p className="text-xs text-slate-400 mt-1">Max Concurrency Enabled</p>
        </div>
      )}

      {/* Header */}
      <div className="bg-white px-6 pt-6 pb-4 shadow-sm border-b border-slate-100 z-10 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-slate-900 tracking-tight">
            {isDesktopMode ? "Add / Batch Upload" : "New Sourcing"}
          </h1>
          <div className="flex items-center gap-1 text-xs font-medium text-indigo-600 mt-0.5">
             <Store size={12} />
             <span>Yiwu District 4</span>
          </div>
        </div>

        {isDesktopMode ? (
          <button onClick={onClose} className="h-8 w-8 rounded-full bg-slate-100 hover:bg-slate-200 flex items-center justify-center transition-colors text-slate-500">
             <X size={18} />
          </button>
        ) : (
          <div className="h-8 w-8 rounded-full bg-indigo-50 flex items-center justify-center border border-indigo-100">
             <Tag size={16} className="text-indigo-600"/>
          </div>
        )}
      </div>

      {/* Form Content */}
      <form onSubmit={handleSubmit} className={`flex-1 overflow-y-auto px-5 py-6 space-y-6 scroll-smooth ${isDesktopMode ? 'pb-6' : 'pb-28'}`}>

        {/* Batch Upload Card */}
        <div className="relative overflow-hidden bg-gradient-to-br from-indigo-600 to-violet-600 rounded-2xl shadow-lg shadow-indigo-200 text-white p-5 transition-transform hover:scale-[1.01] duration-300">
           <div className="relative z-10">
             <div className="flex justify-between items-start mb-3">
               <h3 className="font-bold text-lg flex items-center gap-2">
                 <Layers size={18} /> Quick Batch
               </h3>
               <span className="bg-white/20 px-2 py-0.5 rounded text-[10px] font-medium backdrop-blur-sm">AI Powered</span>
             </div>
             <p className="text-indigo-100 text-xs mb-4 leading-relaxed max-w-[90%]">
               Upload multiple photos (Up to 400). Our AI will search and fill details automatically.
             </p>
             <label className="flex items-center justify-center w-full py-2.5 bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/20 rounded-lg cursor-pointer transition-all active:scale-95">
                <span className="font-semibold text-sm">Select Images</span>
                <input type="file" multiple accept="image/*" onChange={handleBatchSelect} className="hidden" />
             </label>
           </div>
           {/* Decorative Circles */}
           <div className="absolute -top-6 -right-6 w-32 h-32 bg-white/10 rounded-full blur-2xl"></div>
           <div className="absolute bottom-0 left-0 w-24 h-24 bg-indigo-400/20 rounded-full blur-xl"></div>
        </div>

        <div className="flex items-center gap-3 text-xs text-slate-400 font-medium uppercase tracking-wider my-2">
            <div className="h-px bg-slate-200 flex-1"></div>
            <span>Manual Entry</span>
            <div className="h-px bg-slate-200 flex-1"></div>
        </div>

        {/* Photo Section */}
        <div className="space-y-2">
          <label className="text-xs font-semibold text-slate-500 uppercase tracking-wide ml-1">Product Photo</label>
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex gap-4 items-center">
            <div className="relative group shrink-0">
               <div className="w-20 h-20 rounded-xl bg-slate-50 border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden transition-colors group-hover:border-indigo-300">
                  {photoPreview ? (
                    <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <Camera className="text-slate-300 group-hover:text-indigo-400" size={24} />
                  )}
               </div>
               <input type="file" accept="image/*" onChange={handlePhotoSelect} className="absolute inset-0 opacity-0 cursor-pointer" />
            </div>
            <div className="flex-1">
               <h4 className="text-sm font-semibold text-slate-800">Take a photo</h4>
               <p className="text-xs text-slate-500 mt-1">Capture product details clearly.</p>
            </div>
            <div className="h-8 w-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">
               <ChevronRight size={16} />
            </div>
          </div>
        </div>

        {/* Basic Info Group */}
        <div className="space-y-4">
           <div className="relative">
             <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-indigo-600 uppercase">Product Name</label>
             <input 
               type="text" 
               value={nameCn}
               onChange={(e) => setNameCn(e.target.value)}
               placeholder="e.g. Stainless Steel Pot"
               className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all placeholder:text-slate-300 shadow-sm"
             />
           </div>

           <div className="grid grid-cols-2 gap-3">
             <div className="relative">
                <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-slate-400 uppercase">RMB Cost</label>
                <div className="relative">
                  <div className="absolute left-3 top-3.5 text-slate-400"><DollarSign size={14} /></div>
                  <input 
                    type="number" 
                    value={priceRmb}
                    onChange={(e) => setPriceRmb(e.target.value)}
                    placeholder="0.00"
                    className="w-full bg-white border border-slate-200 rounded-xl pl-8 pr-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm"
                    inputMode="decimal"
                  />
                </div>
             </div>
             <div className="relative">
                <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-slate-400 uppercase">MOQ</label>
                <input 
                  type="number" 
                  value={moq}
                  onChange={(e) => setMoq(e.target.value)}
                  placeholder="PCS"
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm"
                  inputMode="numeric"
                />
             </div>
           </div>

           <div className="relative">
             <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-slate-400 uppercase">Shop No.</label>
             <div className="relative">
                <div className="absolute left-3 top-3.5 text-slate-400"><Store size={14} /></div>
                <input 
                  type="text" 
                  value={shopNo}
                  onChange={(e) => setShopNo(e.target.value)}
                  placeholder="F1-1234"
                  className="w-full bg-white border border-slate-200 rounded-xl pl-8 pr-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm"
                />
             </div>
           </div>
        </div>

        {/* Logistics Group */}
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 space-y-4">
          <div className="flex justify-between items-center pb-2 border-b border-slate-50">
             <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wide flex items-center gap-1">
               <Package size={14} /> Packing Info
             </h3>
             <button type="button" onClick={handleSimulateOCR} className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded font-medium hover:bg-indigo-100 transition-colors">
               Auto-Detect
             </button>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
               <label className="block text-[10px] font-medium text-slate-400 mb-1">Box (LxWxH)</label>
               <input type="text" value={boxDims} onChange={(e) => setBoxDims(e.target.value)} placeholder="60*40*50" className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium focus:bg-white focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none transition-all" />
            </div>
             <div>
               <label className="block text-[10px] font-medium text-slate-400 mb-1">Pcs/Ctn</label>
               <input type="number" value={pcsPerBox} onChange={(e) => setPcsPerBox(e.target.value)} placeholder="120" className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium focus:bg-white focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none transition-all" />
            </div>
          </div>
        </div>

        {/* Desktop Save Button (Inline) */}
        {isDesktopMode && (
           <button 
             onClick={handleSubmit}
             className="w-full bg-slate-900 text-white rounded-xl py-3 shadow-lg shadow-slate-200 flex items-center justify-center gap-2 font-bold text-sm tracking-wide hover:bg-slate-800 transition-all mt-4"
           >
             <Save size={18} />
             SAVE & CLOSE
           </button>
        )}
      </form>

      {/* Mobile Floating Save Button (Fixed at Bottom) */}
      {!isDesktopMode && (
        <div className="absolute bottom-24 left-0 right-0 px-6 z-20 pointer-events-none">
           <button 
              onClick={handleSubmit}
              className="w-full pointer-events-auto bg-slate-900 text-white rounded-xl py-3.5 shadow-xl shadow-slate-200 flex items-center justify-center gap-2 font-bold text-sm tracking-wide active:scale-[0.98] transition-all hover:bg-slate-800"
            >
              <Save size={18} />
              SAVE PRODUCT
            </button>
        </div>
      )}

      {/* Mobile Bottom Nav */}
      {!isDesktopMode && (
        <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-12 flex justify-between items-center z-30">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-indigo-600">
            <Plus size={24} strokeWidth={2.5} />
            <span className="text-[10px] font-bold tracking-wide">NEW</span>
          </button>
           <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-slate-300 hover:text-slate-500 transition-colors">
            <Layers size={24} />
            <span className="text-[10px] font-bold tracking-wide">LIST</span>
          </button>
        </nav>
      )}
    </div>
  );
};

export default MobileEntry;

import React, { useState, useEffect } from 'react';
import MobileEntry from './components/MobileEntry';
import Dashboard from './components/Dashboard';
import { Product } from './types';
import { dbService } from './services/db';

export default function App() {
  const [isMobile, setIsMobile] = useState(false);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Load from IndexedDB on mount & Detect Screen Size
  useEffect(() => {
    // 1. Device Detection
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 768);
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);

    // 2. Load Data
    const loadData = async () => {
      try {
        const storedProducts = await dbService.getAll();
        // Sort by newest first
        setProducts(storedProducts.sort((a, b) => b.timestamp - a.timestamp));
      } catch (error) {
        console.error("Failed to load products from DB:", error);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();

    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleAddProduct = async (newProduct: Product) => {
    // Optimistic UI update
    setProducts(prev => [newProduct, ...prev]);
    // Persist to DB
    try {
      await dbService.save(newProduct);
    } catch (error) {
      console.error("Failed to save product:", error);
      alert("Error saving data. Please check storage space.");
    }
  };

  const handleUpdateProduct = async (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
    try {
      await dbService.save(updatedProduct);
    } catch (error) {
      console.error("Failed to update product:", error);
    }
  };

  const handleDeleteProducts = async (ids: string[]) => {
    setProducts(prev => prev.filter(p => !ids.includes(p.id)));
    try {
      await dbService.deleteMany(ids);
    } catch (error) {
      console.error("Failed to delete products:", error);
    }
  };

  if (isLoading) {
    return (
       <div className="h-screen w-screen flex items-center justify-center bg-slate-50">
          <div className="animate-pulse flex flex-col items-center">
             <div className="w-12 h-12 bg-indigo-100 rounded-full mb-3"></div>
             <div className="h-4 w-32 bg-slate-200 rounded"></div>
          </div>
       </div>
    );
  }

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden text-slate-900 bg-slate-100">
      {/* Main Content Area - Automatically routed based on device */}
      <div className="flex-1 overflow-hidden relative">
        {isMobile ? (
          <div className="h-full w-full bg-slate-50">
             <MobileEntry onSave={handleAddProduct} products={products} />
          </div>
        ) : (
          <div className="h-full w-full bg-slate-50 flex flex-col">
            <Dashboard 
              products={products} 
              onUpdateProduct={handleUpdateProduct} 
              onDeleteProduct={handleDeleteProducts}
              onAddProduct={handleAddProduct}
            />
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft } from 'lucide-react';
import { Product, ProcessingStatus } from '../types';
import { analyzeImage } from '../services/geminiService';

interface MobileEntryProps {
  onSave: (product: Product) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave, isDesktopMode, onClose, products = [] }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Ref to track if component is mounted to prevent memory leaks/errors on unmount
  const isMounted = useRef(true);

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // Quick calculate metrics so data is "hot" when hitting the dashboard
  const calculateInitialMetrics = (p: Partial<Product>) => {
    // Default assumptions for instant calculation
    const rate = 7.8; // Euro Rate
    const freight = 150; // $150/CBM
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
    };
  };

  // Helper to read file and COMPRESS it (Optimized for Speed)
  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);

      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;

        img.onload = () => {
          // Resize Logic: Reduced to 800px for faster batch AI processing
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;

          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;

          const ctx = canvas.getContext('2d');
          if (!ctx) {
            resolve(event.target?.result as string); // Fallback to original
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          // Compress to JPEG with 0.6 quality (Faster upload, sufficient for AI)
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
          resolve(dataUrl);
        };

        img.onerror = (err) => reject(err);
      };

      reader.onerror = (err) => reject(err);
    });
  };

  const handlePhotoSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const compressedBase64 = await processImageFile(file);
        if (isMounted.current) setPhotoPreview(compressedBase64);
      } catch (e) {
        console.error("Image processing error", e);
      }
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        // --- RATE LIMIT PROTECTION ---
        // Reduced concurrency to 2 to prevent "Quota Exceeded" errors (429)
        // Added 2000ms delay between requests
        const CONCURRENCY_LIMIT = 2;
        let processedCount = 0;

        // Task function for a single file
        const processFileItem = async (file: File) => {
           try {
             const base64 = await processImageFile(file);

             let aiData;
             try {
                // Calls the updated geminiService with search capabilities
                aiData = await analyzeImage(base64);
             } catch (err: any) {
                console.warn("AI Analysis error", err);
                aiData = { 
                  nameCn: "Processing Error", priceRmb: 0, moq: 0, nameEn: "Error", materialEn: "Unknown", hsCode: "",
                  boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0
                };
             }

             const partialProduct: Product = {
                id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9),
                sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
                photoUrl: base64,
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn,
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || "TBD",
                hsCode: aiData.hsCode, // Map HS Code from Image Analysis
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
             };

             // Calculate metrics immediately
             const metrics = calculateInitialMetrics(partialProduct);

             if (isMounted.current) {
                onSave({ ...partialProduct, ...metrics });
             }

           } catch (e) {
             console.error("File processing critical error", e);
           } finally {
             processedCount++;
             if (isMounted.current) {
               setProcessingCount(prev => ({ ...prev, current: processedCount }));
             }
           }
        };

        // Create a worker queue
        const queue = [...files];
        const workers = Array(Math.min(CONCURRENCY_LIMIT, files.length))
          .fill(null)
          .map(async () => {
            while (queue.length > 0 && isMounted.current) {
              const file = queue.shift();
              if (file) {
                await processFileItem(file);
                // THROTTLE: Wait 2 seconds between processing items to respect API limits
                if (isMounted.current) await new Promise(resolve => setTimeout(resolve, 2000));
              }
            }
          });

        // Wait for all workers to finish
        await Promise.all(workers);

        // Success transition
        if (isMounted.current) {
          await new Promise(resolve => setTimeout(resolve, 500));

          // If in desktop mode, we might want to close the modal or just show success
          if (isDesktopMode) {
            alert(`Batch Complete! Processed ${files.length} images.`);
            if (onClose) onClose();
          } else {
            setActiveTab('list');
          }
        }

      } catch (error) {
        console.error("Batch processing critical error:", error);
        alert("Batch processing stopped due to an error.");
      } finally {
        if (isMounted.current) setIsBatchProcessing(false);
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => {
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
