                      <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded font-medium">{new Date(p.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                    </div>
                    <p className="text-xs text-slate-500 truncate mt-0.5">{p.nameCn || p.nameEn || "No Name"}</p>
                  </div>
                  <div className="flex justify-between items-end mt-2">
                    <div className="flex items-center gap-2 text-xs text-slate-400">
                       <span className="flex items-center gap-1"><Box size={10}/> {p.pcsPerBox}</span>
