export default MobileEntry;

import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft, CheckSquare, Square, Trash2, Sparkles, Download, RefreshCw, FileText, Database, Printer } from 'lucide-react';
import { Product, ProcessingStatus } from '../types';
import { analyzeImage, enrichProductData } from '../services/geminiService';

// Declare globals for CDN libraries
declare const ExcelJS: any;
declare const saveAs: any;

const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832",
};

interface MobileEntryProps {
  onSave: (product: Product) => void;
  onUpdateProduct?: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave, onUpdateProduct, onDeleteProduct, isDesktopMode, onClose, products = [] }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Selection & Action Mode State
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });
  const [showExportMenu, setShowExportMenu] = useState(false);

  // Ref to track if component is mounted to prevent memory leaks/errors on unmount
  const isMounted = useRef(true);

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // Quick calculate metrics
  const calculateMetrics = (p: Partial<Product>) => {
    // Default assumptions
    const rate = 7.8; // Euro Rate
    const freight = 150; // $150/CBM
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / 7.2 : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3))
    };
  };

  // Helper to read file and COMPRESS it (Optimized for Speed)
  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);

      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;

        img.onload = () => {
          // Resize Logic: Reduced to 800px for faster batch AI processing
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;

          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;

          const ctx = canvas.getContext('2d');
          if (!ctx) {
            resolve(event.target?.result as string); // Fallback to original
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          // Compress to JPEG with 0.6 quality (Faster upload, sufficient for AI)
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
          resolve(dataUrl);
        };

        img.onerror = (err) => reject(err);
      };

      reader.onerror = (err) => reject(err);
    });
  };

  const handlePhotoSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const compressedBase64 = await processImageFile(file);
        if (isMounted.current) setPhotoPreview(compressedBase64);
      } catch (e) {
        console.error("Image processing error", e);
      }
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        const CONCURRENCY_LIMIT = 2;
        let processedCount = 0;

        const processFileItem = async (file: File) => {
           try {
             const base64 = await processImageFile(file);
             let aiData;
             try {
                aiData = await analyzeImage(base64);
             } catch (err: any) {
                console.warn("AI Analysis error", err);
                aiData = { 
                  nameCn: "Processing Error", priceRmb: 0, moq: 0, nameEn: "Error", materialEn: "Unknown", hsCode: "",
                  boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0
                };
             }

             const partialProduct: Product = {
                id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9),
                sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
                photoUrl: base64,
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn,
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || "TBD",
                hsCode: aiData.hsCode,
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
             };

             const metrics = calculateMetrics(partialProduct);

             if (isMounted.current) {
                onSave({ ...partialProduct, ...metrics });
             }

           } catch (e) {
             console.error("File processing critical error", e);
           } finally {
             processedCount++;
             if (isMounted.current) {
               setProcessingCount(prev => ({ ...prev, current: processedCount }));
             }
           }
        };

        const queue = [...files];
        const workers = Array(Math.min(CONCURRENCY_LIMIT, files.length))
          .fill(null)
          .map(async () => {
            while (queue.length > 0 && isMounted.current) {
              const file = queue.shift();
              if (file) {
                await processFileItem(file);
                if (isMounted.current) await new Promise(resolve => setTimeout(resolve, 2000));
              }
            }
          });

        await Promise.all(workers);

        if (isMounted.current) {
          await new Promise(resolve => setTimeout(resolve, 500));
          if (isDesktopMode) {
            alert(`Batch Complete! Processed ${files.length} images.`);
            if (onClose) onClose();
          } else {
            setActiveTab('list');
          }
        }

      } catch (error) {
        console.error("Batch processing critical error:", error);
        alert("Batch processing stopped due to an error.");
      } finally {
        if (isMounted.current) setIsBatchProcessing(false);
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => {
    setBoxDims('60x40x50');
    setPcsPerBox('120');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0;
    const w = parts[1] || 0;
    const h = parts[2] || 0;

    const partialProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l,
      boxWidth: w,
      boxHeight: h,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    const metrics = calculateMetrics(partialProduct);
    onSave({ ...partialProduct, ...metrics });

    setNameCn(''); setPriceRmb(''); setMoq(''); setShopNo(''); setBoxDims(''); setPcsPerBox(''); setPhotoPreview(null);

    if (isDesktopMode) {
      alert("Product Saved!");
      if(onClose) onClose();
    } else {
      alert("Saved!");
    }
  };

  // --- SELECTION & BULK ACTIONS ---

  const toggleSelectMode = () => {
    if (isSelectMode) {
        setSelectedIds(new Set()); // Clear selection when exiting
    }
    setIsSelectMode(!isSelectMode);
  };

  const toggleSelectProduct = (id: string) => {
    if (!isSelectMode) return;
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const handleBulkDelete = () => {
    if (!onDeleteProduct) return;
    if (confirm(`Delete ${selectedIds.size} items?`)) {
      onDeleteProduct(Array.from(selectedIds));
      setSelectedIds(new Set());
      setIsSelectMode(false);
    }
  };

  const handleBulkEnrich = async () => {
    if (!onUpdateProduct) return;
    if (!process.env.API_KEY) return alert("API Key missing. Cannot enrich.");

    setIsEnriching(true);
    const itemsToProcess = products.filter(p => selectedIds.has(p.id));
    setEnrichProgress({ current: 0, total: itemsToProcess.length });

    let successCount = 0;

    for (const product of itemsToProcess) {
       try {
         // Using the geminiService to enrich
         const result = await enrichProductData(product.nameCn);
         const metrics = calculateMetrics({ ...product, ...result });
         onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
         successCount++;
       } catch (e) {
         console.error(`Failed to enrich ${product.id}`, e);
       } finally {
         if (isMounted.current) {
            setEnrichProgress(prev => ({ ...prev, current: prev.current + 1 }));
         }
       }
       // Small delay to prevent rate limits
       await new Promise(resolve => setTimeout(resolve, 500));
    }

    if (isMounted.current) {
        setIsEnriching(false);
        alert(`Enrichment Complete! Updated ${successCount} products.`);
        setIsSelectMode(false);
        setSelectedIds(new Set());
    }
  };

  const handleExportExcel = async (exportType: 'master' | 'packinglist' | 'invoice' | 'quotation') => {
    if (typeof ExcelJS === 'undefined') return alert("ExcelJS library not loaded.");
    if (selectedIds.size === 0) return alert("Select items to export.");
    setShowExportMenu(false);

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet(exportType === 'invoice' ? 'INVOICE' : (exportType === 'quotation' ? 'QUOTATION' : 'Sheet1'));

    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };
    const borderStyle = { top: { style: 'thin' }, left: { style: 'thin' }, bottom: { style: 'thin' }, right: { style: 'thin' } };

    const exportItems = products.filter(p => selectedIds.has(p.id));

    if (exportType === 'invoice') {
        // --- INVOICE FORMAT ---
        sheet.columns = [
          { key: 'no', width: 5 }, { key: 'sku', width: 12 }, { key: 'desc', width: 40 },
          { key: 'hs', width: 15 }, { key: 'ctns', width: 8 }, { key: 'pkg', width: 15 },
          { key: 'qty', width: 10 }, { key: 'unit', width: 6 }, { key: 'price', width: 12 },
          { key: 'amount', width: 15 }, { key: 'gwCtn', width: 10 }, { key: 'totalGw', width: 12 },
          { key: 'cbmCtn', width: 10 }, { key: 'totalCbm', width: 12 },
        ];
        sheet.mergeCells('A1:N1'); sheet.getCell('A1').value = DEFAULT_INVOICE_CONFIG.sellerName;
        sheet.getCell('A1').font = { bold: true, size: 16 }; sheet.getCell('A1').alignment = centerStyle;
        sheet.mergeCells('A2:N2'); sheet.getCell('A2').value = DEFAULT_INVOICE_CONFIG.sellerName; sheet.getCell('A2').alignment = centerStyle;
        sheet.mergeCells('A3:N3'); sheet.getCell('A3').value = DEFAULT_INVOICE_CONFIG.sellerAddress; sheet.getCell('A3').alignment = centerStyle;
        sheet.mergeCells('A4:N4'); sheet.getCell('A4').value = `Tel: ${DEFAULT_INVOICE_CONFIG.sellerPhone}  Email: ${DEFAULT_INVOICE_CONFIG.sellerEmail}`; sheet.getCell('A4').alignment = centerStyle;
        sheet.mergeCells('A6:N6'); sheet.getCell('A6').value = "INVOICE"; sheet.getCell('A6').font = { bold: true, size: 20 }; sheet.getCell('A6').alignment = centerStyle;

        sheet.mergeCells('A8:D8'); sheet.getCell('A8').value = `Invoice No: ${DEFAULT_INVOICE_CONFIG.invoiceNo}`; sheet.getCell('A8').font = { bold: true };
        sheet.mergeCells('H8:N8'); sheet.getCell('H8').value = `Date: ${DEFAULT_INVOICE_CONFIG.date}`; sheet.getCell('H8').font = { bold: true };
        sheet.mergeCells('H9:N9'); sheet.getCell('H9').value = `Sailing: ${DEFAULT_INVOICE_CONFIG.sailing}`;
        sheet.mergeCells('A10:D13'); sheet.getCell('A10').value = `To:\n${DEFAULT_INVOICE_CONFIG.buyerInfo}`; sheet.getCell('A10').alignment = { vertical: 'top', horizontal: 'left', wrapText: true }; sheet.getCell('A10').border = borderStyle;
        sheet.mergeCells('A14:D14'); sheet.getCell('A14').value = `Container: ${DEFAULT_INVOICE_CONFIG.containerNo}`; sheet.getCell('A14').font = { bold: true }; sheet.getCell('A14').border = { bottom: { style: 'thin' } };
        sheet.mergeCells('H14:N14'); sheet.getCell('H14').value = `Seal: ${DEFAULT_INVOICE_CONFIG.sealNo}`; sheet.getCell('H14').font = { bold: true }; sheet.getCell('H14').border = { bottom: { style: 'thin' } };

        const headerRow = sheet.getRow(16);
        headerRow.values = ['No.', 'Item NO', 'Description', 'HS CODE', 'CTNS', 'Pkg', 'QTY', 'Unit', 'Price(¥)', 'Amount(¥)', 'GW/ctn', 'Total GW', 'CBM/ctn', 'Total CBM'];
        headerRow.font = { bold: true }; headerRow.alignment = centerStyle;
        headerRow.eachCell((cell:any) => { cell.border = borderStyle; cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0E0E0' } }; });

        let currentRow = 17;
        let tCtns = 0, tQty = 0, tAmt = 0, tGw = 0, tCbm = 0;

        exportItems.forEach((p, i) => {
          const m = calculateMetrics(p);
          const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
          const q = (cQty * p.pcsPerBox) || p.moq || 0;
          const amt = p.priceRmb * q;
          const gw = (p.gwKg || 0) * cQty;
          const cbm = (m.cbm || 0) * cQty;
          tCtns += cQty; tQty += q; tAmt += amt; tGw += gw; tCbm += cbm;
          const row = sheet.getRow(currentRow);
          row.values = [i+1, p.sku, p.nameEn||p.nameCn, p.hsCode, cQty, p.pcsPerBox, q, 'PCS', p.priceRmb, amt, p.gwKg||0, gw.toFixed(2), (m.cbm||0).toFixed(3), cbm.toFixed(3)];
          row.eachCell((c:any, col:any) => { c.border = borderStyle; c.alignment = col===3 ? leftStyle : centerStyle; });
          currentRow++;
        });
        const totalRow = sheet.getRow(currentRow);
        totalRow.getCell(3).value = "TOTAL"; totalRow.getCell(3).font = { bold: true }; totalRow.getCell(3).alignment = centerStyle;
        totalRow.getCell(5).value = tCtns; totalRow.getCell(7).value = tQty; totalRow.getCell(10).value = tAmt; totalRow.getCell(12).value = Number(tGw.toFixed(2)); totalRow.getCell(14).value = Number(tCbm.toFixed(3));
        [3,5,7,10,12,14].forEach(c => { totalRow.getCell(c).font={bold:true}; totalRow.getCell(c).border=borderStyle; });

    } else {
        // --- MASTER / PACKING / QUOTATION FORMATS ---
        if (exportType === 'master') {
          sheet.columns = [
            { header: 'Image', key: 'image', width: 15 }, { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
            { header: 'Name (CN)', key: 'nameCn', width: 25, style: leftStyle }, { header: 'Product Name (EN)', key: 'nameEn', width: 25, style: leftStyle },
            { header: 'Nombre Producto (ES)', key: 'nameEs', width: 25, style: leftStyle }, { header: 'Category', key: 'catMain', width: 15, style: centerStyle },
            { header: 'Sub-Cat', key: 'catSub', width: 15, style: centerStyle }, { header: 'Material', key: 'mat', width: 25, style: leftStyle }, 
            { header: 'HS Code', key: 'hs', width: 15, style: centerStyle }, { header: 'L', key: 'l', width: 8, style: centerStyle },
            { header: 'W', key: 'w', width: 8, style: centerStyle }, { header: 'H', key: 'h', width: 8, style: centerStyle },
            { header: 'Pcs/Box', key: 'pcs', width: 8, style: centerStyle }, { header: 'CBM', key: 'cbm', width: 10, style: centerStyle },
            { header: 'G.W', key: 'gw', width: 8, style: centerStyle }, { header: 'Cost (RMB)', key: 'rmb', width: 12, style: centerStyle },
            { header: 'Duty(%)', key: 'tax', width: 8, style: centerStyle }, { header: 'Frt(€)', key: 'frt', width: 10, style: centerStyle },
            { header: 'Landed(€)', key: 'landed', width: 10, style: centerStyle }, { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
          ];
        } else if (exportType === 'quotation') {
          sheet.columns = [
            { header: 'Image', key: 'image', width: 15 }, 
            { header: 'No.', key: 'no', width: 8, style: centerStyle },
            { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
            { header: 'Description', key: 'desc', width: 40, style: leftStyle },
            { header: 'HS Code', key: 'hs', width: 15, style: centerStyle },
            { header: 'Quantity', key: 'qty', width: 12, style: centerStyle },
            { header: 'Unit Price (USD)', key: 'price', width: 15, style: centerStyle },
            { header: 'Total Amount (USD)', key: 'amount', width: 18, style: centerStyle },
          ];
        } else {
           // Packing List
           sheet.columns = [
            { header: 'Image', key: 'image', width: 15 }, { header: 'No.', key: 'no', width: 6, style: centerStyle },
            { header: 'SKU', key: 'sku', width: 15, style: centerStyle }, { header: 'Description', key: 'desc', width: 35, style: leftStyle },
            { header: 'Qty', key: 'qty', width: 10, style: centerStyle }, { header: 'Cartons', key: 'cartons', width: 10, style: centerStyle },
            { header: 'CBM', key: 'totalCbm', width: 12, style: centerStyle }, { header: 'G.W', key: 'totalGw', width: 12, style: centerStyle },
          ];
        }

        sheet.getRow(1).font = { bold: true, size: 12 }; sheet.getRow(1).height = 35; sheet.getRow(1).alignment = centerStyle;

        exportItems.forEach((p, i) => {
           const m = calculateMetrics(p); 
           const rowIndex = i + 2;
           const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
           const tQty = (cQty * p.pcsPerBox) || p.moq || 0; 
           const tCbm = (m.cbm || 0) * cQty; 
           const tGw = (p.gwKg || 15) * cQty; 

           let rowValues = {};

           if (exportType === 'master') {
             rowValues = {
               sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, nameEs: p.nameEs, catMain: p.categoryMain, catSub: p.categorySub, mat: p.materialEn, hs: p.hsCode,
               l: p.boxLength || 0, w: p.boxWidth || 0, h: p.boxHeight || 0, pcs: p.pcsPerBox, cbm: m.cbm, gw: p.gwKg || 0, rmb: p.priceRmb, tax: p.taxRate, frt: m.freightPerPc, landed: m.landedCostEuro, moq: p.moq
             };
           } else if (exportType === 'quotation') {
             const priceUsd = m.priceStockUsd || 0;
             const totalUsd = priceUsd * tQty;
             rowValues = {
                no: i + 1,
                sku: p.sku,
                desc: p.nameEn || p.nameCn,
                hs: p.hsCode,
                qty: tQty,
                price: priceUsd.toFixed(3),
                amount: totalUsd.toFixed(2)
             };
           } else {
             rowValues = { no: i + 1, sku: p.sku, desc: p.nameEn || p.nameCn, qty: tQty, cartons: cQty, totalCbm: tCbm.toFixed(3), totalGw: tGw.toFixed(2) };
           }

           const row = sheet.addRow(rowValues); 
           row.height = 85; 
           row.alignment = centerStyle;
           row.eachCell((cell:any) => { cell.border = borderStyle; });

           if (p.photoUrl && p.photoUrl.startsWith('data:image')) {
             try {
               const parts = p.photoUrl.split(',');
               if (parts.length > 1) {
                 const base64 = parts[1];
                 const imageId = workbook.addImage({ base64: base64, extension: 'jpeg' });
                 sheet.addImage(imageId, { 
                    tl: { col: 0.05, row: rowIndex - 1 + 0.05 }, 
                    br: { col: 0.95, row: rowIndex - 0.05 },
                    editAs: 'twoCell' 
                 });
               }
             } catch (e) { console.warn("Img Export Error, skipping", e); }
           }
        });
    }

    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_Mobile_${exportType}_${Date.now()}.xlsx`);
    setIsSelectMode(false);
    setSelectedIds(new Set());
  };

  // If in List mode (History) - Only show if NOT in Desktop Mode
  if (activeTab === 'list' && !isDesktopMode) {
    return (
      <div className="flex flex-col h-full bg-slate-50 relative">
        {/* EXPORT MENU MODAL */}
        {showExportMenu && (
          <div className="fixed inset-0 z-[60] bg-black/50 backdrop-blur-sm flex items-end justify-center pb-8 animate-in slide-in-from-bottom-10 fade-in">
             <div className="bg-white w-[90%] max-w-sm rounded-2xl p-5 shadow-2xl flex flex-col gap-3">
                 <div className="flex justify-between items-center mb-1">
                    <h3 className="font-bold text-lg text-slate-800">Select Format</h3>
                    <button onClick={() => setShowExportMenu(false)} className="p-1 text-slate-400 hover:text-slate-600"><X size={20}/></button>
                 </div>

                 <button onClick={() => handleExportExcel('master')} className="flex items-center gap-3 p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-indigo-50 hover:border-indigo-200 transition-all text-left group">
                    <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center group-hover:bg-indigo-600 group-hover:text-white transition-colors"><Database size={20}/></div>
                    <div>
                       <div className="font-bold text-slate-800 text-sm">Master Data</div>
                       <div className="text-[10px] text-slate-500">Full details with cost & landed calculations</div>
                    </div>
                 </button>

                 <button onClick={() => handleExportExcel('quotation')} className="flex items-center gap-3 p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-indigo-50 hover:border-indigo-200 transition-all text-left group">
                    <div className="w-10 h-10 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center group-hover:bg-purple-600 group-hover:text-white transition-colors"><FileText size={20}/></div>
                    <div>
                       <div className="font-bold text-slate-800 text-sm">Quotation</div>
                       <div className="text-[10px] text-slate-500">For customers (USD Prices & Images)</div>
                    </div>
                 </button>

                 <button onClick={() => handleExportExcel('packinglist')} className="flex items-center gap-3 p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-indigo-50 hover:border-indigo-200 transition-all text-left group">
                    <div className="w-10 h-10 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-colors"><Package size={20}/></div>
                    <div>
                       <div className="font-bold text-slate-800 text-sm">Packing List</div>
                       <div className="text-[10px] text-slate-500">Logistics, Cartons, CBM & GW</div>
                    </div>
                 </button>

                 <button onClick={() => handleExportExcel('invoice')} className="flex items-center gap-3 p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-indigo-50 hover:border-indigo-200 transition-all text-left group">
                    <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white transition-colors"><Printer size={20}/></div>
                    <div>
                       <div className="font-bold text-slate-800 text-sm">Commercial Invoice</div>
                       <div className="text-[10px] text-slate-500">Formal export document (No Images)</div>
                    </div>
                 </button>
             </div>
          </div>
        )}

        {isEnriching && (
           <div className="absolute inset-0 z-50 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center">
              <RefreshCw className="animate-spin text-indigo-600 mb-4" size={40} />
              <p className="font-bold text-lg text-slate-800">AI Enriching...</p>
              <p className="text-sm text-slate-500 mt-1">{enrichProgress.current} / {enrichProgress.total}</p>
           </div>
        )}

        <div className="px-6 py-4 bg-white shadow-sm z-10 sticky top-0 flex justify-between items-center">
          <div>
              <h2 className="text-xl font-bold text-slate-800 tracking-tight">
                  {isSelectMode ? `Selected (${selectedIds.size})` : `Recent Scans`}
              </h2>
              {!isSelectMode && <p className="text-xs text-slate-500">{products.length} items</p>}
          </div>
          <button 
            onClick={toggleSelectMode}
            className={`text-sm font-medium px-3 py-1.5 rounded-full transition-colors ${isSelectMode ? 'bg-slate-100 text-slate-600' : 'bg-indigo-50 text-indigo-600'}`}
          >
            {isSelectMode ? 'Cancel' : 'Select'}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-32">
          {products.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-400">
               <Box size={32} className="text-slate-300 mb-2" />
               <p className="font-medium">No items yet.</p>
            </div>
          ) : (
            products.map((p) => (
              <div 
                key={p.id} 
                onClick={() => toggleSelectProduct(p.id)}
                className={`bg-white p-3 rounded-xl shadow-sm border flex gap-3 transition-all active:scale-[0.99] ${selectedIds.has(p.id) ? 'border-indigo-400 ring-1 ring-indigo-400 bg-indigo-50/10' : 'border-slate-100'}`}
              >
                {/* Selection Checkbox Area */}
                {isSelectMode && (
                    <div className="flex items-center justify-center pl-1 pr-2">
                        {selectedIds.has(p.id) ? <CheckSquare className="text-indigo-600" size={20} /> : <Square className="text-slate-300" size={20} />}
                    </div>
                )}

                <div className="w-20 h-20 shrink-0 rounded-lg bg-slate-50 overflow-hidden border border-slate-100">
                  {p.photoUrl ? (
                    <img src={p.photoUrl} alt={p.nameCn} className="w-full h-full object-cover" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-slate-300"><ImagePlus size={20}/></div>
                  )}
                </div>
                <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                  <div>
                    <div className="flex justify-between items-start">
                      <h3 className="font-bold text-slate-800 text-sm truncate pr-2">{p.sku}</h3>
                      <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded font-medium">
                        {p.hsCode ? 'HS:OK' : 'No HS'}
                      </span>
                    </div>
                    <p className="text-xs text-slate-500 truncate mt-0.5">{p.nameEn || p.nameCn || "No Name"}</p>
                  </div>
                  <div className="flex justify-between items-end mt-2">
                    <div className="flex items-center gap-2 text-xs text-slate-400">
                       <span className="flex items-center gap-1"><Box size={10}/> {p.pcsPerBox}</span>
                       <span className="flex items-center gap-1"><Store size={10}/> {p.shopNo || "-"}</span>
                    </div>
                    <div className="font-mono font-bold text-indigo-600 text-sm">¥{p.priceRmb}</div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* BOTTOM ACTION BAR (Conditional) */}
        {isSelectMode ? (
            <div className="absolute bottom-0 w-full bg-white border-t border-slate-200 p-4 shadow-lg z-30 flex items-center justify-between gap-3 safe-area-bottom">
                <button 
                  onClick={handleBulkDelete}
                  disabled={selectedIds.size === 0}
                  className="flex flex-col items-center gap-1 text-slate-500 disabled:opacity-30 active:text-red-600"
                >
                    <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center"><Trash2 size={20} /></div>
                    <span className="text-[10px] font-medium">Delete</span>
                </button>

                <button 
                  onClick={handleBulkEnrich}
                  disabled={selectedIds.size === 0}
                  className="flex-1 bg-indigo-600 text-white rounded-xl h-12 flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 active:scale-95 transition-transform disabled:opacity-50 disabled:active:scale-100"
                >
                    <Sparkles size={18} />
                    <span className="font-bold text-sm">AI Enrich ({selectedIds.size})</span>
                </button>

                <button 
                  onClick={() => setShowExportMenu(true)}
                  disabled={selectedIds.size === 0}
                  className="flex flex-col items-center gap-1 text-slate-500 disabled:opacity-30 active:text-green-600"
                >
                    <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center"><Download size={20} /></div>
                    <span className="text-[10px] font-medium">Excel</span>
                </button>
            </div>
        ) : (
            <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-8 flex justify-between items-center z-20">
            <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-slate-400 hover:text-indigo-600 transition-colors">
                <Plus size={24} />
                <span className="text-[10px] font-medium tracking-wide">NEW</span>
            </button>
            <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-indigo-600">
                <Layers size={24} />
                <span className="text-[10px] font-medium tracking-wide">LIST</span>
            </button>
            </nav>
        )}
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-slate-50 relative font-sans">
      {isBatchProcessing && (
        <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center text-indigo-600">
           <div className="relative">
             <div className="absolute inset-0 bg-indigo-200 blur-xl opacity-50 rounded-full animate-pulse"></div>
             <Loader2 className="animate-spin mb-4 relative z-10" size={48} />
           </div>
           <p className="font-bold text-lg text-slate-800">Processing {processingCount.current} / {processingCount.total}</p>
           <p className="text-sm text-indigo-600 font-medium mt-2 flex items-center gap-1">
              <Zap size={14} fill="currentColor"/> Hyper-Batch Active
           </p>
           <p className="text-xs text-slate-400 mt-1">Max Concurrency Enabled</p>
        </div>
      )}

      {/* Header */}
      <div className="bg-white px-6 pt-6 pb-4 shadow-sm border-b border-slate-100 z-10 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-slate-900 tracking-tight">
            {isDesktopMode ? "Add / Batch Upload" : "New Sourcing"}
          </h1>
          <div className="flex items-center gap-1 text-xs font-medium text-indigo-600 mt-0.5">
             <Store size={12} />
             <span>Yiwu District 4</span>
          </div>
        </div>

        {isDesktopMode ? (
          <button onClick={onClose} className="h-8 w-8 rounded-full bg-slate-100 hover:bg-slate-200 flex items-center justify-center transition-colors text-slate-500">
             <X size={18} />
          </button>
        ) : (
          <div className="h-8 w-8 rounded-full bg-indigo-50 flex items-center justify-center border border-indigo-100">
             <Tag size={16} className="text-indigo-600"/>
          </div>
        )}
      </div>

      {/* Form Content */}
      <form onSubmit={handleSubmit} className={`flex-1 overflow-y-auto px-5 py-6 space-y-6 scroll-smooth ${isDesktopMode ? 'pb-6' : 'pb-28'}`}>

        {/* Batch Upload Card */}
        <div className="relative overflow-hidden bg-gradient-to-br from-indigo-600 to-violet-600 rounded-2xl shadow-lg shadow-indigo-200 text-white p-5 transition-transform hover:scale-[1.01] duration-300">
           <div className="relative z-10">
             <div className="flex justify-between items-start mb-3">
               <h3 className="font-bold text-lg flex items-center gap-2">
                 <Layers size={18} /> Quick Batch
               </h3>
               <span className="bg-white/20 px-2 py-0.5 rounded text-[10px] font-medium backdrop-blur-sm">AI Powered</span>
             </div>
             <p className="text-indigo-100 text-xs mb-4 leading-relaxed max-w-[90%]">
               Upload multiple photos (Up to 400). Our AI will search and fill details automatically.
             </p>
             <label className="flex items-center justify-center w-full py-2.5 bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/20 rounded-lg cursor-pointer transition-all active:scale-95">
                <span className="font-semibold text-sm">Select Images</span>
                <input type="file" multiple accept="image/*" onChange={handleBatchSelect} className="hidden" />
             </label>
           </div>
           {/* Decorative Circles */}
           <div className="absolute -top-6 -right-6 w-32 h-32 bg-white/10 rounded-full blur-2xl"></div>
           <div className="absolute bottom-0 left-0 w-24 h-24 bg-indigo-400/20 rounded-full blur-xl"></div>
        </div>

        <div className="flex items-center gap-3 text-xs text-slate-400 font-medium uppercase tracking-wider my-2">
            <div className="h-px bg-slate-200 flex-1"></div>
            <span>Manual Entry</span>
            <div className="h-px bg-slate-200 flex-1"></div>
        </div>

        {/* Photo Section */}
        <div className="space-y-2">
          <label className="text-xs font-semibold text-slate-500 uppercase tracking-wide ml-1">Product Photo</label>
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex gap-4 items-center">
            <div className="relative group shrink-0">
               <div className="w-20 h-20 rounded-xl bg-slate-50 border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden transition-colors group-hover:border-indigo-300">
                  {photoPreview ? (
                    <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <Camera className="text-slate-300 group-hover:text-indigo-400" size={24} />
                  )}
               </div>
               <input type="file" accept="image/*" onChange={handlePhotoSelect} className="absolute inset-0 opacity-0 cursor-pointer" />
            </div>
            <div className="flex-1">
               <h4 className="text-sm font-semibold text-slate-800">Take a photo</h4>
               <p className="text-xs text-slate-500 mt-1">Capture product details clearly.</p>
            </div>
            <div className="h-8 w-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">
               <ChevronRight size={16} />
            </div>
          </div>
        </div>

        {/* Basic Info Group */}
        <div className="space-y-4">
           <div className="relative">
             <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-indigo-600 uppercase">Product Name</label>
             <input 
               type="text" 
               value={nameCn}
               onChange={(e) => setNameCn(e.target.value)}
               placeholder="e.g. Stainless Steel Pot"
               className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all placeholder:text-slate-300 shadow-sm"
             />
           </div>

           <div className="grid grid-cols-2 gap-3">
             <div className="relative">
                <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-slate-400 uppercase">RMB Cost</label>
                <div className="relative">
                  <div className="absolute left-3 top-3.5 text-slate-400"><DollarSign size={14} /></div>
                  <input 
                    type="number" 
                    value={priceRmb}
                    onChange={(e) => setPriceRmb(e.target.value)}
                    placeholder="0.00"
                    className="w-full bg-white border border-slate-200 rounded-xl pl-8 pr-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm"
                    inputMode="decimal"
                  />
                </div>
             </div>
             <div className="relative">
                <label className="absolute -top-2 left-3 bg-slate-50 px-1 text-[10px] font-bold text-slate-400 uppercase">MOQ</label>
                <input 
                  type="number" 
                  value={moq}
                  onChange={(e) => setMoq(e.target.value)}
                  placeholder="PCS"
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm"
                  inputMode="numeric"
                />
             </div>
           </div>

           <div className="relative">
