interface MobileEntryProps {
  onSave: (product: Product) => void;
  onUpdateProduct?: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave, onUpdateProduct, onDeleteProduct, isDesktopMode, onClose, products = [] }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Selection & Action Mode State
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });
  const [showExportMenu, setShowExportMenu] = useState(false);

  // Supplier / Card State (Session Level)
  const [showSupplierForm, setShowSupplierForm] = useState(false);
  const [isProcessingCard, setIsProcessingCard] = useState(false);
  const [currentSupplier, setCurrentSupplier] = useState<SupplierInfo>({
    companyName: "",
    contactPerson: "",
    phone: "",
    address: ""
  });

  // Ref to track if component is mounted
  const isMounted = useRef(true);

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // Quick calculate metrics
  const calculateMetrics = (p: Partial<Product>) => {
    const rate = 7.8; 
    const freight = 150; 
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / 7.2 : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3))
    };
  };

  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;
          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }
          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) { resolve(event.target?.result as string); return; }
          ctx.drawImage(img, 0, 0, width, height);
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
          resolve(dataUrl);
        };
        img.onerror = (err) => reject(err);
      };
      reader.onerror = (err) => reject(err);
    });
  };

  // --- BUSINESS CARD LOGIC ---
  const handleCardCapture = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsProcessingCard(true);
      const file = e.target.files[0];
      try {
        const base64 = await processImageFile(file);
        const info = await analyzeBusinessCard(base64);
        if (isMounted.current) {
          setCurrentSupplier(prev => ({ ...prev, ...info }));
          setShowSupplierForm(true); // Open form to review/edit
        }
      } catch (err) {
        console.error("Card processing failed", err);
        alert("Could not analyze card. Please enter details manually.");
        setShowSupplierForm(true);
      } finally {
        if (isMounted.current) setIsProcessingCard(false);
      }
    }
  };

  // --- PRODUCT LOGIC ---

  const handlePhotoSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const compressedBase64 = await processImageFile(file);
        if (isMounted.current) setPhotoPreview(compressedBase64);
      } catch (e) {
        console.error("Image processing error", e);
      }
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        const CONCURRENCY_LIMIT = 2;
        let processedCount = 0;

        const processFileItem = async (file: File) => {
           try {
             const base64 = await processImageFile(file);
             let aiData;
             try {
                aiData = await analyzeImage(base64);
             } catch (err: any) {
                aiData = { nameCn: "Processing Error", priceRmb: 0, moq: 0, nameEn: "Error", materialEn: "Unknown", hsCode: "", boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0 };
             }

             const partialProduct: Product = {
                id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9),
                sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
                photoUrl: base64,
                supplier: currentSupplier, // ATTACH SESSION SUPPLIER INFO
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn,
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || currentSupplier.address || "TBD",
                hsCode: aiData.hsCode,
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
             };

             const metrics = calculateMetrics(partialProduct);

             if (isMounted.current) {
                onSave({ ...partialProduct, ...metrics });
             }

           } catch (e) {
             console.error("File processing critical error", e);
           } finally {
             processedCount++;
             if (isMounted.current) {
               setProcessingCount(prev => ({ ...prev, current: processedCount }));
             }
           }
        };

        const queue = [...files];
        const workers = Array(Math.min(CONCURRENCY_LIMIT, files.length)).fill(null).map(async () => {
            while (queue.length > 0 && isMounted.current) {
              const file = queue.shift();
              if (file) {
                await processFileItem(file);
                if (isMounted.current) await new Promise(resolve => setTimeout(resolve, 2000));
              }
            }
          });

        await Promise.all(workers);

        if (isMounted.current) {
          await new Promise(resolve => setTimeout(resolve, 500));
          if (isDesktopMode) {
            alert(`Batch Complete!`);
            if (onClose) onClose();
          } else {
            setActiveTab('list');
          }
        }

      } catch (error) {
        console.error("Batch error:", error);
      } finally {
        if (isMounted.current) setIsBatchProcessing(false);
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => { setBoxDims('60x40x50'); setPcsPerBox('120'); };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0; const w = parts[1] || 0; const h = parts[2] || 0;

    const partialProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      supplier: currentSupplier, // ATTACH SESSION SUPPLIER INFO
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l,
      boxWidth: w,
      boxHeight: h,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    const metrics = calculateMetrics(partialProduct);
    onSave({ ...partialProduct, ...metrics });

    setNameCn(''); setPriceRmb(''); setMoq(''); setBoxDims(''); setPcsPerBox(''); setPhotoPreview(null);
    if (isDesktopMode) { alert("Saved!"); if(onClose) onClose(); } else { alert("Saved!"); }
  };

  // --- EXPORT LOGIC (EXCEL & PDF) ---

  const getExportFileName = (type: string, products: Product[]) => {
    // Try to find the first supplier info from selected products
    const supplierName = products.find(p => p.supplier?.companyName)?.supplier?.companyName || "Unknown";
    const dateStr = new Date().toISOString().slice(0, 10);
    return `${supplierName}_${type}_${dateStr}`;
  };

  const getExportHeaderInfo = (products: Product[]) => {
     // Use first valid supplier info found in batch
     const s = products.find(p => p.supplier?.companyName)?.supplier || { companyName: "Unknown Supplier", contactPerson: "", phone: "", address: "" };
     return s;
  };

  const handleExport = async (format: 'excel' | 'pdf', exportType: 'master' | 'packinglist' | 'invoice' | 'quotation') => {
    if (selectedIds.size === 0) return alert("Select items.");
    const exportItems = products.filter(p => selectedIds.has(p.id));
    const headerInfo = getExportHeaderInfo(exportItems);
    const fileName = getExportFileName(exportType, exportItems);
    setShowExportMenu(false);

    if (format === 'excel') {
        if (typeof ExcelJS === 'undefined') return alert("ExcelJS missing");
        const workbook = new ExcelJS.Workbook();
        const sheet = workbook.addWorksheet('Sheet1');

        // Styles
        const center = { vertical: 'middle', horizontal: 'center', wrapText: true };
        const border = { top: {style:'thin'}, left: {style:'thin'}, bottom: {style:'thin'}, right: {style:'thin'} };

        // --- MASTER TABLE: NO HEADER INFO, JUST DATA ---
        if (exportType === 'master') {
             sheet.columns = [
                { header: 'Image', key: 'image', width: 15 }, { header: 'SKU', key: 'sku', width: 15, style: center },
                { header: 'Name (CN)', key: 'nameCn', width: 25 }, { header: 'Name (EN)', key: 'nameEn', width: 25 },
                { header: 'Material', key: 'mat', width: 20 }, { header: 'HS', key: 'hs', width: 15, style: center },
                { header: 'L', key: 'l', width: 8 }, { header: 'W', key: 'w', width: 8 }, { header: 'H', key: 'h', width: 8 },
                { header: 'Pcs', key: 'pcs', width: 8 }, { header: 'CBM', key: 'cbm', width: 10 }, { header: 'RMB', key: 'rmb', width: 10 }
             ];
             sheet.getRow(1).font = { bold: true };

             exportItems.forEach((p, i) => {
                 const m = calculateMetrics(p);
                 const row = sheet.addRow({
                     sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, mat: p.materialEn, hs: p.hsCode,
                     l: p.boxLength, w: p.boxWidth, h: p.boxHeight, pcs: p.pcsPerBox, cbm: m.cbm, rmb: p.priceRmb
                 });
                 row.height = 80;
                 row.eachCell((c:any) => c.border = border);
                 if (p.photoUrl?.startsWith('data:image')) {
                     const imgId = workbook.addImage({ base64: p.photoUrl.split(',')[1], extension: 'jpeg' });
                     sheet.addImage(imgId, { tl: { col: 0.1, row: i + 1.1 }, br: { col: 0.9, row: i + 1.9 }, editAs: 'twoCell' });
                 }
             });

        } else {
             // --- QUOTE / INVOICE / PACKING: ADD HEADER INFO ---

             // Add Header Rows
             sheet.mergeCells('A1:H1'); sheet.getCell('A1').value = headerInfo.companyName; 
             sheet.getCell('A1').font = { bold: true, size: 16 }; sheet.getCell('A1').alignment = center;

             sheet.mergeCells('A2:H2'); sheet.getCell('A2').value = `Contact: ${headerInfo.contactPerson}  Phone: ${headerInfo.phone}`;
             sheet.getCell('A2').alignment = center;

             sheet.mergeCells('A3:H3'); sheet.getCell('A3').value = `Address: ${headerInfo.address}`;
             sheet.getCell('A3').alignment = center;

             sheet.mergeCells('A4:H4'); sheet.getCell('A4').value = exportType.toUpperCase();
             sheet.getCell('A4').font = { bold: true, size: 14, underline: true }; sheet.getCell('A4').alignment = center;

             // Columns Setup based on Type
             let columns: any[] = [];
             if (exportType === 'quotation') {
                 columns = ['Image', 'No.', 'SKU', 'Description', 'Qty', 'Unit Price ($)', 'Total ($)', 'HS Code'];
             } else if (exportType === 'invoice') {
                 columns = ['No.', 'SKU', 'Description', 'Qty', 'Unit Price ($)', 'Total ($)', 'N.W(kg)', 'G.W(kg)'];
             } else {
                 columns = ['Image', 'No.', 'SKU', 'Description', 'Qty', 'Ctns', 'CBM', 'G.W(kg)'];
             }

             const headerRow = sheet.getRow(6);
             headerRow.values = columns;
             headerRow.font = { bold: true }; headerRow.alignment = center;
             headerRow.eachCell((c:any) => { c.border = border; c.fill = {type:'pattern', pattern:'solid', fgColor:{argb:'FFE0E0E0'}}; });

             // Data Rows
             exportItems.forEach((p, i) => {
                 const m = calculateMetrics(p);
                 const rowIndex = i + 7;
                 const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
                 const tQty = (cQty * p.pcsPerBox) || p.moq || 0;
                 const tGw = (p.gwKg || 15) * cQty;
                 const tCbm = (m.cbm || 0) * cQty;
                 const priceUsd = m.priceStockUsd || 0;

                 let rowData: any[] = [];
                 if (exportType === 'quotation') {
                     rowData = ['', i+1, p.sku, p.nameEn||p.nameCn, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2), p.hsCode];
                 } else if (exportType === 'invoice') {
                     rowData = [i+1, p.sku, p.nameEn||p.nameCn, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2), (tGw*0.9).toFixed(2), tGw.toFixed(2)];
                 } else {
                     rowData = ['', i+1, p.sku, p.nameEn||p.nameCn, tQty, cQty, tCbm.toFixed(3), tGw.toFixed(2)];
                 }

                 const row = sheet.getRow(rowIndex);
                 row.values = rowData;
                 row.height = 80;
                 row.alignment = center;
                 row.eachCell((c:any) => c.border = border);

                 // Add Image (except for pure text Invoice if desired, but user asked for functionality)
                 // For Invoice often no image, but we will add if column 1 is Image
                 if (columns[0] === 'Image' && p.photoUrl?.startsWith('data:image')) {
                    const imgId = workbook.addImage({ base64: p.photoUrl.split(',')[1], extension: 'jpeg' });
                    sheet.addImage(imgId, { tl: { col: 0.1, row: rowIndex - 1 + 0.1 }, br: { col: 0.9, row: rowIndex - 0.1 }, editAs: 'twoCell' });
                 }
             });
        }

        const buffer = await workbook.xlsx.writeBuffer();
        saveAs(new Blob([buffer]), `${fileName}.xlsx`);

    } else if (format === 'pdf') {
        // --- PDF EXPORT (jsPDF + autoTable) ---
        if (typeof jspdf === 'undefined') return alert("jsPDF library missing");

        const doc = new jspdf.jsPDF();

        // Add Header for Non-Master
        let startY = 15;
        if (exportType !== 'master') {
            doc.setFontSize(16); doc.setFont("helvetica", "bold");
            doc.text(headerInfo.companyName, 105, 15, { align: 'center' });

            doc.setFontSize(10); doc.setFont("helvetica", "normal");
            doc.text(`Contact: ${headerInfo.contactPerson}   Phone: ${headerInfo.phone}`, 105, 22, { align: 'center' });
            doc.text(headerInfo.address, 105, 27, { align: 'center' });

            doc.setLineWidth(0.5); doc.line(20, 30, 190, 30);

            doc.setFontSize(14); doc.setFont("helvetica", "bold");
            doc.text(exportType.toUpperCase(), 105, 40, { align: 'center' });
            startY = 45;
        }

        // Prepare Table Data
        const head = [];
        const body = [];

        if (exportType === 'quotation') {
            head.push(['No.', 'SKU', 'Description', 'Qty', 'Unit($)', 'Total($)']);
        } else if (exportType === 'invoice') {
             head.push(['No.', 'SKU', 'Description', 'Qty', 'Unit($)', 'Total($)', 'G.W']);
        } else if (exportType === 'packinglist') {
             head.push(['No.', 'SKU', 'Description', 'Qty', 'Ctns', 'CBM', 'G.W']);
        } else {
             head.push(['SKU', 'Name', 'Mat.', 'HS', 'L*W*H', 'Pcs', 'RMB']);
        }

        exportItems.forEach((p, i) => {
            const m = calculateMetrics(p);
            const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
            const tQty = (cQty * p.pcsPerBox) || p.moq || 0;
            const priceUsd = m.priceStockUsd || 0;
            const desc = p.nameEn || p.nameCn || "Item"; // PDF basic font doesn't support Chinese well without custom font

            if (exportType === 'quotation') {
                body.push([i+1, p.sku, desc, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2)]);
            } else if (exportType === 'invoice') {
                body.push([i+1, p.sku, desc, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2), ((p.gwKg||15)*cQty).toFixed(2)]);
            } else if (exportType === 'packinglist') {
                body.push([i+1, p.sku, desc, tQty, cQty, (m.cbm||0 * cQty).toFixed(3), ((p.gwKg||15)*cQty).toFixed(2)]);
            } else {
                body.push([p.sku, desc, p.materialEn||"-", p.hsCode||"-", `${p.boxLength}x${p.boxWidth}x${p.boxHeight}`, p.pcsPerBox, p.priceRmb]);
            }
        });

        // @ts-ignore
        doc.autoTable({
            startY: startY,
            head: head,
            body: body,
            theme: 'grid',
            headStyles: { fillColor: [66, 66, 66] },
            styles: { fontSize: 9 },
        });

        doc.save(`${fileName}.pdf`);
    }
  };

  // ----------------------------------------------------------------------------------

  // If in List mode (History)
  if (activeTab === 'list' && !isDesktopMode) {
    return (
      <div className="flex flex-col h-full bg-slate-50 relative">
        {/* EXPORT MENU MODAL */}
        {showExportMenu && (
          <div className="fixed inset-0 z-[60] bg-black/50 backdrop-blur-sm flex items-end justify-center pb-8 animate-in slide-in-from-bottom-10 fade-in">
             <div className="bg-white w-[90%] max-w-sm rounded-2xl p-5 shadow-2xl flex flex-col gap-3">
                 <div className="flex justify-between items-center mb-3 border-b border-slate-100 pb-2">
                    <h3 className="font-bold text-lg text-slate-800">Export Options</h3>
                    <button onClick={() => setShowExportMenu(false)} className="p-1 text-slate-400 hover:text-slate-600"><X size={20}/></button>
                 </div>

                 <div className="space-y-2">
                    <p className="text-xs font-bold text-slate-400 uppercase">Format</p>
                    <div className="grid grid-cols-2 gap-2">
                        {/* Format selection is implicit in buttons below for simplicity in this specific UI update */}
                    </div>
                 </div>

                 {['master', 'quotation', 'packinglist', 'invoice'].map((type) => (
                   <div key={type} className="flex gap-2">
                       {/* Excel Button */}
                       <button onClick={() => handleExport('excel', type as any)} className="flex-1 flex items-center gap-3 p-3 rounded-xl border border-slate-100 bg-slate-50 hover:bg-green-50 hover:border-green-200 transition-all text-left">
                          <div className="w-8 h-8 rounded-full bg-green-100 text-green-600 flex items-center justify-center"><Database size={16}/></div>
                          <div>
                             <div className="font-bold text-slate-800 text-sm capitalize">{type} .xlsx</div>
                          </div>
                       </button>
                       {/* PDF Button (Not for Master) */}
                       {type !== 'master' && (
                           <button onClick={() => handleExport('pdf', type as any)} className="w-16 flex items-center justify-center rounded-xl border border-slate-100 bg-slate-50 hover:bg-red-50 hover:border-red-200 transition-all text-red-500">
                              <FileText size={20}/>
                           </button>
                       )}
                   </div>
                 ))}
             </div>
          </div>
        )}

        {isEnriching && (
           <div className="absolute inset-0 z-50 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center">
              <RefreshCw className="animate-spin text-indigo-600 mb-4" size={40} />
              <p className="font-bold text-lg text-slate-800">AI Enriching...</p>
              <p className="text-sm text-slate-500 mt-1">{enrichProgress.current} / {enrichProgress.total}</p>
           </div>
        )}

        <div className="px-6 py-4 bg-white shadow-sm z-10 sticky top-0 flex justify-between items-center">
          <div>
              <h2 className="text-xl font-bold text-slate-800 tracking-tight">
                  {isSelectMode ? `Selected (${selectedIds.size})` : `History`}
              </h2>
              {!isSelectMode && <p className="text-xs text-slate-500">{products.length} items recorded</p>}
          </div>
          <button onClick={() => { if(isSelectMode) setSelectedIds(new Set()); setIsSelectMode(!isSelectMode); }} className={`text-sm font-medium px-3 py-1.5 rounded-full transition-colors ${isSelectMode ? 'bg-slate-100 text-slate-600' : 'bg-indigo-50 text-indigo-600'}`}>
            {isSelectMode ? 'Cancel' : 'Select'}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-32">
          {products.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-400"><Box size={32} className="text-slate-300 mb-2" /><p className="font-medium">No items yet.</p></div>
          ) : (
            products.map((p) => (
              <div key={p.id} onClick={() => isSelectMode && (() => { const s = new Set(selectedIds); if(s.has(p.id)) s.delete(p.id); else s.add(p.id); setSelectedIds(s); })()} className={`bg-white p-3 rounded-xl shadow-sm border flex gap-3 transition-all ${selectedIds.has(p.id) ? 'border-indigo-400 ring-1 ring-indigo-400 bg-indigo-50/10' : 'border-slate-100'}`}>
                {isSelectMode && (<div className="flex items-center justify-center pl-1 pr-2">{selectedIds.has(p.id) ? <CheckSquare className="text-indigo-600" size={20} /> : <Square className="text-slate-300" size={20} />}</div>)}
                <div className="w-20 h-20 shrink-0 rounded-lg bg-slate-50 overflow-hidden border border-slate-100">
                  {p.photoUrl ? <img src={p.photoUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><ImagePlus size={20}/></div>}
                </div>
                <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                  <div>
                    <div className="flex justify-between items-start">
                      <h3 className="font-bold text-slate-800 text-sm truncate pr-2">{p.sku}</h3>
                      {p.supplier?.companyName && <span className="text-[9px] bg-slate-100 px-1 rounded text-slate-500 truncate max-w-[80px]">{p.supplier.companyName}</span>}
                    </div>
                    <p className="text-xs text-slate-500 truncate mt-0.5">{p.nameEn || p.nameCn}</p>
                  </div>
                  <div className="flex justify-between items-end mt-2">
                    <div className="font-mono font-bold text-indigo-600 text-sm">¥{p.priceRmb}</div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* BOTTOM ACTION BAR */}
        {isSelectMode ? (
            <div className="absolute bottom-0 w-full bg-white border-t border-slate-200 p-4 shadow-lg z-30 flex items-center justify-between gap-3 safe-area-bottom">
                <button onClick={() => onDeleteProduct && onDeleteProduct(Array.from(selectedIds))} className="flex flex-col items-center gap-1 text-slate-500 active:text-red-600"><div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center"><Trash2 size={20} /></div></button>
                <button onClick={handleBulkEnrich} className="flex-1 bg-indigo-600 text-white rounded-xl h-12 flex items-center justify-center gap-2 shadow-lg"><Sparkles size={18} /><span className="font-bold text-sm">AI Enrich</span></button>
                <button onClick={() => setShowExportMenu(true)} className="flex flex-col items-center gap-1 text-slate-500 active:text-green-600"><div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center"><Download size={20} /></div></button>
            </div>
        ) : (
            <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-12 flex justify-between items-center z-20">
              <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-indigo-600"><Plus size={24} strokeWidth={2.5} /><span className="text-[10px] font-bold tracking-wide">NEW</span></button>
              <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-slate-300 hover:text-slate-500"><Layers size={24} /><span className="text-[10px] font-bold tracking-wide">LIST</span></button>
            </nav>
        )}
      </div>
    );
  }

  // --- NEW SOURCING FORM ---
  return (
    <div className="flex flex-col h-full bg-slate-50 relative font-sans">

      {/* HEADER: SUPPLIER INFO SECTION */}
      <div className="bg-white border-b border-slate-100 z-20 sticky top-0">
          <div className="px-6 pt-6 pb-2 flex justify-between items-center">
            <h1 className="text-xl font-bold text-slate-900">{isDesktopMode ? "Add Product" : "New Sourcing"}</h1>
            {isDesktopMode && <button onClick={onClose}><X size={18} /></button>}
          </div>

          {/* Supplier Info Toggle/Card */}
          <div className="px-6 pb-4">
             {showSupplierForm ? (
                <div className="bg-slate-50 border border-slate-200 rounded-xl p-3 space-y-3 animate-in fade-in slide-in-from-top-2">
                   <div className="flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-400 uppercase">Session Header Info</span>
                      <button onClick={() => setShowSupplierForm(false)} className="text-indigo-600 text-xs font-medium">Done</button>
                   </div>
                   <input placeholder="Company Name" className="w-full text-sm p-2 border rounded" value={currentSupplier.companyName} onChange={e => setCurrentSupplier({...currentSupplier, companyName: e.target.value})} />
                   <div className="flex gap-2">
                      <input placeholder="Contact Person" className="flex-1 text-sm p-2 border rounded" value={currentSupplier.contactPerson} onChange={e => setCurrentSupplier({...currentSupplier, contactPerson: e.target.value})} />
                      <input placeholder="Phone" className="flex-1 text-sm p-2 border rounded" value={currentSupplier.phone} onChange={e => setCurrentSupplier({...currentSupplier, phone: e.target.value})} />
                   </div>
                   <input placeholder="Address" className="w-full text-sm p-2 border rounded" value={currentSupplier.address} onChange={e => setCurrentSupplier({...currentSupplier, address: e.target.value})} />
                </div>
             ) : (
                <div className="flex items-center justify-between bg-white border border-dashed border-slate-300 rounded-xl p-2.5">
                   <div className="flex items-center gap-3 overflow-hidden">
                      <div className="w-10 h-10 rounded-full bg-indigo-50 flex items-center justify-center text-indigo-600 shrink-0">
                         {isProcessingCard ? <Loader2 className="animate-spin" size={18}/> : <Contact size={18}/>}
                      </div>
                      <div className="min-w-0">
                         <div className="text-sm font-bold text-slate-800 truncate">{currentSupplier.companyName || "No Header Info"}</div>
                         <div className="text-xs text-slate-500 truncate">{currentSupplier.contactPerson || "Tap to scan card or add info"}</div>
                      </div>
                   </div>

                   <div className="flex items-center gap-2">
                      <label className="p-2 bg-slate-100 rounded-full text-slate-600 active:bg-slate-200 cursor-pointer">
                         <Camera size={18} />
                         <input type="file" accept="image/*" className="hidden" onChange={handleCardCapture} />
                      </label>
                      <button onClick={() => setShowSupplierForm(true)} className="p-2 bg-slate-100 rounded-full text-slate-600 active:bg-slate-200">
                         <Briefcase size={18} />
                      </button>
                   </div>
                </div>
             )}
          </div>
      </div>

      {isBatchProcessing && (
        <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center text-indigo-600">
           <Loader2 className="animate-spin mb-4" size={48} />
           <p className="font-bold text-lg text-slate-800">Processing {processingCount.current} / {processingCount.total}</p>
        </div>
      )}

      {/* Main Form */}
      <form onSubmit={handleSubmit} className={`flex-1 overflow-y-auto px-5 py-6 space-y-6 scroll-smooth ${isDesktopMode ? 'pb-6' : 'pb-28'}`}>

        {/* Batch Upload */}
        <div className="relative overflow-hidden bg-gradient-to-br from-indigo-600 to-violet-600 rounded-2xl shadow-lg p-5 text-white">
           <h3 className="font-bold text-lg flex items-center gap-2 mb-3"><Layers size={18} /> Quick Batch</h3>
           <p className="text-indigo-100 text-xs mb-4">Upload multiple photos. Auto-link to above header.</p>
           <label className="flex items-center justify-center w-full py-2.5 bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/20 rounded-lg cursor-pointer">
              <span className="font-semibold text-sm">Select Images</span>
              <input type="file" multiple accept="image/*" onChange={handleBatchSelect} className="hidden" />
           </label>
        </div>

        <div className="flex items-center gap-3 text-xs text-slate-400 font-medium uppercase tracking-wider my-2">
            <div className="h-px bg-slate-200 flex-1"></div><span>Manual Entry</span><div className="h-px bg-slate-200 flex-1"></div>
        </div>

        {/* Photo Input */}
        <div className="space-y-2">
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex gap-4 items-center">
            <div className="relative group shrink-0">
               <div className="w-20 h-20 rounded-xl bg-slate-50 border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden">
                  {photoPreview ? <img src={photoPreview} className="w-full h-full object-cover" /> : <Camera className="text-slate-300" size={24} />}
               </div>
               <input type="file" accept="image/*" onChange={handlePhotoSelect} className="absolute inset-0 opacity-0 cursor-pointer" />
            </div>
            <div className="flex-1">
               <h4 className="text-sm font-semibold text-slate-800">Product Photo</h4>
               <p className="text-xs text-slate-500 mt-1">Capture details clearly.</p>
            </div>
          </div>
        </div>

        {/* Fields */}
        <div className="space-y-4">
           <div>
             <label className="text-xs font-bold text-indigo-600 uppercase ml-1">Product Name</label>
             <input type="text" value={nameCn} onChange={(e) => setNameCn(e.target.value)} className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm" placeholder="e.g. Toy Car" />
           </div>
           <div className="grid grid-cols-2 gap-3">
             <div><label className="text-xs font-bold text-slate-400 uppercase ml-1">RMB Cost</label><input type="number" value={priceRmb} onChange={(e) => setPriceRmb(e.target.value)} className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm" placeholder="0.00" /></div>
             <div><label className="text-xs font-bold text-slate-400 uppercase ml-1">MOQ</label><input type="number" value={moq} onChange={(e) => setMoq(e.target.value)} className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm" placeholder="PCS" /></div>
           </div>
        </div>

        {/* Logistics */}
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 space-y-4">
          <div className="flex justify-between items-center pb-2 border-b border-slate-50">
             <h3 className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1"><Package size={14} /> Packing</h3>
             <button type="button" onClick={handleSimulateOCR} className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded">Auto-Detect</button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div><label className="block text-[10px] text-slate-400 mb-1">Box (LxWxH)</label><input type="text" value={boxDims} onChange={(e) => setBoxDims(e.target.value)} placeholder="60*40*50" className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm" /></div>
             <div><label className="block text-[10px] text-slate-400 mb-1">Pcs/Ctn</label><input type="number" value={pcsPerBox} onChange={(e) => setPcsPerBox(e.target.value)} placeholder="120" className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm" /></div>
          </div>
        </div>

        {isDesktopMode && <button onClick={handleSubmit} className="w-full bg-slate-900 text-white rounded-xl py-3 shadow-lg flex items-center justify-center gap-2 font-bold text-sm mt-4"><Save size={18} /> SAVE</button>}
      </form>

      {!isDesktopMode && (
        <div className="absolute bottom-24 left-0 right-0 px-6 z-20 pointer-events-none">
           <button onClick={handleSubmit} className="w-full pointer-events-auto bg-slate-900 text-white rounded-xl py-3.5 shadow-xl flex items-center justify-center gap-2 font-bold text-sm active:scale-[0.98] transition-all hover:bg-slate-800"><Save size={18} /> SAVE PRODUCT</button>
        </div>
      )}

      {!isDesktopMode && (
        <nav className="glass-nav absolute bottom-0 w-full pb-6 pt-4 px-12 flex justify-between items-center z-30">
          <button onClick={() => setActiveTab('new')} className="flex flex-col items-center gap-1 text-indigo-600"><Plus size={24} strokeWidth={2.5} /><span className="text-[10px] font-bold tracking-wide">NEW</span></button>
          <button onClick={() => setActiveTab('list')} className="flex flex-col items-center gap-1 text-slate-300 hover:text-slate-500"><Layers size={24} /><span className="text-[10px] font-bold tracking-wide">LIST</span></button>
        </nav>
      )}
    </div>
  );
};

export default MobileEntry;

import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft, CheckSquare, Square, Trash2, Sparkles, Download, RefreshCw, FileText, Database, Printer, Contact, UserCircle, Briefcase } from 'lucide-react';
import { Product, ProcessingStatus, SupplierInfo } from '../types';
import { analyzeImage, enrichProductData, analyzeBusinessCard } from '../services/geminiService';

// Declare globals for CDN libraries
declare const ExcelJS: any;
declare const saveAs: any;
declare const jspdf: any;

const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832",
};

interface MobileEntryProps {
  onSave: (product: Product) => void;
  onUpdateProduct?: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
}

const MobileEntry: React.FC<MobileEntryProps> = ({ onSave, onUpdateProduct, onDeleteProduct, isDesktopMode, onClose, products = [] }) => {
  const [activeTab, setActiveTab] = useState<'new' | 'list'>('new');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [processingCount, setProcessingCount] = useState({ current: 0, total: 0 });

  // Selection & Action Mode State
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });
  const [showExportMenu, setShowExportMenu] = useState(false);

  // Supplier / Card State (Session Level)
  const [showSupplierForm, setShowSupplierForm] = useState(false);
  const [isProcessingCard, setIsProcessingCard] = useState(false);
  const [currentSupplier, setCurrentSupplier] = useState<SupplierInfo>({
    companyName: "",
    contactPerson: "",
    phone: "",
    address: ""
  });

  // Ref to track if component is mounted
  const isMounted = useRef(true);

  // Form State
  const [nameCn, setNameCn] = useState('');
  const [priceRmb, setPriceRmb] = useState('');
  const [moq, setMoq] = useState('');
  const [shopNo, setShopNo] = useState('');
  const [boxDims, setBoxDims] = useState(''); 
  const [pcsPerBox, setPcsPerBox] = useState('');
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // Quick calculate metrics
  const calculateMetrics = (p: Partial<Product>) => {
    const rate = 7.8; 
    const freight = 150; 
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const cbf = cbm * 35.315;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / 7.2 : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      cbf: Number(cbf.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3))
    };
  };

  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;
          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }
          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) { resolve(event.target?.result as string); return; }
          ctx.drawImage(img, 0, 0, width, height);
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
          resolve(dataUrl);
        };
        img.onerror = (err) => reject(err);
      };
      reader.onerror = (err) => reject(err);
    });
  };

  // --- BUSINESS CARD LOGIC ---
  const handleCardCapture = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsProcessingCard(true);
      const file = e.target.files[0];
      try {
        const base64 = await processImageFile(file);
        const info = await analyzeBusinessCard(base64);
        if (isMounted.current) {
          setCurrentSupplier(prev => ({ ...prev, ...info }));
          setShowSupplierForm(true); // Open form to review/edit
        }
      } catch (err) {
        console.error("Card processing failed", err);
        alert("Could not analyze card. Please enter details manually.");
        setShowSupplierForm(true);
      } finally {
        if (isMounted.current) setIsProcessingCard(false);
      }
    }
  };

  // --- PRODUCT LOGIC ---

  const handlePhotoSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const compressedBase64 = await processImageFile(file);
        if (isMounted.current) setPhotoPreview(compressedBase64);
      } catch (e) {
        console.error("Image processing error", e);
      }
    }
  };

  const handleBatchSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setIsBatchProcessing(true);
      setProcessingCount({ current: 0, total: files.length });

      try {
        const CONCURRENCY_LIMIT = 2;
        let processedCount = 0;

        const processFileItem = async (file: File) => {
           try {
             const base64 = await processImageFile(file);
             let aiData;
             try {
                aiData = await analyzeImage(base64);
             } catch (err: any) {
                aiData = { nameCn: "Processing Error", priceRmb: 0, moq: 0, nameEn: "Error", materialEn: "Unknown", hsCode: "", boxLength: 0, boxWidth: 0, boxHeight: 0, pcsPerBox: 0 };
             }

             const partialProduct: Product = {
                id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 9),
                sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
                photoUrl: base64,
                supplier: currentSupplier, // ATTACH SESSION SUPPLIER INFO
                nameCn: aiData.nameCn,
                nameEn: aiData.nameEn,
                materialEn: aiData.materialEn,
                priceRmb: aiData.priceRmb,
                moq: aiData.moq,
                shopNo: shopNo || currentSupplier.address || "TBD",
                hsCode: aiData.hsCode,
                boxLength: aiData.boxLength,
                boxWidth: aiData.boxWidth,
                boxHeight: aiData.boxHeight,
                pcsPerBox: aiData.pcsPerBox,
                status: ProcessingStatus.DRAFT,
                timestamp: Date.now()
             };

             const metrics = calculateMetrics(partialProduct);

             if (isMounted.current) {
                onSave({ ...partialProduct, ...metrics });
             }

           } catch (e) {
             console.error("File processing critical error", e);
           } finally {
             processedCount++;
             if (isMounted.current) {
               setProcessingCount(prev => ({ ...prev, current: processedCount }));
             }
           }
        };

        const queue = [...files];
        const workers = Array(Math.min(CONCURRENCY_LIMIT, files.length)).fill(null).map(async () => {
            while (queue.length > 0 && isMounted.current) {
              const file = queue.shift();
              if (file) {
                await processFileItem(file);
                if (isMounted.current) await new Promise(resolve => setTimeout(resolve, 2000));
              }
            }
          });

        await Promise.all(workers);

        if (isMounted.current) {
          await new Promise(resolve => setTimeout(resolve, 500));
          if (isDesktopMode) {
            alert(`Batch Complete!`);
            if (onClose) onClose();
          } else {
            setActiveTab('list');
          }
        }

      } catch (error) {
        console.error("Batch error:", error);
      } finally {
        if (isMounted.current) setIsBatchProcessing(false);
        e.target.value = '';
      }
    }
  };

  const handleSimulateOCR = () => { setBoxDims('60x40x50'); setPcsPerBox('120'); };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanDims = boxDims.replace(/[xX*]/g, ' ').replace(/\s+/g, ' ').trim();
    const parts = cleanDims.split(' ').map(Number);
    const l = parts[0] || 0; const w = parts[1] || 0; const h = parts[2] || 0;

    const partialProduct: Product = {
      id: Date.now().toString(),
      sku: `YIWU-${Math.floor(Math.random() * 10000)}`,
      photoUrl: photoPreview || `https://picsum.photos/200/200?random=${Date.now()}`,
      supplier: currentSupplier, // ATTACH SESSION SUPPLIER INFO
      nameCn,
      priceRmb: Number(priceRmb) || 0,
      moq: Number(moq) || 0,
      shopNo,
      boxLength: l,
      boxWidth: w,
      boxHeight: h,
      pcsPerBox: Number(pcsPerBox) || 0,
      status: ProcessingStatus.DRAFT,
      timestamp: Date.now()
    };

    const metrics = calculateMetrics(partialProduct);
    onSave({ ...partialProduct, ...metrics });

    setNameCn(''); setPriceRmb(''); setMoq(''); setBoxDims(''); setPcsPerBox(''); setPhotoPreview(null);
    if (isDesktopMode) { alert("Saved!"); if(onClose) onClose(); } else { alert("Saved!"); }
  };

  // --- EXPORT LOGIC (EXCEL & PDF) ---

  const getExportFileName = (type: string, products: Product[]) => {
    // Try to find the first supplier info from selected products
    const supplierName = products.find(p => p.supplier?.companyName)?.supplier?.companyName || "Unknown";
    const dateStr = new Date().toISOString().slice(0, 10);
    return `${supplierName}_${type}_${dateStr}`;
  };

  const getExportHeaderInfo = (products: Product[]) => {
     // Use first valid supplier info found in batch
     const s = products.find(p => p.supplier?.companyName)?.supplier || { companyName: "Unknown Supplier", contactPerson: "", phone: "", address: "" };
     return s;
  };

  const handleExport = async (format: 'excel' | 'pdf', exportType: 'master' | 'packinglist' | 'invoice' | 'quotation') => {
    if (selectedIds.size === 0) return alert("Select items.");
    const exportItems = products.filter(p => selectedIds.has(p.id));
    const headerInfo = getExportHeaderInfo(exportItems);
    const fileName = getExportFileName(exportType, exportItems);
    setShowExportMenu(false);

    if (format === 'excel') {
        if (typeof ExcelJS === 'undefined') return alert("ExcelJS missing");
        const workbook = new ExcelJS.Workbook();
        const sheet = workbook.addWorksheet('Sheet1');

        // Styles
        const center = { vertical: 'middle', horizontal: 'center', wrapText: true };
        const border = { top: {style:'thin'}, left: {style:'thin'}, bottom: {style:'thin'}, right: {style:'thin'} };

        // --- MASTER TABLE: NO HEADER INFO, JUST DATA ---
        if (exportType === 'master') {
             sheet.columns = [
                { header: 'Image', key: 'image', width: 15 }, { header: 'SKU', key: 'sku', width: 15, style: center },
                { header: 'Name (CN)', key: 'nameCn', width: 25 }, { header: 'Name (EN)', key: 'nameEn', width: 25 },
                { header: 'Material', key: 'mat', width: 20 }, { header: 'HS', key: 'hs', width: 15, style: center },
                { header: 'L', key: 'l', width: 8 }, { header: 'W', key: 'w', width: 8 }, { header: 'H', key: 'h', width: 8 },
                { header: 'Pcs', key: 'pcs', width: 8 }, { header: 'CBM', key: 'cbm', width: 10 }, { header: 'RMB', key: 'rmb', width: 10 }
             ];
             sheet.getRow(1).font = { bold: true };

             exportItems.forEach((p, i) => {
                 const m = calculateMetrics(p);
                 const row = sheet.addRow({
                     sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, mat: p.materialEn, hs: p.hsCode,
                     l: p.boxLength, w: p.boxWidth, h: p.boxHeight, pcs: p.pcsPerBox, cbm: m.cbm, rmb: p.priceRmb
                 });
                 row.height = 80;
                 row.eachCell((c:any) => c.border = border);
                 if (p.photoUrl?.startsWith('data:image')) {
                     const imgId = workbook.addImage({ base64: p.photoUrl.split(',')[1], extension: 'jpeg' });
                     sheet.addImage(imgId, { tl: { col: 0.1, row: i + 1.1 }, br: { col: 0.9, row: i + 1.9 }, editAs: 'twoCell' });
                 }
             });

        } else {
             // --- QUOTE / INVOICE / PACKING: ADD HEADER INFO ---

             // Add Header Rows
             sheet.mergeCells('A1:H1'); sheet.getCell('A1').value = headerInfo.companyName; 
             sheet.getCell('A1').font = { bold: true, size: 16 }; sheet.getCell('A1').alignment = center;

             sheet.mergeCells('A2:H2'); sheet.getCell('A2').value = `Contact: ${headerInfo.contactPerson}  Phone: ${headerInfo.phone}`;
             sheet.getCell('A2').alignment = center;

             sheet.mergeCells('A3:H3'); sheet.getCell('A3').value = `Address: ${headerInfo.address}`;
             sheet.getCell('A3').alignment = center;

             sheet.mergeCells('A4:H4'); sheet.getCell('A4').value = exportType.toUpperCase();
             sheet.getCell('A4').font = { bold: true, size: 14, underline: true }; sheet.getCell('A4').alignment = center;

             // Columns Setup based on Type
             let columns: any[] = [];
             if (exportType === 'quotation') {
                 columns = ['Image', 'No.', 'SKU', 'Description', 'Qty', 'Unit Price ($)', 'Total ($)', 'HS Code'];
             } else if (exportType === 'invoice') {
                 columns = ['No.', 'SKU', 'Description', 'Qty', 'Unit Price ($)', 'Total ($)', 'N.W(kg)', 'G.W(kg)'];
             } else {
                 columns = ['Image', 'No.', 'SKU', 'Description', 'Qty', 'Ctns', 'CBM', 'G.W(kg)'];
             }

             const headerRow = sheet.getRow(6);
             headerRow.values = columns;
             headerRow.font = { bold: true }; headerRow.alignment = center;
             headerRow.eachCell((c:any) => { c.border = border; c.fill = {type:'pattern', pattern:'solid', fgColor:{argb:'FFE0E0E0'}}; });

             // Data Rows
             exportItems.forEach((p, i) => {
                 const m = calculateMetrics(p);
                 const rowIndex = i + 7;
                 const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
                 const tQty = (cQty * p.pcsPerBox) || p.moq || 0;
                 const tGw = (p.gwKg || 15) * cQty;
                 const tCbm = (m.cbm || 0) * cQty;
                 const priceUsd = m.priceStockUsd || 0;

                 let rowData: any[] = [];
                 if (exportType === 'quotation') {
                     rowData = ['', i+1, p.sku, p.nameEn||p.nameCn, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2), p.hsCode];
                 } else if (exportType === 'invoice') {
                     rowData = [i+1, p.sku, p.nameEn||p.nameCn, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2), (tGw*0.9).toFixed(2), tGw.toFixed(2)];
                 } else {
                     rowData = ['', i+1, p.sku, p.nameEn||p.nameCn, tQty, cQty, tCbm.toFixed(3), tGw.toFixed(2)];
                 }

                 const row = sheet.getRow(rowIndex);
                 row.values = rowData;
                 row.height = 80;
                 row.alignment = center;
                 row.eachCell((c:any) => c.border = border);

                 // Add Image (except for pure text Invoice if desired, but user asked for functionality)
                 // For Invoice often no image, but we will add if column 1 is Image
                 if (columns[0] === 'Image' && p.photoUrl?.startsWith('data:image')) {
                    const imgId = workbook.addImage({ base64: p.photoUrl.split(',')[1], extension: 'jpeg' });
                    sheet.addImage(imgId, { tl: { col: 0.1, row: rowIndex - 1 + 0.1 }, br: { col: 0.9, row: rowIndex - 0.1 }, editAs: 'twoCell' });
                 }
             });
        }

        const buffer = await workbook.xlsx.writeBuffer();
        saveAs(new Blob([buffer]), `${fileName}.xlsx`);

    } else if (format === 'pdf') {
        // --- PDF EXPORT (jsPDF + autoTable) ---
        if (typeof jspdf === 'undefined') return alert("jsPDF library missing");

        const doc = new jspdf.jsPDF();

        // Add Header for Non-Master
        let startY = 15;
        if (exportType !== 'master') {
            doc.setFontSize(16); doc.setFont("helvetica", "bold");
            doc.text(headerInfo.companyName, 105, 15, { align: 'center' });

            doc.setFontSize(10); doc.setFont("helvetica", "normal");
            doc.text(`Contact: ${headerInfo.contactPerson}   Phone: ${headerInfo.phone}`, 105, 22, { align: 'center' });
            doc.text(headerInfo.address, 105, 27, { align: 'center' });

            doc.setLineWidth(0.5); doc.line(20, 30, 190, 30);

            doc.setFontSize(14); doc.setFont("helvetica", "bold");
            doc.text(exportType.toUpperCase(), 105, 40, { align: 'center' });
            startY = 45;
        }

        // Prepare Table Data
        const head = [];
        const body = [];

        if (exportType === 'quotation') {
            head.push(['No.', 'SKU', 'Description', 'Qty', 'Unit($)', 'Total($)']);
        } else if (exportType === 'invoice') {
             head.push(['No.', 'SKU', 'Description', 'Qty', 'Unit($)', 'Total($)', 'G.W']);
        } else if (exportType === 'packinglist') {
             head.push(['No.', 'SKU', 'Description', 'Qty', 'Ctns', 'CBM', 'G.W']);
        } else {
             head.push(['SKU', 'Name', 'Mat.', 'HS', 'L*W*H', 'Pcs', 'RMB']);
        }

        exportItems.forEach((p, i) => {
            const m = calculateMetrics(p);
            const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 0;
            const tQty = (cQty * p.pcsPerBox) || p.moq || 0;
            const priceUsd = m.priceStockUsd || 0;
            const desc = p.nameEn || p.nameCn || "Item"; // PDF basic font doesn't support Chinese well without custom font

            if (exportType === 'quotation') {
                body.push([i+1, p.sku, desc, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2)]);
            } else if (exportType === 'invoice') {
                body.push([i+1, p.sku, desc, tQty, priceUsd.toFixed(3), (priceUsd*tQty).toFixed(2), ((p.gwKg||15)*cQty).toFixed(2)]);
            } else if (exportType === 'packinglist') {
                body.push([i+1, p.sku, desc, tQty, cQty, (m.cbm||0 * cQty).toFixed(3), ((p.gwKg||15)*cQty).toFixed(2)]);
            } else {
                body.push([p.sku, desc, p.materialEn||"-", p.hsCode||"-", `${p.boxLength}x${p.boxWidth}x${p.boxHeight}`, p.pcsPerBox, p.priceRmb]);
            }
        });

        // @ts-ignore
        doc.autoTable({
            startY: startY,
            head: head,
            body: body,
            theme: 'grid',
            headStyles: { fillColor: [66, 66, 66] },
            styles: { fontSize: 9 },
        });

        doc.save(`${fileName}.pdf`);
    }
  };

  const handleBulkEnrich = async () => {
    if (!onUpdateProduct) return;

    setIsEnriching(true);
    const ids = Array.from(selectedIds);
    setEnrichProgress({ current: 0, total: ids.length });

    let processedCount = 0;

    const itemsToProcess = products.filter(p => selectedIds.has(p.id));

    for (const product of itemsToProcess) {
       if (!isMounted.current) break;

       try {
         const queryName = product.nameCn || product.nameEn || "Product";
         const result = await enrichProductData(queryName);

         const merged = { ...product, ...result };
         const metrics = calculateMetrics(merged);

         onUpdateProduct({ 
             ...merged, 
             ...metrics, 
             status: ProcessingStatus.REVIEW_NEEDED 
         });

