import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft, CheckSquare, Square, Trash2, Sparkles, Download, RefreshCw, FileText, Database, Printer, Contact, UserCircle, Briefcase, Globe, ScanLine, Edit2, Folder, FolderPlus, ArrowUpRight, Grid, Image as ImageIcon, Eraser } from 'lucide-react';
import { Product, ProcessingStatus, SupplierInfo, Language } from '../types';
import { analyzeImage, enrichProductData, analyzeBusinessCard } from '../services/geminiService';
import { translations } from '../utils/i18n';

// Declare globals for CDN libraries
declare const ExcelJS: any;
declare const saveAs: any;
declare const jspdf: any;

interface DraftImage {
  id: string;
  url: string;
  timestamp: number;
}

interface DraftFolder {
  id: string;
  name: string;
  supplier: SupplierInfo;
  images: DraftImage[];
  timestamp: number;
}

interface MobileEntryProps {
  onSave: (product: Product) => void;
  onUpdateProduct?: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
  currentLang?: Language;
  onLanguageChange?: (lang: Language) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ 
  onSave, onUpdateProduct, onDeleteProduct, isDesktopMode, onClose, products = [], 
  currentLang = 'en', onLanguageChange 
}) => {
  const t = translations[currentLang];

  // --- STATE ---
  const [viewMode, setViewMode] = useState<'folders' | 'folderDetail' | 'history'>('folders');
  const [activeFolderId, setActiveFolderId] = useState<string | null>(null);

  // Folders (Shops) State - Locally persisted in memory for this session
  const [folders, setFolders] = useState<DraftFolder[]>([]);

  // Selection State (Global: can select images from different folders)
  const [selectedImageIds, setSelectedImageIds] = useState<Set<string>>(new Set());

  // Processing State
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStatus, setProcessingStatus] = useState({ current: 0, total: 0, text: '' });

  // History / Product List State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });

  // Refs & Utils
  const isMounted = useRef(true);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cardInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // --- HELPERS ---

  const calculateMetrics = (p: Partial<Product>) => {
    const rate = 7.8; 
    const freight = 150; 
    const duty = p.taxRate || 0;

    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) 
      ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 
      : 0;
    const freightPerPc = (cbm > 0 && (p.pcsPerBox || 1) > 0) ? (freight * cbm) / (p.pcsPerBox || 1) : 0;
    const baseCostEuro = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / rate : 0;
    const dutyCost = baseCostEuro * (duty / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceSpainEuro = landedCostEuro * 1.2;
    const priceStockUsd = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / 7.2 : 0;

    return {
      cbm: Number(cbm.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceSpainEuro: Number(priceSpainEuro.toFixed(2)),
      priceStockUsd: Number(priceStockUsd.toFixed(3))
    };
  };

  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;
          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }
          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) { resolve(event.target?.result as string); return; }
          ctx.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg', 0.6));
        };
        img.onerror = (err) => reject(err);
      };
      reader.onerror = (err) => reject(err);
    });
  };

  // --- ACTIONS: FOLDERS ---

  const handleCreateFolder = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setIsProcessing(true);
      setProcessingStatus({ current: 0, total: 1, text: t.analyzingCard });

      try {
        const base64 = await processImageFile(file);
        const info = await analyzeBusinessCard(base64);

        const newFolder: DraftFolder = {
          id: Date.now().toString(),
          name: info.companyName || "New Shop " + (folders.length + 1),
          supplier: info,
          images: [],
          timestamp: Date.now()
        };

        if (isMounted.current) {
          setFolders(prev => [newFolder, ...prev]);
          setActiveFolderId(newFolder.id); 
          setViewMode('folderDetail');
        }
      } catch (err) {
        console.error(err);
        const newFolder: DraftFolder = {
          id: Date.now().toString(),
          name: "New Shop " + (folders.length + 1),
          supplier: { companyName: "", contactPerson: "", phone: "", address: "" },
          images: [],
          timestamp: Date.now()
        };
        setFolders(prev => [newFolder, ...prev]);
        setActiveFolderId(newFolder.id);
        setViewMode('folderDetail');
      } finally {
        setIsProcessing(false);
      }
    }
  };

  const handleDeleteFolder = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Delete this folder and all its photos?")) {
       setFolders(prev => prev.filter(f => f.id !== id));
       const folder = folders.find(f => f.id === id);
       if (folder) {
         const idsToRemove = new Set(folder.images.map(img => img.id));
         setSelectedImageIds(prev => {
           const next = new Set(prev);
           idsToRemove.forEach(i => next.delete(i));
           return next;
         });
       }
    }
  };

  const handleClearAllDrafts = () => {
    if (confirm("Clear all draft images and folders? (This will not affect saved table records)")) {
        setFolders([]);
        setSelectedImageIds(new Set());
    }
  };

  // --- ACTIONS: IMAGES ---

  const handleAddPhotos = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!activeFolderId) return;
    if (e.target.files && e.target.files.length > 0) {
      const files: File[] = Array.from(e.target.files);
      const newImages: DraftImage[] = [];

      for (const file of files) {
         try {
           const base64 = await processImageFile(file);
           newImages.push({
             id: Math.random().toString(36).substr(2, 9) + Date.now(),
             url: base64,
             timestamp: Date.now()
           });
         } catch (err) {
           console.error("Img error", err);
         }
      }

      setFolders(prev => prev.map(f => {
        if (f.id === activeFolderId) {
          return { ...f, images: [...newImages, ...f.images] };
        }
        return f;
      }));

      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const toggleImageSelection = (imgId: string) => {
    setSelectedImageIds(prev => {
      const next = new Set(prev);
      if (next.has(imgId)) next.delete(imgId);
      else next.add(imgId);
      return next;
    });
  };

  const toggleFolderSelection = (folderId: string) => {
     const folder = folders.find(f => f.id === folderId);
     if (!folder) return;
     const allSelected = folder.images.every(img => selectedImageIds.has(img.id));
     setSelectedImageIds(prev => {
        const next = new Set(prev);
        if (allSelected) {
           folder.images.forEach(img => next.delete(img.id));
        } else {
           folder.images.forEach(img => next.add(img.id));
        }
        return next;
     });
  };

  // --- ACTIONS: PROCESSING ---

  const handleProcessSelected = async () => {
    if (selectedImageIds.size === 0) return;

    setIsProcessing(true);
    let processed = 0;
    const total = selectedImageIds.size;
    const queue: { img: DraftImage, supplier: SupplierInfo }[] = [];

    folders.forEach(f => {
      f.images.forEach(img => {
        if (selectedImageIds.has(img.id)) {
          queue.push({ img, supplier: f.supplier });
        }
      });
    });

    setProcessingStatus({ current: 0, total, text: "Initializing..." });

    for (const item of queue) {
      if (!isMounted.current) break;
      setProcessingStatus({ current: processed + 1, total, text: `Analyzing item ${processed + 1}/${total}` });

      try {
        const aiData = await analyzeImage(item.img.url);
        const newProduct: Product = {
           id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 5),
           sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`,
           photoUrl: item.img.url,
           supplier: item.supplier,
           nameCn: aiData.nameCn,
           nameEn: aiData.nameEn,
           materialEn: aiData.materialEn,
           priceRmb: aiData.priceRmb,
           moq: aiData.moq,
           shopNo: item.supplier.address || "TBD",
           hsCode: aiData.hsCode,
           boxLength: aiData.boxLength,
           boxWidth: aiData.boxWidth,
           boxHeight: aiData.boxHeight,
           pcsPerBox: aiData.pcsPerBox,
           status: ProcessingStatus.DRAFT,
           timestamp: Date.now()
        };

        const metrics = calculateMetrics(newProduct);
        onSave({ ...newProduct, ...metrics });

        // CLEANUP: definitively remove processed image
        setFolders(prev => prev.map(f => ({
           ...f,
           images: f.images.filter(img => img.id !== item.img.id)
        })).filter(f => f.images.length > 0)); // Auto-remove empty folders

        setSelectedImageIds(prev => {
           const next = new Set(prev);
           next.delete(item.img.id);
           return next;
        });

      } catch (e) {
        console.error("Processing error", e);
      }
      processed++;
    }

    setIsProcessing(false);
    if (isMounted.current) {
        alert(t.batchComplete);
        setViewMode('history');
    }
  };

  // --- ACTIONS: HISTORY & EXPORT ---

  const handleBulkEnrich = async () => {
    if (selectedIds.size === 0) return;
    setIsEnriching(true);
    setEnrichProgress({ current: 0, total: selectedIds.size });
    const ids = Array.from(selectedIds);
    const items = products.filter(p => ids.includes(p.id));
    for (let i = 0; i < items.length; i++) {
        if (!isMounted.current) break;
        const p = items[i];
        setEnrichProgress({ current: i + 1, total: items.length });
        try {
             const enriched = await enrichProductData(p.nameCn);
             if (onUpdateProduct) {
                 const updated = { ...p, ...enriched };
                 const metrics = calculateMetrics(updated);
                 onUpdateProduct({ ...updated, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
             }
        } catch (e) { console.error("Bulk enrich error", e); }
    }
    setIsEnriching(false);
    setIsSelectMode(false);
    setSelectedIds(new Set());
    alert(t.batchComplete);
  };

  const handleExport = async (method: 'excel', type: 'master' | 'quotation' | 'packinglist' | 'invoice') => {
      if (typeof ExcelJS === 'undefined') return alert("ExcelJS not ready");
      const items = selectedIds.size > 0 ? products.filter(p => selectedIds.has(p.id)) : products;
      if (items.length === 0) return;
      const workbook = new ExcelJS.Workbook();
      const sheet = workbook.addWorksheet(type.toUpperCase());
      if (type === 'quotation') {
        sheet.columns = [
           { header: 'Image', key: 'img', width: 15 }, { header: 'SKU', key: 'sku', width: 15 },
           { header: 'Description', key: 'desc', width: 30 }, { header: 'Price', key: 'price', width: 10 },
           { header: 'Qty', key: 'qty', width: 10 }, { header: 'Total', key: 'total', width: 12 },
        ];
      } else {
        sheet.columns = [
           { header: 'Image', key: 'img', width: 15 }, { header: 'SKU', key: 'sku', width: 15 },
           { header: 'Name (CN)', key: 'nameCn', width: 20 }, { header: 'Name (EN)', key: 'nameEn', width: 20 },
           { header: 'Specs', key: 'specs', width: 20 }, { header: 'CBM', key: 'cbm', width: 10 },
           { header: 'G.W', key: 'gw', width: 10 },
        ];
      }
      for (let i = 0; i < items.length; i++) {
         const p = items[i];
         const m = calculateMetrics(p);
         const rowIdx = i + 2;
         const rowValues = type === 'quotation' 
            ? { sku: p.sku, desc: p.nameEn || p.nameCn, price: m.priceStockUsd, qty: p.moq, total: (m.priceStockUsd || 0) * (p.moq || 0) }
            : { sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, specs: `${p.boxLength}x${p.boxWidth}x${p.boxHeight}`, cbm: m.cbm, gw: p.gwKg };
         const row = sheet.addRow(rowValues);
         row.height = 80;
         if (p.photoUrl && p.photoUrl.startsWith('data:image')) {
             try {
                const base64 = p.photoUrl.split(',')[1];
                const imgId = workbook.addImage({ base64, extension: 'jpeg' });
                sheet.addImage(imgId, {
                    tl: { col: 0, row: rowIdx - 1 },
                    br: { col: 1, row: rowIdx },
                    editAs: 'twoCell'
                });
             } catch(e) {}
         }
      }
      const buffer = await workbook.xlsx.writeBuffer();
      saveAs(new Blob([buffer]), `Yiwu_Mobile_Export_${type}.xlsx`);
      setShowExportMenu(false);
  };

  const toggleLanguage = () => {
     if (!onLanguageChange) return;
     if (currentLang === 'en') onLanguageChange('zh');
     else if (currentLang === 'zh') onLanguageChange('es');
     else onLanguageChange('en');
  };

  // --- RENDER ---

  if (isProcessing) {
     return (
        <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center text-indigo-600">
           <Loader2 className="animate-spin mb-4" size={48} />
           <p className="font-bold text-lg text-slate-800">{processingStatus.text}</p>
           <div className="w-64 h-2 bg-slate-100 rounded-full mt-4 overflow-hidden">
              <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${(processingStatus.current / processingStatus.total) * 100}%` }}></div>
           </div>
           <p className="text-xs text-slate-400 mt-2">{processingStatus.current} / {processingStatus.total}</p>
        </div>
     );
  }

  if (viewMode === 'folders') {
    return (
      <div className="flex flex-col h-full bg-slate-50 font-sans relative">
         <div className="bg-white border-b border-slate-100 px-6 py-4 flex justify-between items-center sticky top-0 z-20">
             <h1 className="text-xl font-bold text-slate-900 tracking-tight">{t.myShops}</h1>
             <div className="flex items-center gap-2">
                 {folders.length > 0 && (
                    <button onClick={handleClearAllDrafts} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                        <Eraser size={20} />
                    </button>
                 )}
                 {!isDesktopMode && onClose && (
                      <button onClick={onClose} className="p-1.5 bg-slate-50 rounded-full text-slate-600">
                          <Home size={18}/>
                      </button>
                 )}
                 <button onClick={toggleLanguage} className="text-xs font-bold px-2.5 py-1.5 bg-slate-50 rounded-lg text-slate-600 flex items-center gap-1 border border-slate-100">
                    <Globe size={13}/> {currentLang.toUpperCase()}
                 </button>
             </div>
         </div>
         <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-32">
             <div className="bg-gradient-to-r from-violet-600 to-indigo-600 rounded-2xl shadow-lg shadow-indigo-200 p-0.5">
                 <div className="bg-white rounded-[14px] p-4 flex items-center justify-between">
                     <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600"><Store size={24} /></div>
                        <div><div className="font-bold text-slate-900">{t.newShop}</div><div className="text-xs text-slate-500">{t.scanCardToCreate}</div></div>
                     </div>
                     <label className="bg-slate-900 text-white w-10 h-10 rounded-full flex items-center justify-center cursor-pointer shadow-md active:scale-95 transition-transform">
                        <ScanLine size={20} /><input type="file" accept="image/*" className="hidden" ref={cardInputRef} onChange={handleCreateFolder} />
                     </label>
                 </div>
             </div>
             {folders.length === 0 ? (
                <div className="text-center py-20 text-slate-400">
                   <FolderPlus size={48} className="mx-auto mb-3 opacity-20" />
                   <p className="text-sm font-medium">{t.emptyFolders}</p>
                </div>
             ) : (
                <div className="space-y-3">
                   {folders.map(folder => {
                      const selectedCount = folder.images.filter(img => selectedImageIds.has(img.id)).length;
                      const hasSelection = selectedCount > 0;
                      return (
                        <div key={folder.id} className={`bg-white rounded-2xl border ${hasSelection ? 'border-indigo-300 ring-1 ring-indigo-100' : 'border-slate-100'} shadow-sm overflow-hidden`}>
                           <div className="p-4 flex items-start justify-between">
                              <div className="flex items-center gap-3 flex-1 cursor-pointer" onClick={() => { setActiveFolderId(folder.id); setViewMode('folderDetail'); }}>
                                 <div className="bg-amber-100 text-amber-600 p-2.5 rounded-lg"><Folder size={20} fill="currentColor" className="opacity-80"/></div>
                                 <div className="min-w-0"><div className="font-bold text-slate-800 text-sm truncate">{folder.name}</div><div className="text-xs text-slate-400">{folder.images.length} {t.photos}</div></div>
                              </div>
                              <div className="flex items-center gap-1">
                                 <button onClick={() => toggleFolderSelection(folder.id)} className={`p-2 rounded-full ${hasSelection ? 'text-indigo-600 bg-indigo-50' : 'text-slate-300'}`}>
                                    {selectedCount === folder.images.length && folder.images.length > 0 ? <CheckSquare size={20}/> : <Square size={20}/>}
                                 </button>
                                 <button onClick={() => { setActiveFolderId(folder.id); setViewMode('folderDetail'); }} className="p-2 text-slate-300"><ChevronRight size={20} /></button>
                              </div>
                           </div>
                           {folder.images.length > 0 && (
                             <div className="px-4 pb-4 flex gap-2 overflow-x-auto no-scrollbar">
                                {folder.images.slice(0, 5).map(img => (
                                   <div key={img.id} onClick={() => toggleImageSelection(img.id)} className={`w-12 h-12 rounded-lg shrink-0 overflow-hidden border relative ${selectedImageIds.has(img.id) ? 'border-indigo-500 ring-2 ring-indigo-500' : 'border-slate-100'}`}>
                                      <img src={img.url} className="w-full h-full object-cover" />
                                   </div>
                                ))}
                             </div>
                           )}
                           <div className="px-4 py-2 bg-slate-50 border-t border-slate-100 flex justify-between items-center">
                              <span className="text-[10px] text-slate-400">{new Date(folder.timestamp).toLocaleTimeString()}</span>
                              <button onClick={(e) => handleDeleteFolder(folder.id, e)} className="text-slate-400 hover:text-red-500 p-1"><Trash2 size={14}/></button>
                           </div>
                        </div>
                      );
                   })}
                </div>
             )}
         </div>
         {selectedImageIds.size > 0 && (
            <div className="absolute bottom-24 left-6 right-6 z-30 animate-in slide-in-from-bottom-4">
               <button onClick={handleProcessSelected} className="w-full bg-slate-900 text-white rounded-2xl py-4 shadow-xl flex items-center justify-center gap-2 font-bold text-sm">
                 <Sparkles size={18} className="text-indigo-300"/> {t.processSelected} ({selectedImageIds.size})
               </button>
            </div>
         )}
         {!isDesktopMode && (
            <nav className="glass-nav absolute bottom-0 w-full pb-8 pt-4 px-12 flex justify-between items-center z-10">
              <button onClick={() => setViewMode('folders')} className="flex flex-col items-center gap-1.5 text-indigo-600 relative">
                 <div className="absolute -top-1 w-8 h-1 bg-indigo-600 rounded-full"></div>
                 <Grid size={24} strokeWidth={2.5} /><span className="text-[10px] font-bold tracking-wide">{t.myShops}</span>
              </button>
              <button onClick={() => setViewMode('history')} className="flex flex-col items-center gap-1.5 text-slate-300 transition-colors">
                 <Database size={24} /><span className="text-[10px] font-bold tracking-wide">{t.history}</span>
              </button>
            </nav>
         )}
      </div>
    );
  }

  if (viewMode === 'folderDetail' && activeFolderId) {
    const folder = folders.find(f => f.id === activeFolderId);
    if (!folder) { setViewMode('folders'); return null; }
    const selectedInThisFolder = folder.images.filter(img => selectedImageIds.has(img.id));
    const isAllSelected = selectedInThisFolder.length === folder.images.length && folder.images.length > 0;
    return (
      <div className="flex flex-col h-full bg-white font-sans relative">
         <div className="bg-white border-b border-slate-100 px-4 py-3 flex items-center justify-between sticky top-0 z-20">
             <button onClick={() => setViewMode('folders')} className="p-2 -ml-2 text-slate-600 rounded-full"><ArrowLeft size={20} /></button>
             <div className="text-center"><div className="font-bold text-slate-900 text-sm">{folder.name}</div><div className="text-[10px] text-slate-400">{folder.images.length} {t.photos}</div></div>
             <button onClick={() => toggleFolderSelection(folder.id)} className="text-xs font-bold text-indigo-600">{isAllSelected ? t.unselectAll : t.selectAll}</button>
         </div>
         <div className="p-4 bg-slate-50 border-b border-slate-100">
             <div className="bg-white rounded-xl border border-slate-200 p-3 space-y-2">
                 <div className="flex justify-between items-center mb-1"><span className="text-[10px] font-bold text-slate-400 uppercase tracking-wide">{t.sessionHeader}</span><ScanLine size={14} className="text-slate-400" /></div>
                 <input className="w-full text-sm font-bold border-none p-0 focus:ring-0" value={folder.supplier.companyName} onChange={(e) => {
                      const newSupplier = { ...folder.supplier, companyName: e.target.value };
                      setFolders(prev => prev.map(f => f.id === folder.id ? { ...f, name: e.target.value, supplier: newSupplier } : f));
                 }} placeholder={t.companyName} />
                 <div className="flex gap-2 text-xs">
                    <input className="flex-1 bg-slate-50 rounded px-2 py-1.5 border-none" value={folder.supplier.contactPerson} onChange={(e) => {
                          const newSupplier = { ...folder.supplier, contactPerson: e.target.value };
                          setFolders(prev => prev.map(f => f.id === folder.id ? { ...f, supplier: newSupplier } : f));
                    }} placeholder={t.contactPerson} />
                    <input className="flex-1 bg-slate-50 rounded px-2 py-1.5 border-none" value={folder.supplier.phone} onChange={(e) => {
                          const newSupplier = { ...folder.supplier, phone: e.target.value };
                          setFolders(prev => prev.map(f => f.id === folder.id ? { ...f, supplier: newSupplier } : f));
                    }} placeholder={t.phone} />
                 </div>
             </div>
         </div>
         <div className="flex-1 overflow-y-auto p-1 pb-32">
             <div className="grid grid-cols-3 gap-1">
                {folder.images.map(img => (
                   <div key={img.id} onClick={() => toggleImageSelection(img.id)} className={`aspect-square relative cursor-pointer`}>
                      <img src={img.url} className="w-full h-full object-cover" />
                      <div className={`absolute top-1 right-1 w-5 h-5 rounded-full border border-white flex items-center justify-center ${selectedImageIds.has(img.id) ? 'bg-indigo-600' : 'bg-black/20'}`}>
                         {selectedImageIds.has(img.id) && <CheckSquare size={12} className="text-white"/>}
                      </div>
                   </div>
                ))}
                <label className="aspect-square bg-slate-100 flex flex-col items-center justify-center text-slate-400 cursor-pointer"><Camera size={24} className="mb-1"/><span className="text-[10px] font-bold">{t.addPhotos}</span><input type="file" multiple accept="image/*" onChange={handleAddPhotos} className="hidden" ref={fileInputRef} /></label>
             </div>
         </div>
         {selectedImageIds.size > 0 && (
            <div className="absolute bottom-6 left-6 right-6 z-30">
               <button onClick={handleProcessSelected} className="w-full bg-slate-900 text-white rounded-2xl py-4 shadow-xl flex items-center justify-center gap-2 font-bold text-sm">
                 <Sparkles size={18} className="text-indigo-300"/> {t.processSelected} ({selectedImageIds.size})
               </button>
            </div>
         )}
      </div>
    );
  }

  return (
      <div className="flex flex-col h-full bg-slate-50 relative">
        {showExportMenu && (
          <div className="fixed inset-0 z-[60] bg-black/50 backdrop-blur-sm flex items-end justify-center pb-8 animate-in slide-in-from-bottom-10">
             <div className="bg-white w-[90%] max-w-sm rounded-2xl p-5 shadow-2xl flex flex-col gap-3">
                 <div className="flex justify-between items-center mb-3 border-b border-slate-100 pb-2"><h3 className="font-bold text-lg text-slate-800">{t.exportOptions}</h3><button onClick={() => setShowExportMenu(false)} className="p-1 text-slate-400"><X size={20}/></button></div>
                 {[{ id: 'master', label: t.masterData }, { id: 'quotation', label: t.quotation }, { id: 'packinglist', label: t.packingList }, { id: 'invoice', label: t.invoice }].map((item) => (
                   <div key={item.id} className="flex gap-2"><button onClick={() => handleExport('excel', item.id as any)} className="flex-1 flex items-center gap-3 p-3 rounded-xl border border-slate-100 bg-slate-50 text-left"><div className="w-8 h-8 rounded-full bg-green-100 text-green-600 flex items-center justify-center"><Database size={16}/></div><div><div className="font-bold text-slate-800 text-sm">{item.label} .xlsx</div></div></button></div>
                 ))}
             </div>
          </div>
        )}
        {isEnriching && (
           <div className="absolute inset-0 z-50 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center"><RefreshCw className="animate-spin text-indigo-600 mb-4" size={40} /><p className="font-bold text-lg text-slate-800">AI Enriching...</p><p className="text-sm text-slate-500 mt-1">{enrichProgress.current} / {enrichProgress.total}</p></div>
        )}
        <div className="px-6 py-4 bg-white shadow-sm z-10 sticky top-0 flex justify-between items-center">
          <div><h2 className="text-xl font-bold text-slate-800 tracking-tight">{isSelectMode ? `${t.selected} (${selectedIds.size})` : t.history}</h2>{!isSelectMode && <p className="text-xs text-slate-500">{products.length} {t.items}</p>}</div>
          <div className="flex gap-2">
             {!isDesktopMode && onClose && (<button onClick={onClose} className="text-xs font-bold px-3 py-1.5 bg-slate-100 rounded-full text-slate-600 flex items-center gap-1"><Home size={14}/></button>)}
             <button onClick={() => { if(isSelectMode) setSelectedIds(new Set()); setIsSelectMode(!isSelectMode); }} className={`text-sm font-medium px-3 py-1.5 rounded-full transition-colors ${isSelectMode ? 'bg-slate-100 text-slate-600' : 'bg-indigo-50 text-indigo-600'}`}>{isSelectMode ? t.cancel : t.select}</button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-32">
          {products.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-400"><Box size={32} className="text-slate-300 mb-2" /><p className="font-medium">No items yet.</p></div>
          ) : (
            products.map((p) => (
              <div key={p.id} onClick={() => isSelectMode && (() => { const s = new Set(selectedIds); if(s.has(p.id)) s.delete(p.id); else s.add(p.id); setSelectedIds(s); })()} className={`bg-white p-3 rounded-xl shadow-sm border flex gap-3 transition-all ${selectedIds.has(p.id) ? 'border-indigo-400 ring-1 ring-indigo-400 bg-indigo-50/10' : 'border-slate-100'}`}>
                {isSelectMode && (<div className="flex items-center justify-center pl-1 pr-2">{selectedIds.has(p.id) ? <CheckSquare className="text-indigo-600" size={20} /> : <Square className="text-slate-300" size={20} />}</div>)}
                <div className="w-20 h-20 shrink-0 rounded-lg bg-slate-50 overflow-hidden border border-slate-100">{p.photoUrl ? <img src={p.photoUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><ImagePlus size={20}/></div>}</div>
                <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                  <div>
                    <div className="flex justify-between items-start"><h3 className="font-bold text-slate-800 text-sm truncate pr-2">{p.sku}</h3>{p.supplier?.companyName && <span className="text-[9px] bg-slate-100 px-1 rounded text-slate-500 truncate max-w-[80px]">{p.supplier.companyName}</span>}</div>
                    <p className="text-xs text-slate-500 truncate mt-0.5">{p.nameEn || p.nameCn}</p>
                  </div>
                  <div className="flex justify-between items-end mt-2"><div className="font-mono font-bold text-indigo-600 text-sm">¥{p.priceRmb}</div></div>
                </div>
              </div>
            ))
          )}
        </div>
        {isSelectMode ? (
            <div className="absolute bottom-24 w-full px-4 z-30 flex items-center justify-between gap-3">
                <button onClick={() => onDeleteProduct && onDeleteProduct(Array.from(selectedIds))} className="flex flex-col items-center gap-1 text-slate-500 active:text-red-600 bg-white p-3 rounded-full shadow-lg"><Trash2 size={20} /></button>
                <button onClick={handleBulkEnrich} className="flex-1 bg-indigo-600 text-white rounded-xl h-12 flex items-center justify-center gap-2 shadow-lg"><Sparkles size={18} /><span className="font-bold text-sm">{t.aiEnrich}</span></button>
                <button onClick={() => setShowExportMenu(true)} className="flex flex-col items-center gap-1 text-slate-500 active:text-green-600 bg-white p-3 rounded-full shadow-lg"><Download size={20} /></button>
            </div>
        ) : (
            <nav className="glass-nav absolute bottom-0 w-full pb-8 pt-4 px-12 flex justify-between items-center z-20">
              <button onClick={() => setViewMode('folders')} className="flex flex-col items-center gap-1.5 text-slate-300 active:text-indigo-600 transition-colors"><Grid size={24} /><span className="text-[10px] font-bold tracking-wide">{t.myShops}</span></button>
              <button onClick={() => setViewMode('history')} className="flex flex-col items-center gap-1.5 text-indigo-600 relative"><div className="absolute -top-1 w-8 h-1 bg-indigo-600 rounded-full"></div><Database size={24} strokeWidth={2.5} /><span className="text-[10px] font-bold tracking-wide">{t.history}</span></button>
            </nav>
        )}
      </div>
  );
};

export default MobileEntry;

import React, { useState } from 'react';
import { Product, ProcessingStatus, Language } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, Settings, Database, Edit, Save as SaveIcon, X, Trash2, CheckSquare, Square, Printer, Search, Download, Package, Box as BoxIcon, Plus, UploadCloud, ZoomIn, FileText, Globe, Home, Menu } from 'lucide-react';
import MobileEntry from './MobileEntry';
import { translations } from '../utils/i18n';

// Declare ExcelJS and saveAs globally since we loaded them via CDN
declare const ExcelJS: any;
declare const saveAs: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  onAddProduct: (product: Product) => void;
  currentLang?: Language;
  onLanguageChange?: (lang: Language) => void;
  onHome?: () => void;
}

const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832",
  bankBeneficiary: "YiWu Edas Import and Export Co., Ltd",
  bankName: "TED BANK, Yiwu Branch",
  bankAddress: "TED Address, Yiwu, China",
  bankSwift: "TEDXXXX",
  bankAccount: "TED-ACCOUNT-NUMBER",
};

const Dashboard: React.FC<DashboardProps> = ({ 
  products, onUpdateProduct, onDeleteProduct, onAddProduct, 
  currentLang = 'en', onLanguageChange, onHome 
}) => {
  const t = translations[currentLang];
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Product>>({});

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);

  const [showInvoiceModal, setShowInvoiceModal] = useState(false);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [invoiceConfig, setInvoiceConfig] = useState(DEFAULT_INVOICE_CONFIG);

  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150);
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2); 
  const [vatRate, setVatRate] = useState<number>(21);

  const calculateMetrics = (p: Product, overrides?: { euroRate?: number, freight?: number, vat?: number }) => {
    const rate = overrides?.euroRate || euroRmbRate;
    const freight = overrides?.freight || freightRateCbm;
    const vat = overrides?.vat || vatRate;
    const usdRate = usdRmbRate;
    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 : 0;
    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) ? (freight * cbm) / p.pcsPerBox : 0;
    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;
    const dutyCost = baseCostEuro * ((p.taxRate || 0) / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;
    return {
      cbm: Number(cbm.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
    };
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === products.length) { setSelectedIds(new Set()); } else { setSelectedIds(new Set(products.map(p => p.id))); }
  };
  const toggleSelectRow = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) { newSet.delete(id); } else { newSet.add(id); }
    setSelectedIds(newSet);
  };
  const handleBulkDelete = () => {
    if (confirm(`Are you sure you want to delete ${selectedIds.size} items?`)) {
      if (onDeleteProduct) { onDeleteProduct(Array.from(selectedIds)); setSelectedIds(new Set()); }
    }
  };
  const handleBulkEnrich = async () => {
    setIsBulkProcessing(true);
    const itemsToProcess = products.filter(p => selectedIds.has(p.id));
    for (const product of itemsToProcess) {
       try {
         const result = await enrichProductData(product.nameCn);
         const metrics = calculateMetrics({ ...product, ...result });
         onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
       } catch (e) { console.error(`Failed to enrich ${product.id}`, e); }
    }
    setIsBulkProcessing(false); setSelectedIds(new Set()); alert(t.batchComplete);
  };
  const handleEnrichment = async (product: Product) => {
    if (!process.env.API_KEY) return alert("API Key missing");
    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });
    try {
      const result = await enrichProductData(product.nameCn);
      const metrics = calculateMetrics({ ...product, ...result });
      onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
    } catch (error) { onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally { setProcessingId(null); }
  };
  const startEditing = (product: Product) => { setEditingId(product.id); setEditForm({ ...product }); };
  const saveEdit = () => {
    if (!editingId) return;
    const product = products.find(p => p.id === editingId);
    if (product) { const merged = { ...product, ...editForm }; const metrics = calculateMetrics(merged); onUpdateProduct({ ...merged, ...metrics }); }
    setEditingId(null); setEditForm({});
  };
  const cancelEdit = () => { setEditingId(null); setEditForm({}); };

  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice' | 'quotation') => {
     if (typeof ExcelJS === 'undefined') return alert("ExcelJS library not loaded.");
     if (products.length === 0) return alert("No products to export.");

     const workbook = new ExcelJS.Workbook();
     const sheet = workbook.addWorksheet(exportType.toUpperCase());
     const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
     const leftStyle = { vertical: 'middle', horizontal: 'left', wrapText: true };
     const borderStyle = { top: { style: 'thin' }, left: { style: 'thin' }, bottom: { style: 'thin' }, right: { style: 'thin' } };

     if (exportType === 'invoice') {
        sheet.columns = [
          { key: 'no', width: 5 }, { key: 'sku', width: 12 }, { key: 'desc', width: 40 },
          { key: 'hs', width: 15 }, { key: 'ctns', width: 8 }, { key: 'pkg', width: 15 },
          { key: 'qty', width: 10 }, { key: 'unit', width: 6 }, { key: 'price', width: 12 },
          { key: 'amount', width: 15 }, { key: 'gwCtn', width: 10 }, { key: 'totalGw', width: 12 },
          { key: 'cbmCtn', width: 10 }, { key: 'totalCbm', width: 12 },
        ];
        sheet.mergeCells('A1:N1'); sheet.getCell('A1').value = invoiceConfig.sellerName;
        sheet.getCell('A1').font = { bold: true, size: 16 }; sheet.getCell('A1').alignment = centerStyle;
        sheet.mergeCells('A2:N2'); sheet.getCell('A2').value = invoiceConfig.sellerName; sheet.getCell('A2').alignment = centerStyle;
        sheet.mergeCells('A3:N3'); sheet.getCell('A3').value = invoiceConfig.sellerAddress; sheet.getCell('A3').alignment = centerStyle;
        sheet.mergeCells('A4:N4'); sheet.getCell('A4').value = `Tel: ${invoiceConfig.sellerPhone}  Email: ${invoiceConfig.sellerEmail}`; sheet.getCell('A4').alignment = centerStyle;
        sheet.mergeCells('A6:N6'); sheet.getCell('A6').value = "INVOICE"; sheet.getCell('A6').font = { bold: true, size: 20 }; sheet.getCell('A6').alignment = centerStyle;

        sheet.mergeCells('A8:D8'); sheet.getCell('A8').value = `Invoice No: ${invoiceConfig.invoiceNo}`; sheet.getCell('A8').font = { bold: true };
        sheet.mergeCells('H8:N8'); sheet.getCell('H8').value = `Date: ${invoiceConfig.date}`; sheet.getCell('H8').font = { bold: true };
        sheet.mergeCells('H9:N9'); sheet.getCell('H9').value = `Sailing: ${invoiceConfig.sailing}`;
        sheet.mergeCells('A10:D13'); sheet.getCell('A10').value = `To:\n${invoiceConfig.buyerInfo}`; sheet.getCell('A10').alignment = { vertical: 'top', horizontal: 'left', wrapText: true }; sheet.getCell('A10').border = borderStyle;
        sheet.mergeCells('A14:D14'); sheet.getCell('A14').value = `Container: ${invoiceConfig.containerNo}`; sheet.getCell('A14').font = { bold: true }; sheet.getCell('A14').border = { bottom: { style: 'thin' } };
        sheet.mergeCells('H14:N14'); sheet.getCell('H14').value = `Seal: ${invoiceConfig.sealNo}`; sheet.getCell('H14').font = { bold: true }; sheet.getCell('H14').border = { bottom: { style: 'thin' } };

        const headerRow = sheet.getRow(16);
        headerRow.values = ['No.', 'Item NO', 'Description', 'HS CODE', 'CTNS', 'Pkg', 'QTY', 'Unit', 'Price(¥)', 'Amount(¥)', 'GW/ctn', 'Total GW', 'CBM/ctn', 'Total CBM'];
        headerRow.font = { bold: true }; headerRow.alignment = centerStyle;
        headerRow.eachCell((cell:any) => { cell.border = borderStyle; cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0E0E0' } }; });

        let currentRow = 17;
        products.forEach((p, i) => {
          const m = calculateMetrics(p);
          const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 1;
          const q = (cQty * p.pcsPerBox) || p.moq || 1;
          const row = sheet.getRow(currentRow);
          row.values = [i+1, p.sku, p.nameEn||p.nameCn, p.hsCode, cQty, p.pcsPerBox, q, 'PCS', p.priceRmb, p.priceRmb * q, p.gwKg||0, (p.gwKg||0)*cQty, (m.cbm||0).toFixed(3), ((m.cbm||0)*cQty).toFixed(3)];
          row.eachCell((c:any) => { c.border = borderStyle; });
          currentRow++;
        });
     } else {
        if (exportType === 'master') {
          sheet.columns = [
            { header: 'Image', key: 'image', width: 20 }, { header: 'SKU', key: 'sku', width: 15, style: centerStyle },
            { header: 'Name (CN)', key: 'nameCn', width: 25, style: leftStyle }, { header: 'Product Name (EN)', key: 'nameEn', width: 25, style: leftStyle },
            { header: 'Material', key: 'mat', width: 20, style: leftStyle }, { header: 'HS Code', key: 'hs', width: 15, style: centerStyle }, 
            { header: 'L', key: 'l', width: 8, style: centerStyle }, { header: 'W', key: 'w', width: 8, style: centerStyle }, { header: 'H', key: 'h', width: 8, style: centerStyle },
            { header: 'Pcs/Box', key: 'pcs', width: 8, style: centerStyle }, { header: 'CBM', key: 'cbm', width: 10, style: centerStyle },
            { header: 'Cost (RMB)', key: 'rmb', width: 12, style: centerStyle }, { header: 'MOQ', key: 'moq', width: 8, style: centerStyle }
          ];
        } else if (exportType === 'quotation') {
          sheet.columns = [
            { header: 'Image', key: 'image', width: 20 }, { header: 'No.', key: 'no', width: 8, style: centerStyle },
            { header: 'SKU', key: 'sku', width: 15, style: centerStyle }, { header: 'Description', key: 'desc', width: 40, style: leftStyle },
            { header: 'HS Code', key: 'hs', width: 15, style: centerStyle }, { header: 'Quantity', key: 'qty', width: 12, style: centerStyle },
            { header: 'Price (USD)', key: 'price', width: 15, style: centerStyle }, { header: 'Total (USD)', key: 'amount', width: 18, style: centerStyle },
          ];
        } else {
           sheet.columns = [
            { header: 'Image', key: 'image', width: 20 }, { header: 'No.', key: 'no', width: 6, style: centerStyle },
            { header: 'SKU', key: 'sku', width: 15, style: centerStyle }, { header: 'Description', key: 'desc', width: 35, style: leftStyle },
            { header: 'Qty', key: 'qty', width: 10, style: centerStyle }, { header: 'Cartons', key: 'cartons', width: 10, style: centerStyle },
            { header: 'CBM', key: 'totalCbm', width: 12, style: centerStyle }, { header: 'G.W', key: 'totalGw', width: 12, style: centerStyle },
          ];
        }

        sheet.getRow(1).font = { bold: true }; sheet.getRow(1).height = 30; sheet.getRow(1).alignment = centerStyle;

        products.forEach((p, i) => {
           const m = calculateMetrics(p); const rowIndex = i + 2;
           const cQty = (p.moq && p.pcsPerBox) ? Math.ceil(p.moq / p.pcsPerBox) : 1;
           const tQty = (cQty * p.pcsPerBox) || p.moq || 1; 
           let rowValues = {};

           if (exportType === 'master') {
             rowValues = { sku: p.sku, nameCn: p.nameCn, nameEn: p.nameEn, mat: p.materialEn, hs: p.hsCode, l: p.boxLength, w: p.boxWidth, h: p.boxHeight, pcs: p.pcsPerBox, cbm: m.cbm, rmb: p.priceRmb, moq: p.moq };
           } else if (exportType === 'quotation') {
             rowValues = { no: i+1, sku: p.sku, desc: p.nameEn||p.nameCn, hs: p.hsCode, qty: tQty, price: m.priceStockUsd, amount: m.priceStockUsd * tQty };
           } else {
             rowValues = { no: i+1, sku: p.sku, desc: p.nameEn||p.nameCn, qty: tQty, cartons: cQty, totalCbm: (m.cbm*cQty).toFixed(3), totalGw: ((p.gwKg||0)*cQty).toFixed(2) };
           }

           const row = sheet.addRow(rowValues); 
           row.height = 110; // Match width 20 (approx 150px) to keep cell square
           row.alignment = centerStyle;
           row.eachCell((cell:any) => { cell.border = borderStyle; });

           if (p.photoUrl && p.photoUrl.startsWith('data:image')) {
             try {
               const base64 = p.photoUrl.split(',')[1];
               const imageId = workbook.addImage({ base64, extension: 'jpeg' });
               // FULL BLEED: tl:0, br:1 ensures the image touches every corner of the cell
               sheet.addImage(imageId, { 
                  tl: { col: 0, row: rowIndex - 1 }, 
                  br: { col: 1, row: rowIndex },
                  editAs: 'twoCell' 
               });
             } catch (e) {}
           }
        });
     }
     const buffer = await workbook.xlsx.writeBuffer();
     saveAs(new Blob([buffer]), `Yiwu_${exportType}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  const toggleLanguage = () => {
     if (!onLanguageChange) return;
     if (currentLang === 'en') onLanguageChange('zh');
     else if (currentLang === 'zh') onLanguageChange('es');
     else onLanguageChange('en');
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 font-sans relative">
      {showUploadModal && (
        <div className="fixed inset-0 z-[70] bg-slate-900/50 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in">
           <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg h-[80vh] overflow-hidden flex flex-col relative">
             <MobileEntry onSave={onAddProduct} isDesktopMode={true} onClose={() => setShowUploadModal(false)} currentLang={currentLang} onLanguageChange={onLanguageChange} products={products} onUpdateProduct={onUpdateProduct} onDeleteProduct={onDeleteProduct} />
           </div>
        </div>
      )}
      {previewImage && (
        <div className="fixed inset-0 z-[80] bg-black/90 backdrop-blur-md flex items-center justify-center p-4" onClick={() => setPreviewImage(null)}>
          <div className="relative max-w-4xl max-h-[90vh] w-full flex items-center justify-center">
             <img src={previewImage} className="max-w-full max-h-[90vh] object-contain rounded-lg shadow-2xl" />
             <button onClick={() => setPreviewImage(null)} className="absolute top-4 right-4 bg-white/20 text-white p-2 rounded-full"><X size={24} /></button>
          </div>
        </div>
      )}
      {showInvoiceModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-slate-100 flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10"><h2 className="text-xl font-bold flex items-center gap-2 text-slate-800"><Settings size={20} className="text-indigo-600"/> {t.invoiceConfig}</h2><button onClick={() => setShowInvoiceModal(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20}/></button></div>
            <div className="p-8 space-y-6">
              <div className="space-y-4"><h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{t.sellerDetails}</h3><div className="grid grid-cols-2 gap-4"><div className="col-span-2"><label className="text-sm font-medium text-slate-700">{t.companyName}</label><input className="w-full mt-1 border border-slate-200 p-2.5 rounded-lg text-sm" value={invoiceConfig.sellerName} onChange={e => setInvoiceConfig({...invoiceConfig, sellerName: e.target.value})} /></div></div></div>
              <div className="space-y-4 pt-4 border-t border-slate-100"><h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{t.shipmentDetails}</h3><div className="grid grid-cols-2 gap-4"><div className="col-span-2"><label className="text-sm font-medium text-slate-700">{t.buyerInfo}</label><textarea className="w-full mt-1 border border-slate-200 p-2.5 rounded-lg text-sm h-24" value={invoiceConfig.buyerInfo} onChange={e => setInvoiceConfig({...invoiceConfig, buyerInfo: e.target.value})} /></div></div></div>
            </div>
            <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end gap-3 sticky bottom-0"><button onClick={() => setShowInvoiceModal(false)} className="px-5 py-2.5 text-slate-600 font-medium">Cancel</button><button onClick={() => { setShowInvoiceModal(false); generateExcel('invoice'); }} className="px-5 py-2.5 bg-indigo-600 text-white font-medium rounded-lg shadow-lg">Save & Download</button></div>
          </div>
        </div>
      )}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm/50">
        <div className="p-4 md:px-8 md:py-4 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center gap-3 w-full md:w-auto justify-between md:justify-start">
             <div className="flex items-center gap-3"><div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg shrink-0"><Database size={20} /></div><div><h1 className="text-lg font-bold text-slate-900 leading-tight">{t.dashboard}</h1><p className="text-xs text-slate-500 font-medium">{products.length} {t.recordsFound}</p></div></div>
             <div className="flex md:hidden items-center gap-2"><button onClick={toggleLanguage} className="text-xs font-bold px-2 py-1 bg-slate-100 rounded text-slate-600">{currentLang.toUpperCase()}</button></div>
          </div>
          <div className="flex items-center gap-3 w-full md:w-auto overflow-x-auto pb-2 md:pb-0 no-scrollbar">
             {onHome && (<button onClick={onHome} className="text-xs font-bold px-3 py-2 bg-slate-100 rounded-lg text-slate-600 flex items-center gap-1 shrink-0"><Home size={14}/> {t.backHome}</button>)}
             <button onClick={() => setShowUploadModal(true)} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-xs font-bold uppercase rounded-lg shadow-lg shrink-0"><UploadCloud size={16} /> {t.newSourcingBatch}</button>
             <div className="flex bg-slate-100 p-1 rounded-lg shrink-0">
                <button onClick={() => generateExcel('master')} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white rounded-md transition-all shrink-0">{t.masterData}</button>
                <button onClick={() => generateExcel('packinglist')} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white rounded-md transition-all shrink-0">{t.packingList}</button>
                <button onClick={() => generateExcel('quotation')} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white rounded-md transition-all shrink-0">{t.quotation}</button>
                <button onClick={() => setShowInvoiceModal(true)} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white rounded-md transition-all shrink-0">{t.invoice}</button>
             </div>
          </div>
        </div>
        <div className="px-4 py-3 md:px-8 bg-slate-50/50 border-t border-slate-200 flex flex-col md:flex-row items-stretch md:items-center justify-between gap-3">
           {selectedIds.size > 0 ? (
             <div className="flex items-center justify-between md:justify-start gap-4 bg-indigo-50 border border-indigo-100 px-4 py-2 rounded-lg w-full md:w-auto">
                <span className="text-sm font-bold text-indigo-700 flex items-center gap-2"><CheckSquare size={16} /> {selectedIds.size} {t.selected}</span>
                <div className="flex gap-3"><button onClick={handleBulkEnrich} disabled={isBulkProcessing} className="text-xs font-medium text-indigo-600 flex items-center gap-1.5">{isBulkProcessing ? <RefreshCw className="animate-spin" size={14}/> : <Sparkles size={14}/>} {t.aiEnrich}</button><button onClick={handleBulkDelete} className="text-xs font-medium text-red-600 flex items-center gap-1.5"><Trash2 size={14}/> {t.delete}</button></div>
             </div>
           ) : (
             <div className="flex items-center gap-6 text-sm text-slate-500 overflow-x-auto no-scrollbar w-full md:w-auto">
               <div className="flex items-center gap-2 bg-white border rounded-md px-3 py-1 shrink-0"><span className="text-xs font-bold text-slate-400">EUR</span><input type="number" value={euroRmbRate} onChange={e => setEuroRmbRate(Number(e.target.value))} className="w-10 text-center outline-none" /></div>
               <div className="flex items-center gap-2 bg-white border rounded-md px-3 py-1 shrink-0"><span className="text-xs font-bold text-slate-400">FRT</span><input type="number" value={freightRateCbm} onChange={e => setFreightRateCbm(Number(e.target.value))} className="w-10 text-center outline-none" /></div>
             </div>
           )}
           <div className="relative w-full md:w-auto"><Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder={t.searchPlaceholder} className="pl-9 pr-4 py-2 text-sm border rounded-full outline-none focus:border-indigo-500 w-full md:w-64 bg-white" /></div>
        </div>
      </header>
      <main className="flex-1 overflow-auto bg-slate-100 p-2 md:p-6">
        <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm whitespace-nowrap">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 w-10 text-center"><button onClick={toggleSelectAll} className="text-slate-400">{selectedIds.size === products.length ? <CheckSquare size={18}/> : <Square size={18}/>}</button></th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase">{t.productName}</th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase">{t.details}</th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase">{t.category}</th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase text-right">{t.cost}</th>
                  <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase text-right">{t.landed}</th>
                  <th className="px-6 py-3 text-xs font-bold text-slate-500 uppercase text-center">{t.actions}</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {products.map((p) => {
                  const m = calculateMetrics(p); const isEditing = editingId === p.id; const isSelected = selectedIds.has(p.id);
                  return (
                    <tr key={p.id} className={`${isEditing ? 'bg-indigo-50/50' : isSelected ? 'bg-blue-50/30' : 'hover:bg-slate-50'}`}>
                      <td className="px-6 py-4 text-center"><button onClick={() => toggleSelectRow(p.id)} className={isSelected ? 'text-indigo-600' : 'text-slate-300'}><CheckSquare size={18}/></button></td>
                      <td className="px-4 py-4"><div className="flex items-center gap-4"><img src={p.photoUrl} onClick={() => setPreviewImage(p.photoUrl)} className="w-16 h-16 md:w-20 md:h-20 rounded border object-cover bg-white cursor-pointer" /><div><div className="font-bold">{p.sku}</div><div className="text-slate-600 text-xs">{p.nameCn}</div></div></div></td>
                      <td className="px-4 py-4">{isEditing ? <input className="w-full border p-1 text-xs" value={editForm.nameEn} onChange={e => setEditForm({...editForm, nameEn: e.target.value})} /> : <div className="font-medium text-indigo-600">{p.nameEn || "-"}</div>}</td>
                      <td className="px-4 py-4"><span className="px-2 py-0.5 rounded text-[10px] font-medium bg-slate-100 text-slate-800">{p.categoryMain || "N/A"}</span></td>
                      <td className="px-4 py-4 text-right font-mono">¥{p.priceRmb}</td>
                      <td className="px-4 py-4 text-right"><div className="font-mono font-bold text-emerald-600">€{m.landedCostEuro.toFixed(2)}</div></td>
                      <td className="px-6 py-4 text-center">
                         <div className="flex justify-center gap-2">
                            {isEditing ? (<><button onClick={saveEdit} className="p-1 bg-green-100 text-green-700 rounded"><SaveIcon size={14}/></button><button onClick={cancelEdit} className="p-1 bg-red-100 text-red-700 rounded"><X size={14}/></button></>) : (<><button onClick={() => handleEnrichment(p)} className="p-1 bg-indigo-50 text-indigo-600 rounded"><Sparkles size={14}/></button><button onClick={() => startEditing(p)} className="p-1 bg-slate-100 text-slate-600 rounded"><Edit size={14}/></button></>)}
                         </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Product, ProcessingStatus, Language } from '../types';
import { enrichProductData } from '../services/geminiService';
import { Sparkles, RefreshCw, Settings, Database, Edit, Save as SaveIcon, X, Trash2, CheckSquare, Square, Printer, Search, Download, Package, Box as BoxIcon, Plus, UploadCloud, ZoomIn, FileText, Globe, Home, FileDown } from 'lucide-react';
import MobileEntry from './MobileEntry';
import { translations } from '../utils/i18n';

// Declare global libraries
declare const ExcelJS: any;
declare const saveAs: any;
declare const jspdf: any;

interface DashboardProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  onAddProduct: (product: Product) => void;
  currentLang?: Language;
  onLanguageChange?: (lang: Language) => void;
  onHome?: () => void;
}

const DEFAULT_INVOICE_CONFIG = {
  sellerName: "YiWu Edas Import and Export Co., Ltd",
  sellerAddress: "Room 301, 3rd Floor, NO. 16, DaShi Road, FoTang Town, YiWu City, Zhejiang, China",
  sellerPhone: "86-579-85569925",
  sellerEmail: "info@yiwudiyasi.com",
  buyerInfo: "BERNARDI GROUP PTY LTD\nSHOP 4, 159-173 LACHLAN STREET\nFORBES NSW 2871\nAUSTRALIA",
  invoiceNo: "20250712001",
  date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }),
  sailing: "ALS CLIVIA/001S",
  containerNo: "CMAU9593405",
  sealNo: "R6953832"
};

const Dashboard: React.FC<DashboardProps> = ({ 
  products, onUpdateProduct, onDeleteProduct, onAddProduct, 
  currentLang = 'en', onLanguageChange, onHome 
}) => {
  const t = translations[currentLang];
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Product>>({});
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);
  const [showInvoiceModal, setShowInvoiceModal] = useState(false);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [invoiceConfig, setInvoiceConfig] = useState(DEFAULT_INVOICE_CONFIG);
  const [euroRmbRate, setEuroRmbRate] = useState<number>(7.8);
  const [freightRateCbm, setFreightRateCbm] = useState<number>(150);
  const [usdRmbRate, setUsdRmbRate] = useState<number>(7.2);

  const calculateMetrics = (p: Product) => {
    const rate = euroRmbRate;
    const freight = freightRateCbm;
    const usdRate = usdRmbRate;
    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 : 0;
    const freightPerPc = (cbm > 0 && p.pcsPerBox > 0) ? (freight * cbm) / p.pcsPerBox : 0;
    const baseCostEuro = p.priceRmb > 0 ? p.priceRmb / rate : 0;
    const dutyCost = baseCostEuro * ((p.taxRate || 0) / 100);
    const landedCostEuro = baseCostEuro + freightPerPc + dutyCost;
    const priceStockUsd = p.priceRmb > 0 ? p.priceRmb / usdRate : 0;
    return {
      cbm: Number(cbm.toFixed(4)),
      freightPerPc: Number(freightPerPc.toFixed(4)),
      landedCostEuro: Number(landedCostEuro.toFixed(3)),
      priceStockUsd: Number(priceStockUsd.toFixed(3)),
    };
  };

  const generateExcel = async (exportType: 'master' | 'packinglist' | 'invoice' | 'quotation') => {
    if (typeof ExcelJS === 'undefined') return alert("ExcelJS not loaded.");
    const items = selectedIds.size > 0 ? products.filter(p => selectedIds.has(p.id)) : products;
    if (items.length === 0) return alert("No products to export.");

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet(exportType.toUpperCase());
    const centerStyle = { vertical: 'middle', horizontal: 'center', wrapText: true };
    const borderStyle = { top: { style: 'thin' }, left: { style: 'thin' }, bottom: { style: 'thin' }, right: { style: 'thin' } };

    if (exportType === 'invoice') {
       // Commercial Invoice columns
       sheet.columns = [
         { key: 'no', width: 5 }, { key: 'sku', width: 12 }, { key: 'desc', width: 40 },
         { key: 'hs', width: 15 }, { key: 'ctns', width: 8 }, { key: 'pkg', width: 10 },
         { key: 'qty', width: 10 }, { key: 'unit', width: 8 }, { key: 'price', width: 12 },
         { key: 'amount', width: 15 }
       ];
       sheet.mergeCells('A1:J1'); sheet.getCell('A1').value = invoiceConfig.sellerName;
       sheet.getCell('A1').font = { bold: true, size: 16 }; sheet.getCell('A1').alignment = centerStyle;
       sheet.mergeCells('A6:J6'); sheet.getCell('A6').value = "COMMERCIAL INVOICE"; sheet.getCell('A6').font = { bold: true, size: 20 };

       const headerRow = sheet.getRow(16);
       headerRow.values = ['No.', 'Item NO', 'Description', 'HS CODE', 'CTNS', 'Pkg', 'QTY', 'Unit', 'Price(¥)', 'Amount(¥)'];
       headerRow.font = { bold: true }; headerRow.alignment = centerStyle;

       items.forEach((p, i) => {
         const cQty = Math.ceil(p.moq / (p.pcsPerBox || 1)) || 1;
         const row = sheet.addRow([i+1, p.sku, p.nameEn||p.nameCn, p.hsCode, cQty, p.pcsPerBox, cQty*p.pcsPerBox, 'PCS', p.priceRmb, p.priceRmb * cQty * p.pcsPerBox]);
         row.eachCell((c:any) => { c.border = borderStyle; });
       });
    } else {
       // Table headers for other types
       sheet.columns = [
         { header: 'Image', key: 'image', width: 20 },
         { header: 'No.', key: 'no', width: 8 },
         { header: 'SKU', key: 'sku', width: 15 },
         { header: 'Description', key: 'desc', width: 40 },
         { header: 'HS Code', key: 'hs', width: 15 },
         { header: 'Qty', key: 'qty', width: 12 },
         { header: 'Price (USD)', key: 'price', width: 15 },
         { header: 'Total (USD)', key: 'total', width: 18 }
       ];
       sheet.getRow(1).font = { bold: true }; sheet.getRow(1).height = 30; sheet.getRow(1).alignment = centerStyle;

       items.forEach((p, i) => {
         const m = calculateMetrics(p);
         const rowIndex = i + 2;
         const qty = Math.ceil(p.moq / (p.pcsPerBox || 1)) * (p.pcsPerBox || 1);
         const row = sheet.addRow({ no: i+1, sku: p.sku, desc: p.nameEn||p.nameCn, hs: p.hsCode, qty: qty, price: m.priceStockUsd, total: m.priceStockUsd * qty });
         row.height = 110; row.alignment = centerStyle;
         row.eachCell((c:any) => { c.border = borderStyle; });

         if (p.photoUrl && p.photoUrl.startsWith('data:image')) {
            try {
              const base64 = p.photoUrl.split(',')[1];
              const imageId = workbook.addImage({ base64, extension: 'jpeg' });
              // FULL BLEED Logic: 0 margin
              sheet.addImage(imageId, { 
                 tl: { col: 0, row: rowIndex - 1 }, 
                 br: { col: 1, row: rowIndex },
                 editAs: 'twoCell' 
              });
            } catch (e) {}
         }
       });
    }
    const buffer = await workbook.xlsx.writeBuffer();
    saveAs(new Blob([buffer]), `Yiwu_${exportType}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  const generatePDF = async (type: 'quotation' | 'packinglist' | 'invoice') => {
     if (typeof jspdf === 'undefined') return alert("PDF library not loaded.");
     const items = selectedIds.size > 0 ? products.filter(p => selectedIds.has(p.id)) : products;
     if (items.length === 0) return;

     const { jsPDF } = jspdf;
     const doc = new jsPDF('l', 'mm', 'a4'); // Landscape for better image fit

     doc.setFontSize(20); doc.text(type.toUpperCase(), 14, 20);
     doc.setFontSize(10); doc.text(invoiceConfig.sellerName, 14, 28);
     doc.text(`Date: ${new Date().toLocaleDateString()}`, 250, 20, { align: 'right' });

     const head = type === 'quotation' 
        ? [['Image', 'No.', 'SKU', 'Description', 'HS Code', 'Qty', 'Price(USD)', 'Total(USD)']]
        : [['Image', 'No.', 'SKU', 'Description', 'Qty', 'Cartons', 'CBM', 'G.W']];

     const body = items.map((p, i) => {
        const m = calculateMetrics(p);
        const ctns = Math.ceil(p.moq / (p.pcsPerBox || 1)) || 1;
        const qty = ctns * (p.pcsPerBox || 1);
        return type === 'quotation'
          ? ['', i+1, p.sku, p.nameEn || p.nameCn, p.hsCode, qty, `$${m.priceStockUsd}`, `$${(m.priceStockUsd * qty).toFixed(2)}`]
          : ['', i+1, p.sku, p.nameEn || p.nameCn, qty, ctns, (m.cbm * ctns).toFixed(3), ((p.gwKg || 0) * ctns).toFixed(2)];
     });

     (doc as any).autoTable({
        head: head,
        body: body,
        startY: 35,
        rowPageBreak: 'avoid',
        styles: { cellPadding: 2, fontSize: 8, valign: 'middle', halign: 'center' },
        columnStyles: { 0: { cellWidth: 30 }, 3: { halign: 'left' } },
        didDrawCell: (data: any) => {
           if (data.column.index === 0 && data.cell.section === 'body') {
              const p = items[data.row.index];
              if (p.photoUrl) {
                doc.addImage(p.photoUrl, 'JPEG', data.cell.x + 2, data.cell.y + 2, 26, 26);
              }
           }
        },
        bodyStyles: { minCellHeight: 30 }
     });

     doc.save(`Yiwu_${type}_${Date.now()}.pdf`);
  };

  // Rest of the methods (Enrichment, Editing, etc.) remain identical
  const handleBulkEnrich = async () => {
    setIsBulkProcessing(true);
    const itemsToProcess = products.filter(p => selectedIds.has(p.id));
    for (const product of itemsToProcess) {
       try {
         const result = await enrichProductData(product.nameCn);
         const metrics = calculateMetrics({ ...product, ...result });
         onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
       } catch (e) {}
    }
    setIsBulkProcessing(false); setSelectedIds(new Set()); alert(t.batchComplete);
  };

  const handleEnrichment = async (product: Product) => {
    setProcessingId(product.id);
    onUpdateProduct({ ...product, status: ProcessingStatus.AI_PROCESSING });
    try {
      const result = await enrichProductData(product.nameCn);
      const metrics = calculateMetrics({ ...product, ...result });
      onUpdateProduct({ ...product, ...result, ...metrics, status: ProcessingStatus.REVIEW_NEEDED });
    } catch (error) { onUpdateProduct({ ...product, status: ProcessingStatus.DRAFT });
    } finally { setProcessingId(null); }
  };

  const startEditing = (product: Product) => { setEditingId(product.id); setEditForm({ ...product }); };
  const saveEdit = () => {
    if (!editingId) return;
    const product = products.find(p => p.id === editingId);
    if (product) { const merged = { ...product, ...editForm }; const metrics = calculateMetrics(merged); onUpdateProduct({ ...merged, ...metrics }); }
    setEditingId(null); setEditForm({});
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 font-sans relative">
      {/* Modals & Overlays */}
      {showUploadModal && (
        <div className="fixed inset-0 z-[70] bg-slate-900/50 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg h-[80vh] overflow-hidden flex flex-col">
             <MobileEntry onSave={onAddProduct} isDesktopMode={true} onClose={() => setShowUploadModal(false)} currentLang={currentLang} onLanguageChange={onLanguageChange} products={products} onUpdateProduct={onUpdateProduct} onDeleteProduct={onDeleteProduct} />
           </div>
        </div>
      )}
      {previewImage && (
        <div className="fixed inset-0 z-[80] bg-black/90 backdrop-blur-md flex items-center justify-center p-4" onClick={() => setPreviewImage(null)}>
          <img src={previewImage} className="max-w-full max-h-[90vh] object-contain rounded-lg shadow-2xl" />
        </div>
      )}
      {showInvoiceModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col">
            <div className="p-6 border-b flex justify-between items-center"><h2 className="text-xl font-bold flex items-center gap-2"><Settings size={20} className="text-indigo-600"/> {t.invoiceConfig}</h2><button onClick={() => setShowInvoiceModal(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20}/></button></div>
            <div className="p-8 space-y-6">
               <div><label className="text-xs font-bold text-slate-400 uppercase tracking-widest">{t.companyName}</label><input className="w-full mt-1 border rounded-lg p-3" value={invoiceConfig.sellerName} onChange={e => setInvoiceConfig({...invoiceConfig, sellerName: e.target.value})} /></div>
               <div className="flex gap-4"><button onClick={() => { setShowInvoiceModal(false); generateExcel('invoice'); }} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"><Download size={20} /> Excel (.xlsx)</button><button onClick={() => { setShowInvoiceModal(false); generatePDF('invoice'); }} className="flex-1 bg-red-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"><FileDown size={20} /> PDF (.pdf)</button></div>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-30 shadow-sm">
        <div className="p-4 md:px-8 md:py-4 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center gap-3"><div className="bg-indigo-600 p-2 rounded-lg text-white"><Database size={20} /></div><div><h1 className="text-lg font-bold text-slate-900">{t.dashboard}</h1><p className="text-xs text-slate-500">{products.length} {t.recordsFound}</p></div></div>
          <div className="flex items-center gap-2 flex-wrap">
             {onHome && (<button onClick={onHome} className="px-3 py-2 bg-slate-100 rounded-lg text-slate-600 flex items-center gap-2"><Home size={16}/> {t.backHome}</button>)}
             <button onClick={() => setShowUploadModal(true)} className="px-4 py-2 bg-indigo-600 text-white rounded-lg shadow-lg flex items-center gap-2"><UploadCloud size={16} /> {t.newSourcingBatch}</button>

             {/* Integrated Format Bar */}
             <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-xl">
                <span className="text-[10px] font-black text-slate-400 px-2 uppercase">Export</span>
                <div className="h-6 w-px bg-slate-200 mx-1"></div>
                <button onClick={() => generateExcel('master')} title="Master Excel" className="p-2 hover:bg-white rounded-lg text-slate-600 hover:text-indigo-600"><Database size={18} /></button>
                <div className="flex bg-white rounded-lg shadow-sm border border-slate-200 divide-x">
                   <button onClick={() => generateExcel('quotation')} className="px-2 py-1.5 text-[10px] font-bold text-indigo-600 hover:bg-indigo-50">QTN.xlsx</button>
                   <button onClick={() => generatePDF('quotation')} className="px-2 py-1.5 text-[10px] font-bold text-red-600 hover:bg-red-50">QTN.pdf</button>
                </div>
                <div className="flex bg-white rounded-lg shadow-sm border border-slate-200 divide-x ml-1">
                   <button onClick={() => generateExcel('packinglist')} className="px-2 py-1.5 text-[10px] font-bold text-green-600 hover:bg-green-50">PKL.xlsx</button>
                   <button onClick={() => generatePDF('packinglist')} className="px-2 py-1.5 text-[10px] font-bold text-red-600 hover:bg-red-50">PKL.pdf</button>
                </div>
                <button onClick={() => setShowInvoiceModal(true)} className="p-2 hover:bg-white rounded-lg text-slate-600"><Printer size={18}/></button>
             </div>
          </div>
        </div>

        {/* Sub-Filters */}
        <div className="px-4 py-2 md:px-8 bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-4">
           {selectedIds.size > 0 ? (
             <div className="flex items-center gap-4 bg-indigo-50 px-4 py-2 rounded-lg border border-indigo-100 w-full md:w-auto">
                <span className="text-sm font-bold text-indigo-700 flex items-center gap-2"><CheckSquare size={16} /> {selectedIds.size} {t.selected}</span>
                <button onClick={handleBulkEnrich} className="text-xs font-bold text-indigo-600 flex items-center gap-1"><Sparkles size={14}/> {t.aiEnrich}</button>
                <button onClick={() => { if(confirm("Delete?")) onDeleteProduct?.(Array.from(selectedIds)); setSelectedIds(new Set()); }} className="text-xs font-bold text-red-600 flex items-center gap-1"><Trash2 size={14}/> {t.delete}</button>
             </div>
           ) : (
             <div className="flex gap-6 text-sm text-slate-500 w-full overflow-x-auto no-scrollbar">
                <div className="flex items-center gap-2"><span>EUR:</span><input type="number" value={euroRmbRate} onChange={e=>setEuroRmbRate(Number(e.target.value))} className="w-12 border rounded text-center"/></div>
                <div className="flex items-center gap-2"><span>USD:</span><input type="number" value={usdRmbRate} onChange={e=>setUsdRmbRate(Number(e.target.value))} className="w-12 border rounded text-center"/></div>
                <div className="flex items-center gap-2"><span>FRT:</span><input type="number" value={freightRateCbm} onChange={e=>setFreightRateCbm(Number(e.target.value))} className="w-12 border rounded text-center"/></div>
             </div>
           )}
           <div className="relative w-full md:w-auto"><Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder={t.searchPlaceholder} className="pl-9 pr-4 py-2 text-sm border rounded-full w-full md:w-64" /></div>
        </div>
      </header>

      {/* Main Grid */}
      <main className="flex-1 overflow-auto p-2 md:p-6">
        <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
          <table className="w-full text-left text-sm whitespace-nowrap">
            <thead className="bg-slate-50 border-b">
               <tr>
                 <th className="px-6 py-4 w-10"><button onClick={() => selectedIds.size === products.length ? setSelectedIds(new Set()) : setSelectedIds(new Set(products.map(p=>p.id)))} className="text-slate-400">{selectedIds.size === products.length ? <CheckSquare size={18}/> : <Square size={18}/>}</button></th>
                 <th className="px-4 py-3">{t.productName}</th>
                 <th className="px-4 py-3">{t.details}</th>
                 <th className="px-4 py-3 text-right">{t.cost}</th>
                 <th className="px-4 py-3 text-right">{t.landed}</th>
                 <th className="px-6 py-3 text-center">{t.actions}</th>
               </tr>
            </thead>
            <tbody className="divide-y">
               {products.map(p => {
                 const m = calculateMetrics(p); const isEditing = editingId === p.id; const isSelected = selectedIds.has(p.id);
                 return (
                   <tr key={p.id} className={`${isSelected ? 'bg-indigo-50/30' : 'hover:bg-slate-50'}`}>
                     <td className="px-6 py-4"><button onClick={() => { const s = new Set(selectedIds); if(s.has(p.id)) s.delete(p.id); else s.add(p.id); setSelectedIds(s); }} className={isSelected ? 'text-indigo-600' : 'text-slate-300'}><CheckSquare size={18}/></button></td>
                     <td className="px-4 py-4"><div className="flex gap-4"><img src={p.photoUrl} onClick={()=>setPreviewImage(p.photoUrl)} className="w-16 h-16 rounded border object-cover cursor-pointer bg-white" /><div><div className="font-bold">{p.sku}</div><div className="text-[10px] text-slate-500">{p.nameCn}</div></div></div></td>
                     <td className="px-4 py-4 max-w-[200px] truncate">{isEditing ? <input className="w-full border p-1" value={editForm.nameEn} onChange={e=>setEditForm({...editForm, nameEn: e.target.value})}/> : p.nameEn || "-"}</td>
                     <td className="px-4 py-4 text-right font-mono">¥{p.priceRmb}</td>
                     <td className="px-4 py-4 text-right font-mono text-emerald-600 font-bold">€{m.landedCostEuro.toFixed(2)}</td>
                     <td className="px-6 py-4">
                        <div className="flex justify-center gap-1">
                          {isEditing ? (<><button onClick={saveEdit} className="p-1.5 bg-green-100 text-green-700 rounded"><SaveIcon size={14}/></button><button onClick={()=>setEditingId(null)} className="p-1.5 bg-red-100 text-red-700 rounded"><X size={14}/></button></>) : (<><button onClick={()=>handleEnrichment(p)} className="p-1.5 bg-indigo-50 text-indigo-600 rounded"><Sparkles size={14}/></button><button onClick={()=>startEditing(p)} className="p-1.5 bg-slate-100 text-slate-600 rounded"><Edit size={14}/></button></>)}
                        </div>
                     </td>
                   </tr>
                 );
               })}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft, CheckSquare, Square, Trash2, Sparkles, Download, RefreshCw, FileText, Database, Printer, Contact, UserCircle, Briefcase, Globe, ScanLine, Edit2, Folder, FolderPlus, ArrowUpRight, Grid, Image as ImageIcon, Eraser, FileDown } from 'lucide-react';
import { Product, ProcessingStatus, SupplierInfo, Language } from '../types';
import { analyzeImage, enrichProductData, analyzeBusinessCard } from '../services/geminiService';
import { translations } from '../utils/i18n';

// Declare globals for CDN libraries
declare const ExcelJS: any;
declare const saveAs: any;
declare const jspdf: any;

interface DraftImage {
  id: string;
  url: string;
  timestamp: number;
}

interface DraftFolder {
  id: string;
  name: string;
  supplier: SupplierInfo;
  images: DraftImage[];
  timestamp: number;
}

interface MobileEntryProps {
  onSave: (product: Product) => void;
  onUpdateProduct?: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
  currentLang?: Language;
  onLanguageChange?: (lang: Language) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ 
  onSave, onUpdateProduct, onDeleteProduct, isDesktopMode, onClose, products = [], 
  currentLang = 'en', onLanguageChange 
}) => {
  const t = translations[currentLang];

  // --- STATE ---
  const [viewMode, setViewMode] = useState<'folders' | 'folderDetail' | 'history'>('folders');
  const [activeFolderId, setActiveFolderId] = useState<string | null>(null);
  const [folders, setFolders] = useState<DraftFolder[]>([]);
  const [selectedImageIds, setSelectedImageIds] = useState<Set<string>>(new Set());
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStatus, setProcessingStatus] = useState({ current: 0, total: 0, text: '' });
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });
  const isMounted = useRef(true);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cardInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  const calculateMetrics = (p: Partial<Product>) => {
    const rate = 7.8; 
    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 : 0;
    const priceStockUsd = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / 7.2 : 0;
    return { cbm: Number(cbm.toFixed(4)), priceStockUsd: Number(priceStockUsd.toFixed(3)) };
  };

  const handleExport = async (format: 'excel' | 'pdf', type: 'master' | 'quotation' | 'packinglist' | 'invoice') => {
      const items = selectedIds.size > 0 ? products.filter(p => selectedIds.has(p.id)) : products;
      if (items.length === 0) return;

      if (format === 'excel') {
          if (typeof ExcelJS === 'undefined') return;
          const workbook = new ExcelJS.Workbook();
          const sheet = workbook.addWorksheet(type.toUpperCase());
          sheet.columns = [{ header: 'Image', key: 'img', width: 15 }, { header: 'SKU', key: 'sku', width: 15 }, { header: 'Name', key: 'name', width: 30 }];
          items.forEach((p, i) => {
             const row = sheet.addRow({ sku: p.sku, name: p.nameEn || p.nameCn });
             row.height = 80;
             if (p.photoUrl && p.photoUrl.startsWith('data:image')) {
                 try {
                    const base64 = p.photoUrl.split(',')[1];
                    const imgId = workbook.addImage({ base64, extension: 'jpeg' });
                    sheet.addImage(imgId, { tl: { col: 0, row: i + 1 }, br: { col: 1, row: i + 2 }, editAs: 'twoCell' });
                 } catch(e) {}
             }
          });
          const buffer = await workbook.xlsx.writeBuffer();
          saveAs(new Blob([buffer]), `Export_${type}.xlsx`);
      } else {
          if (typeof jspdf === 'undefined') return;
          const doc = new jspdf.jsPDF('p', 'mm', 'a4');
          doc.text(type.toUpperCase(), 14, 20);
          const body = items.map((p, i) => ['', i+1, p.sku, p.nameEn || p.nameCn]);
          (doc as any).autoTable({
              head: [['Image', 'No.', 'SKU', 'Description']],
              body: body,
              startY: 30,
              columnStyles: { 0: { cellWidth: 30 } },
              didDrawCell: (data: any) => {
                 if (data.column.index === 0 && data.cell.section === 'body') {
                    const p = items[data.row.index];
                    if (p.photoUrl) doc.addImage(p.photoUrl, 'JPEG', data.cell.x+2, data.cell.y+2, 26, 26);
                 }
              },
              bodyStyles: { minCellHeight: 30 }
          });
          doc.save(`Export_${type}.pdf`);
      }
      setShowExportMenu(false);
  };

  // Logic for processing, folders etc. remains same as previous stable version
  const handleProcessSelected = async () => {
    if (selectedImageIds.size === 0) return;
    setIsProcessing(true);
    let processed = 0; const total = selectedImageIds.size;
    const queue: { img: DraftImage, supplier: SupplierInfo }[] = [];
    folders.forEach(f => { f.images.forEach(img => { if (selectedImageIds.has(img.id)) queue.push({ img, supplier: f.supplier }); }); });
    for (const item of queue) {
      if (!isMounted.current) break;
      setProcessingStatus({ current: processed + 1, total, text: `Analyzing item ${processed + 1}/${total}` });
      try {
        const aiData = await analyzeImage(item.img.url);
        const newProduct: Product = { id: Date.now().toString() + "_" + Math.random().toString(36).substr(2, 5), sku: `YW-${Math.floor(Math.random() * 90000) + 10000}`, photoUrl: item.img.url, supplier: item.supplier, nameCn: aiData.nameCn, nameEn: aiData.nameEn, materialEn: aiData.materialEn, priceRmb: aiData.priceRmb, moq: aiData.moq, shopNo: item.supplier.address || "TBD", hsCode: aiData.hsCode, boxLength: aiData.boxLength, boxWidth: aiData.boxWidth, boxHeight: aiData.boxHeight, pcsPerBox: aiData.pcsPerBox, status: ProcessingStatus.DRAFT, timestamp: Date.now() };
        onSave({ ...newProduct, ...calculateMetrics(newProduct) });
        setFolders(prev => prev.map(f => ({ ...f, images: f.images.filter(img => img.id !== item.img.id) })).filter(f => f.images.length > 0));
        setSelectedImageIds(prev => { const next = new Set(prev); next.delete(item.img.id); return next; });
      } catch (e) {}
      processed++;
    }
    setIsProcessing(false); if (isMounted.current) { alert(t.batchComplete); setViewMode('history'); }
  };

  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_WIDTH = 800; let width = img.width; let height = img.height;
          if (width > MAX_WIDTH) { height *= MAX_WIDTH / width; width = MAX_WIDTH; }
          const canvas = document.createElement('canvas'); canvas.width = width; canvas.height = height;
          const ctx = canvas.getContext('2d'); if (!ctx) { resolve(event.target?.result as string); return; }
          ctx.drawImage(img, 0, 0, width, height); resolve(canvas.toDataURL('image/jpeg', 0.6));
        };
      };
    });
  };

  if (viewMode === 'folders') {
    return (
      <div className="flex flex-col h-full bg-slate-50 font-sans relative">
         <div className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-20">
             <h1 className="text-xl font-bold">{t.myShops}</h1>
             <div className="flex items-center gap-2">
                 {folders.length > 0 && (<button onClick={()=>setFolders([])} className="p-2 text-slate-400 hover:text-red-500"><Eraser size={20} /></button>)}
                 <button onClick={() => { if(currentLang==='en') onLanguageChange?.('zh'); else onLanguageChange?.('en'); }} className="text-xs font-bold px-2.5 py-1.5 bg-slate-50 rounded-lg border">{currentLang.toUpperCase()}</button>
             </div>
         </div>
         <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-32">
             <div className="bg-indigo-600 rounded-2xl p-4 flex items-center justify-between shadow-lg text-white">
                 <div className="flex items-center gap-4"><div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center"><Store size={24} /></div><div><div className="font-bold">{t.newShop}</div><div className="text-xs opacity-70">{t.scanCardToCreate}</div></div></div>
                 <label className="bg-white text-indigo-600 w-10 h-10 rounded-full flex items-center justify-center cursor-pointer"><ScanLine size={20} /><input type="file" accept="image/*" className="hidden" onChange={async (e) => { if (e.target.files?.[0]) { const b64 = await processImageFile(e.target.files[0]); const info = await analyzeBusinessCard(b64); setFolders([{ id: Date.now().toString(), name: info.companyName || "Shop", supplier: info, images: [], timestamp: Date.now() }, ...folders]); } }} /></label>
             </div>
             {folders.map(f => (
                <div key={f.id} className="bg-white rounded-2xl border p-4 shadow-sm" onClick={() => { setActiveFolderId(f.id); setViewMode('folderDetail'); }}>
                   <div className="flex items-center gap-3"><div className="bg-amber-100 text-amber-600 p-2.5 rounded-lg"><Folder size={20} /></div><div><div className="font-bold text-sm">{f.name}</div><div className="text-xs text-slate-400">{f.images.length} {t.photos}</div></div></div>
                </div>
             ))}
         </div>
         {selectedImageIds.size > 0 && (<div className="absolute bottom-24 left-6 right-6 z-30"><button onClick={handleProcessSelected} className="w-full bg-slate-900 text-white rounded-2xl py-4 shadow-xl flex items-center justify-center gap-2 font-bold text-sm"><Sparkles size={18} className="text-indigo-300"/> {t.processSelected} ({selectedImageIds.size})</button></div>)}
         {!isDesktopMode && (
            <nav className="glass-nav absolute bottom-0 w-full pb-8 pt-4 px-12 flex justify-between items-center z-10">
              <button onClick={() => setViewMode('folders')} className="flex flex-col items-center gap-1.5 text-indigo-600 relative"><div className="absolute -top-1 w-8 h-1 bg-indigo-600 rounded-full"></div><Grid size={24} strokeWidth={2.5} /><span className="text-[10px] font-bold">{t.myShops}</span></button>
              <button onClick={() => setViewMode('history')} className="flex flex-col items-center gap-1.5 text-slate-300"><Database size={24} /><span className="text-[10px] font-bold">{t.history}</span></button>
            </nav>
         )}
      </div>
    );
  }

  // History view with Export Options
  return (
    <div className="flex flex-col h-full bg-slate-50 relative">
        {showExportMenu && (
          <div className="fixed inset-0 z-[60] bg-black/50 backdrop-blur-sm flex items-end justify-center pb-8 animate-in slide-in-from-bottom-10">
             <div className="bg-white w-[90%] max-w-sm rounded-2xl p-5 shadow-2xl space-y-4">
                 <div className="flex justify-between items-center"><h3 className="font-bold text-lg">{t.exportOptions}</h3><button onClick={()=>setShowExportMenu(false)} className="p-1 text-slate-400"><X size={20}/></button></div>
                 <div className="grid grid-cols-1 gap-2">
                    <div className="p-3 bg-slate-50 rounded-xl border"><div className="text-xs font-bold text-slate-400 mb-2 uppercase">Excel Format</div><div className="flex gap-2"><button onClick={()=>handleExport('excel', 'quotation')} className="flex-1 py-2 bg-indigo-600 text-white rounded-lg text-xs font-bold">QTN.xlsx</button><button onClick={()=>handleExport('excel', 'packinglist')} className="flex-1 py-2 bg-green-600 text-white rounded-lg text-xs font-bold">PKL.xlsx</button></div></div>
                    <div className="p-3 bg-slate-50 rounded-xl border"><div className="text-xs font-bold text-slate-400 mb-2 uppercase">PDF Format</div><div className="flex gap-2"><button onClick={()=>handleExport('pdf', 'quotation')} className="flex-1 py-2 bg-red-600 text-white rounded-lg text-xs font-bold">QTN.pdf</button><button onClick={()=>handleExport('pdf', 'packinglist')} className="flex-1 py-2 bg-red-600 text-white rounded-lg text-xs font-bold">PKL.pdf</button></div></div>
                 </div>
             </div>
          </div>
        )}
        <div className="px-6 py-4 bg-white shadow-sm flex justify-between items-center sticky top-0 z-10">
           <h2 className="text-xl font-bold">{t.history}</h2>
           <button onClick={() => setIsSelectMode(!isSelectMode)} className="text-sm font-medium px-3 py-1.5 rounded-full bg-indigo-50 text-indigo-600">{isSelectMode ? t.cancel : t.select}</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-32">
           {products.map(p => (
              <div key={p.id} className="bg-white p-3 rounded-xl shadow-sm border flex gap-3">
                {isSelectMode && (<div onClick={()=>{ const s = new Set(selectedIds); if(s.has(p.id)) s.delete(p.id); else s.add(p.id); setSelectedIds(s); }} className="flex items-center">{selectedIds.has(p.id) ? <CheckSquare className="text-indigo-600"/> : <Square className="text-slate-300"/>}</div>)}
                <img src={p.photoUrl} className="w-20 h-20 rounded-lg object-cover border" />
                <div className="flex-1 py-1"><div className="font-bold text-sm">{p.sku}</div><p className="text-xs text-slate-500">{p.nameEn || p.nameCn}</p><div className="font-bold text-indigo-600 text-sm mt-1">¥{p.priceRmb}</div></div>
              </div>
           ))}
        </div>
        {isSelectMode ? (
          <div className="absolute bottom-24 w-full px-4 flex gap-3"><button onClick={()=>setShowExportMenu(true)} className="flex-1 bg-indigo-600 text-white rounded-xl h-12 flex items-center justify-center gap-2 font-bold shadow-lg"><Download size={20}/> {t.exportOptions}</button></div>
        ) : (
          <nav className="glass-nav absolute bottom-0 w-full pb-8 pt-4 px-12 flex justify-between items-center z-20">
            <button onClick={() => setViewMode('folders')} className="flex flex-col items-center gap-1.5 text-slate-300"><Grid size={24} /><span className="text-[10px] font-bold">{t.myShops}</span></button>
            <button onClick={() => setViewMode('history')} className="flex flex-col items-center gap-1.5 text-indigo-600 relative"><div className="absolute -top-1 w-8 h-1 bg-indigo-600 rounded-full"></div><Database size={24} strokeWidth={2.5} /><span className="text-[10px] font-bold">{t.history}</span></button>
          </nav>
        )}
    </div>
  );
};

export default MobileEntry;

import React, { useState, useEffect, useRef } from 'react';
import { Camera, Save, Box, Home, Plus, Layers, Loader2, ImagePlus, ChevronRight, Package, Tag, Store, DollarSign, Zap, X, ArrowLeft, CheckSquare, Square, Trash2, Sparkles, Download, RefreshCw, FileText, Database, Printer, Contact, UserCircle, Briefcase, Globe, ScanLine, Edit2, Folder, FolderPlus, ArrowUpRight, Grid, Image as ImageIcon, Eraser, FileDown } from 'lucide-react';
import { Product, ProcessingStatus, SupplierInfo, Language } from '../types';
import { analyzeImage, enrichProductData, analyzeBusinessCard } from '../services/geminiService';
import { translations } from '../utils/i18n';

// Declare globals for CDN libraries
declare const ExcelJS: any;
declare const saveAs: any;
declare const jspdf: any;

interface DraftImage {
  id: string;
  url: string;
  timestamp: number;
}

interface DraftFolder {
  id: string;
  name: string;
  supplier: SupplierInfo;
  images: DraftImage[];
  timestamp: number;
}

interface MobileEntryProps {
  onSave: (product: Product) => void;
  onUpdateProduct?: (product: Product) => void;
  onDeleteProduct?: (ids: string[]) => void;
  isDesktopMode?: boolean;
  onClose?: () => void;
  products?: Product[];
  currentLang?: Language;
  onLanguageChange?: (lang: Language) => void;
}

const MobileEntry: React.FC<MobileEntryProps> = ({ 
  onSave, onUpdateProduct, onDeleteProduct, isDesktopMode, onClose, products = [], 
  currentLang = 'en', onLanguageChange 
}) => {
  const t = translations[currentLang];

  // --- STATE ---
  const [viewMode, setViewMode] = useState<'folders' | 'folderDetail' | 'history'>('folders');
  const [activeFolderId, setActiveFolderId] = useState<string | null>(null);
  const [folders, setFolders] = useState<DraftFolder[]>([]);
  const [selectedImageIds, setSelectedImageIds] = useState<Set<string>>(new Set());
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStatus, setProcessingStatus] = useState({ current: 0, total: 0, text: '' });
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });

  const isMounted = useRef(true);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cardInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // --- HELPERS ---

  const calculateMetrics = (p: Partial<Product>) => {
    const rate = 7.8; 
    const cbm = (p.boxLength && p.boxWidth && p.boxHeight) ? (p.boxLength * p.boxWidth * p.boxHeight) / 1000000 : 0;
    const priceStockUsd = (p.priceRmb || 0) > 0 ? (p.priceRmb || 0) / 7.2 : 0;
    return { cbm: Number(cbm.toFixed(4)), priceStockUsd: Number(priceStockUsd.toFixed(3)) };
  };

  const processImageFile = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;
          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }
          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) { resolve(event.target?.result as string); return; }
          ctx.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg', 0.6));
        };
      };
    });
  };

  // --- HANDLERS ---

  const handleCreateFolder = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsProcessing(true);
      setProcessingStatus({ current: 0, total: 1, text: t.analyzingCard });
      try {
        const base64 = await processImageFile(e.target.files[0]);
        const info = await analyzeBusinessCard(base64);
        const newFolder: DraftFolder = {
          id: Date.now().toString(),
          name: info.companyName || "New Shop " + (folders.length + 1),
          supplier: info,
          images: [],
          timestamp: Date.now()
        };
        setFolders(prev => [newFolder, ...prev]);
        setActiveFolderId(newFolder.id);
        setViewMode('folderDetail');
      } catch (err) {
        console.error(err);
      } finally {
        setIsProcessing(false);
      }
    }
  };

  const handleAddPhotos = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!activeFolderId) return;
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files);
      const newImages: DraftImage[] = [];
      for (const file of files) {
        const b64 = await processImageFile(file);
        newImages.push({
          id: Math.random().toString(36).substr(2, 9) + Date.now(),
          url: b64,
          timestamp: Date.now()
        });
      }
      setFolders(prev => prev.map(f => f.id === activeFolderId ? { ...f, images: [...f.images, ...newImages] } : f));
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const toggleImageSelection = (imgId: string) => {
    setSelectedImageIds(prev => {
      const next = new Set(prev);
      if (next.has(imgId)) next.delete(imgId);
      else next.add(imgId);
      return next;
    });
  };

  const handleProcessSelected = async () => {
    if (selectedImageIds.size === 0) return;
    setIsProcessing(true);
    let processed = 0; const total = selectedImageIds.size;
    const queue: { img: DraftImage, supplier: SupplierInfo }[] = [];
